async function getUserIdFromToken(token) {
  try {
    const r = await pool.query('SELECT user_id FROM user_fcm_tokens WHERE fcm_token = $1 LIMIT 1', [token]);
    return r.rows[0]?.user_id || null;
  } catch { return null; }
}

async function sendNotificationLogged(token, title, body, data) {
  const result = await _origSendNotification(token, title, body, data);
  let userId = data && (data.userId || data.user_id || data.ownerId || data.owner_id);
  if (!userId && token) userId = await getUserIdFromToken(token);
  if (userId) saveNotificationToHistory(userId, title, body, (data && data.type) || 'push', data);
  return result;
}
async function sendNotificationToMultipleLogged(tokens, title, body, data) {
  const result = await _origSendNotificationToMultiple(tokens, title, body, data);
  let userId = data && (data.userId || data.user_id || data.ownerId || data.owner_id);
  if (!userId && tokens && tokens.length > 0) userId = await getUserIdFromToken(tokens[0]);
  if (userId) saveNotificationToHistory(userId, title, body, (data && data.type) || 'push', data);
  return result;
}
/**
 * Nettoie le nom du voyageur extrait d'iCal
 */
function cleanGuestName(rawName, platform) {
  if (!rawName) {
    return platform ? `Voyageur ${platform}` : 'Voyageur';
  }
  
  const cleaned = rawName.trim().replace(/^\(|\)$/g, '');
  
  const invalidNames = ['not available', 'closed', 'reservation', 'blocked', 'unavailable', 'booked'];
  
if (invalidNames.some(invalid => cleaned.toLowerCase().includes(invalid))) {
    if (platform && platform.toLowerCase().includes('airbnb')) {
      return 'Voyageur Airbnb';
    } else if (platform && platform.toLowerCase().includes('booking')) {
      return 'Voyageur Booking';
    } else {
      return 'Voyageur';
    }
  }
  
  return cleaned;
}
