/**
 * Synchronise toutes les URLs iCal de tous les logements
 */
async function syncAllIcalUrls(pool) {
  try {
    const propsResult = await pool.query(
      `SELECT id, user_id, name, ical_urls FROM properties WHERE ical_urls IS NOT NULL AND ical_urls != '[]'`
    );

    for (const prop of propsResult.rows) {
      let icalUrls = [];
      try {
        icalUrls = typeof prop.ical_urls === 'string' ? JSON.parse(prop.ical_urls) : (prop.ical_urls || []);
      } catch (_) { continue; }

      if (!Array.isArray(icalUrls) || icalUrls.length === 0) continue;

      for (const entry of icalUrls) {
        const url = entry.url || entry;
        if (!url || typeof url !== 'string') continue;
        try {
          await syncSingleIcalUrl(pool, prop, entry);
        } catch (err) {
          console.warn(`⚠️ [ICAL] Erreur sync ${url}:`, err.message);
        }
      }
    }
    console.log(`✅ [ICAL CRON] Synchronisation terminée pour ${propsResult.rows.length} logement(s)`);
  } catch (err) {
    console.error('❌ [ICAL CRON] syncAllIcalUrls:', err.message);
  }
}

/**
 * Synchronise une URL iCal pour un logement
 */
async function syncSingleIcalUrl(pool, property, entry) {
  const url = entry.url || entry;
  const platformName = entry.platformName || entry.platform || 'iCal';
  const platformColor = entry.color || '#888888';

  // Récupérer le fichier iCal
  const response = await axios.get(url, { timeout: 10000, headers: { 'User-Agent': 'Boostinghost/1.0' } });
  const icalText = response.data;

  // Parser les événements VEVENT
  const events = parseIcalText(icalText);
  console.log(`📥 [ICAL] ${property.name} / ${platformName} : ${events.length} événement(s)`);

  let created = 0, skipped = 0;

  for (const event of events) {
    if (!event.start || !event.end) continue;
    if (event.type === 'block') continue; // Ignorer les blocages iCal

    const startStr = event.start;
    const endStr = event.end;
    const guestName = event.summary || `Voyageur ${platformName}`;
    const icalUid = event.uid || `${property.id}_${platformName}_${startStr}`;

    // Anti-doublon : par ical_uid d'abord, puis par dates
    const existing = await pool.query(
      `SELECT id FROM reservations
       WHERE property_id = $1
       AND (ical_uid = $2 OR (DATE(start_date) = DATE($3) AND status != 'cancelled'))
       LIMIT 1`,
      [property.id, icalUid, startStr]
    );

    if (existing.rows.length > 0) { skipped++; continue; }

    // Créer la réservation
    const uid = `ICAL_${Date.now().toString(36)}_${Math.random().toString(36).slice(2,6)}`;
    await pool.query(
      `INSERT INTO reservations
        (uid, property_id, user_id, start_date, end_date, guest_name,
         platform, source, status, ical_uid, created_at, updated_at)
       VALUES ($1,$2,$3,$4,$5,$6,$7,$8,'confirmed',$9,NOW(),NOW())`,
      [uid, property.id, property.user_id, startStr, endStr, guestName,
       platformName, 'ical', icalUid]
    );
    created++;

    // ── Post-création : conversation + templates + notification push ──
    try {
      // 1. Créer ou réutiliser la conversation
      const existingConv = await pool.query(
        `SELECT id FROM conversations
         WHERE property_id = $1 AND DATE(reservation_start_date) = DATE($2)
         ORDER BY created_at DESC LIMIT 1`,
        [property.id, startStr]
      );

      let convId;
      if (existingConv.rows.length > 0) {
        convId = existingConv.rows[0].id;
      } else {
        const convResult = await pool.query(
          `INSERT INTO conversations
            (user_id, property_id, reservation_start_date, reservation_end_date,
             platform, guest_name, pin_code, unique_token, photos_token,
             is_verified, status)
           VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9,FALSE,'pending')
           RETURNING id`,
          [
            property.user_id, property.id, startStr, endStr,
            platformName, guestName,
            Math.floor(1000 + Math.random() * 9000).toString(),
            crypto.randomBytes(32).toString('hex'),
            crypto.randomBytes(32).toString('hex')
          ]
        );
        convId = convResult.rows[0].id;
        if (io) io.to(`user_${property.user_id}`).emit('new_conversation', { conversationId: convId });
      }

      // 2. Notification push propriétaire
      try {
        const tokensRes = await pool.query(
          'SELECT fcm_token FROM user_fcm_tokens WHERE user_id = $1 AND fcm_token IS NOT NULL',
          [property.user_id]
        );
        if (tokensRes.rows.length > 0 && await shouldSendNotification(property.user_id, 'notif_new_reservation')) {
          const fcmTokens = tokensRes.rows.map(r => r.fcm_token);
          const checkin = new Date(startStr).toLocaleDateString('fr-FR', { day:'numeric', month:'short' });
          const checkout = new Date(endStr).toLocaleDateString('fr-FR', { day:'numeric', month:'short' });
          await sendNotificationToMultipleLogged(
            fcmTokens,
            `📅 Nouvelle réservation ${platformName}`,
            `${displayName(property)} - ${checkin} au ${checkout}`,
            { type: 'new_reservation', reservation_id: uid, property_name: displayName(property) }
          );
          await sendNotificationToDelegatesOf(
            property.user_id,
            `📅 Nouvelle réservation ${platformName}`,
            `${displayName(property)} - ${checkin} au ${checkout}`,
            { type: 'new_reservation', reservation_id: uid, property_name: displayName(property) }
          );
          await sendNotificationToSubAccountsOf(
            property.user_id, 'can_view_calendar',
            `🏠 Nouvelle réservation — ${displayName(property)}`,
            `${guestName} · ${checkin} → ${checkout}`,
            { type: 'new_reservation', reservation_id: uid },
            'notif_sub_new_reservation'
          );
        }
      } catch (notifErr) {
        console.warn(`⚠️ [ICAL] Notif push ${uid}:`, notifErr.message);
      }

      // 3. Déclencher les templates on_booking
      try {
        const nowParis = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Paris' }));
        const todayStr = nowParis.toISOString().split('T')[0];
        // ⚠️ on_arrival géré séparément avec vérification caution — ne pas l'inclure ici
        const triggerTypes = ['on_booking'];

        const templates = await pool.query(
          `SELECT * FROM message_templates WHERE user_id = $1 AND trigger_type = ANY($3) AND active = TRUE
           AND (property_id IS NULL OR property_id::text = $2::text)`,
          [property.user_id, property.id, triggerTypes]
        );

        if (templates.rows.length > 0) {
          const convRow = await pool.query(
            `SELECT c.*, r.guest_country, r.guest_language
             FROM conversations c
             LEFT JOIN reservations r ON (
               r.channex_booking_id = c.channex_booking_id AND c.channex_booking_id IS NOT NULL
             )
             WHERE c.id = $1 LIMIT 1`, [convId]
          );
          const propInfo = await pool.query(
            `SELECT address, arrival_time, departure_time, access_code, wifi_name,
                    wifi_password, practical_info, welcome_book_url, name, internal_name
             FROM properties WHERE id = $1`, [property.id]
          );
          if (convRow.rows[0] && propInfo.rows[0]) {
            for (const tmpl of templates.rows) {
              await sendTemplateMessage(pool, io, {
                template: tmpl,
                conv: { ...convRow.rows[0], user_id: property.user_id },
                property: propInfo.rows[0]
              });
            }
          }
        }
      } catch (tplErr) {
        console.warn(`⚠️ [ICAL] Templates ${uid}:`, tplErr.message);
      }

      // 4. Notifier les cleaners
      try {
        await notifyCleanersAboutNewBookings([{
          userId: property.user_id,
          propertyId: property.id,
          propertyName: displayName(property)
        }]);
      } catch (cleanErr) {
        console.warn(`⚠️ [ICAL] Notif cleaners ${uid}:`, cleanErr.message);
      }

    } catch (postErr) {
      console.warn(`⚠️ [ICAL] Post-création ${uid}:`, postErr.message);
    }
  }

  console.log(`✅ [ICAL] ${property.name}/${platformName} : ${created} créée(s), ${skipped} doublon(s)`);
}

/**
 * Parse un fichier iCal texte et retourne les événements
 */
function parseIcalText(icalText) {
  const events = [];
  const lines = icalText.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');

  let current = null;
  for (const line of lines) {
    if (line.startsWith('BEGIN:VEVENT')) {
      current = {};
    } else if (line.startsWith('END:VEVENT') && current) {
      events.push(current);
      current = null;
    } else if (current) {
      if (line.startsWith('DTSTART')) {
        const val = line.split(':').slice(1).join(':').trim();
        // Format DATE: 20240101 ou DATETIME: 20240101T150000Z
        current.start = val.length >= 8 ? `${val.slice(0,4)}-${val.slice(4,6)}-${val.slice(6,8)}` : null;
      } else if (line.startsWith('DTEND')) {
        const val = line.split(':').slice(1).join(':').trim();
        current.end = val.length >= 8 ? `${val.slice(0,4)}-${val.slice(4,6)}-${val.slice(6,8)}` : null;
      } else if (line.startsWith('SUMMARY')) {
        const summary = line.split(':').slice(1).join(':').trim();
        current.summary = summary;
        // Détecter les blocages
        if (/blocked|unavailable|indisponible|blocage|not available/i.test(summary)) {
          current.type = 'block';
        }
      } else if (line.startsWith('UID')) {
        current.uid = line.split(':').slice(1).join(':').trim();
      }
    }
  }
  return events;
}

