// Multer en mémoire pour envoyer directement à Cloudinary
const storage = multer.memoryStorage();
const upload = multer({
  storage,
  limits: { fileSize: 10 * 1024 * 1024 }, // 10MB max
  fileFilter: (req, file, cb) => {
    const allowedMimes = [
      'image/jpeg',
      'image/jpg',
      'image/png',
      'image/webp',
      'image/gif',
      'image/heic',
      'image/heif',
      'application/pdf'
    ];
    
    const allowedExtensions = ['.jpg', '.jpeg', '.png', '.webp', '.gif', '.heic', '.heif', '.pdf'];
    const fileExtension = file.originalname.toLowerCase().match(/\.[^.]+$/)?.[0];
    
    const mimeOk = allowedMimes.includes(file.mimetype.toLowerCase());
    const extOk = fileExtension && allowedExtensions.includes(fileExtension);
    
    if (mimeOk || extOk) {
      return cb(null, true);
    }
    
    console.log('❌ Fichier rejeté:', {
      mimetype: file.mimetype,
      extension: fileExtension,
      filename: file.originalname
    });
    
    return cb(new Error('Type de fichier non supporté. Formats acceptés: JPG, PNG, WEBP, GIF'), false);
  }
});
// Fonction helper pour uploader vers Cloudinary
async function uploadToCloudinary(fileBuffer, filename) {
  return new Promise((resolve, reject) => {
    const uploadStream = cloudinary.uploader.upload_stream(
      {
        folder: 'lcc-properties',
        public_id: filename.replace(/\.[^.]+$/, ''), // Nom sans extension
        resource_type: 'auto'
      },
      (error, result) => {
        if (error) {
          console.error('Erreur upload Cloudinary:', error);
          reject(error);
        } else {
          resolve(result.secure_url);
        }
      }
    );
    
    // Envoyer le buffer vers Cloudinary
    const bufferStream = require('stream').Readable.from(fileBuffer);
    bufferStream.pipe(uploadStream);
  });
}
// ============================================
// MIDDLEWARE D'AUTHENTIFICATION JWT
// ============================================
function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'Token manquant' });
  }
  const secret = process.env.JWT_SECRET || 'dev-secret-change-me';
  try {
    const decoded = jwt.verify(token, secret);
    
    // ✅ Détecter le type de compte
    if (decoded.type === 'sub_account') {
      req.user = { 
        id: null,
        subAccountId: decoded.subAccountId,
        type: 'sub',
        isSubAccount: true
      };
    } else if (decoded.type === 'agency_access') {
      // Token agence : l'agent gère un autre compte
      req.user = {
        id: decoded.id,          // compte géré (comme si on était ce user)
        agentId: decoded.agentId, // vrai identité de l'agent
        delegationId: decoded.delegationId,
        agencyPermissions: decoded.permissions,
        type: 'agency',
        isSubAccount: false,
        isAgencyAccess: true
      };
    } else {
      req.user = decoded;
      req.user.type = 'main';
      req.user.isSubAccount = false;
      req.user.isAgencyAccess = false;
    }
    
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Token invalide' });
  }
}
// ============================================
// MIDDLEWARE DE VÉRIFICATION D'ABONNEMENT
// À AJOUTER DANS server.js APRÈS authenticateToken
// ============================================

async function checkSubscription(req, res, next) {
  try {
    // ✅ Skip vérification pour sous-comptes
    if (req.user && req.user.isSubAccount) {
      return next();
    }
    
    const userId = req.user.id;

    // Récupérer l'abonnement
    const result = await pool.query(
      `SELECT status, trial_end_date, current_period_end
       FROM subscriptions 
       WHERE user_id = $1`,
      [userId]
    );

    if (result.rows.length === 0) {
      // Pas d'abonnement trouvé
      return res.status(403).json({ 
        error: 'Aucun abonnement', 
        subscriptionExpired: true 
      });
    }

    const sub = result.rows[0];
    const now = new Date();

    // Vérifier si l'abonnement est expiré
    if (sub.status === 'trial') {
      const trialEnd = new Date(sub.trial_end_date);
      if (now > trialEnd) {
        return res.status(403).json({ 
          error: 'Essai expiré', 
          subscriptionExpired: true 
        });
      }
    } else if (sub.status === 'active') {
      // L'abonnement actif est valide (géré par Stripe)
      // On pourrait vérifier current_period_end si besoin
    } else if (sub.status === 'expired' || sub.status === 'canceled') {
      return res.status(403).json({ 
        error: 'Abonnement expiré', 
        subscriptionExpired: true 
      });
    }

    // Abonnement valide — attacher le plan à req pour usage downstream
    req.planBase = getBasePlanName(sub.status === 'trial' ? 'starter' : (sub.plan_type || 'starter'));
    req.planType = sub.plan_type;
    req.isTrial  = sub.status === 'trial' || sub.status === 'trialing';
    next();

  } catch (err) {
    console.error('Erreur vérification abonnement:', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
}

