// ===== Helper: vérifier préférence avant envoi =====
async function shouldSendNotification(userId, prefKey) {
  try {
    const settings = await getNotificationSettings(userId);
    const allowed = settings[prefKey] !== false;
    if (!allowed) console.log(`ℹ️ Notif [${prefKey}] désactivée pour ${userId}`);
    return allowed;
  } catch(e) {
    return true;
  }
}

// ============================================================
// 🔔 NOTIFICATIONS VERS LES SOUS-COMPTES
// requiredPermission : colonne permission (ex: 'can_view_calendar')
// notifColumn (optionnel) : colonne notif_sub_* à vérifier en plus
// ============================================================
async function sendNotificationToSubAccountsOf(parentUserId, requiredPermission, title, body, data, notifColumn, propertyId, excludeTokens) {
  data = data || {};
  // Extraire propertyId depuis data si pas passé directement
  if (!propertyId && data.propertyId) propertyId = data.propertyId;
  try {
    console.log('🔍 [SubNotif] parentUserId:', parentUserId, '| permission:', requiredPermission, '| notifColumn:', notifColumn, '| propertyId:', propertyId);

    let q = `SELECT uft.fcm_token, sa.first_name, sa.id as sub_account_id
       FROM user_fcm_tokens uft
       JOIN sub_accounts sa ON sa.id = uft.sub_account_id
       JOIN sub_account_permissions sap ON sap.sub_account_id = sa.id
       WHERE sa.parent_user_id = $1
         AND sa.is_active = TRUE
         AND uft.sub_account_id IS NOT NULL
         AND uft.fcm_token IS NOT NULL
         AND sap.` + requiredPermission + ` = TRUE`;
    if (notifColumn) q += ` AND sap.` + notifColumn + ` = TRUE`;
    // Filtrer par logement si propertyId fourni
    // Si le sous-compte a des logements assignés, vérifier que propertyId en fait partie
    // Si aucun logement assigné (accès global), on envoie quand même
    if (propertyId) {
      q += ` AND (
        NOT EXISTS (SELECT 1 FROM sub_account_properties WHERE sub_account_id = sa.id)
        OR EXISTS (SELECT 1 FROM sub_account_properties WHERE sub_account_id = sa.id AND property_id = '` + propertyId + `')
      )`;
    }
    const result = await pool.query(q, [parentUserId]);
    console.log('🔍 [SubNotif] rows found:', result.rows.length);

    if (result.rows.length === 0) {
      // Debug sans les filtres token/notif pour voir ce qui bloque
      try {
        const debugCols = `sa.id, sa.first_name, sa.is_active, sap.` + requiredPermission
          + (notifColumn ? `, sap.` + notifColumn : '')
          + `, uft.fcm_token`;
        const debugQ = `SELECT ` + debugCols + ` FROM sub_accounts sa LEFT JOIN sub_account_permissions sap ON sap.sub_account_id = sa.id LEFT JOIN user_fcm_tokens uft ON uft.sub_account_id = sa.id WHERE sa.parent_user_id = $1`;
        const debugR = await pool.query(debugQ, [parentUserId]);
        console.log('🔍 [SubNotif] Debug (sans filtre):', JSON.stringify(debugR.rows));
      } catch(de) { console.log('🔍 [SubNotif] Debug query error:', de.message); }

      console.log('ℹ️ Aucun sous-compte [' + requiredPermission + '] avec token pour user ' + parentUserId);
      return;
    }

    const tokens = result.rows.map(function(r) { return r.fcm_token; })
      .filter(function(t) { return !excludeTokens || !excludeTokens.has(t); });
    console.log('📨 Notif sous-comptes [' + requiredPermission + ']: ' + tokens.length + ' destinataire(s)');
    if (!tokens.length) return;
    await sendNotificationToMultipleLogged(tokens, title, body, data);
    console.log('✅ Notif sous-comptes envoyée à ' + tokens.length + ' appareil(s)');

    // ── Envoyer aussi aux agents agence qui gèrent ce compte ──
    await sendNotificationToDelegatesOf(parentUserId, title, body, data);
  } catch (err) {
    console.error('❌ sendNotificationToSubAccountsOf [' + requiredPermission + ']:', err.message);
  }
}

// ── Envoyer une notif aux agents agence qui gèrent ce compte ──────
// Appelé quand un événement se produit sur le compte d'un propriétaire géré
async function sendNotificationToDelegatesOf(ownerUserId, title, body, data) {
  try {
    // Trouver tous les délégués actifs de ce propriétaire
    const delegates = await pool.query(
      `SELECT ad.delegate_user_id, uft.fcm_token
       FROM account_delegations ad
       JOIN user_fcm_tokens uft ON uft.user_id = ad.delegate_user_id
       WHERE ad.delegator_user_id = $1
         AND ad.status = 'accepted'
         AND uft.fcm_token IS NOT NULL
         AND uft.sub_account_id IS NULL`,  // tokens principaux uniquement
      [ownerUserId]
    );
    if (!delegates.rows.length) return;
    const tokens = delegates.rows.map(r => r.fcm_token);
    console.log(`📨 [AgenceNotif] Envoi à ${tokens.length} agent(s) pour compte ${ownerUserId}`);
    await sendNotificationToMultipleLogged(tokens, title, body, data || {});
    console.log(`✅ [AgenceNotif] Notif envoyée à ${tokens.length} agent(s)`);
  } catch(err) {
    console.error('❌ sendNotificationToDelegatesOf:', err.message);
  }
}

// Prend en compte : 1) assignation par reservation_key spécifique 2) cleaner par défaut du logement
async function getCleanerAssignmentsMapForUser(userId) {
  if (!userId) return {};

  // Assignations spécifiques (par reservation_key ou par property_id)
  const result = await pool.query(
    `
    SELECT
      ca.property_id,
      ca.cleaner_id,
      c.name  AS cleaner_name,
      c.email AS cleaner_email,
      c.phone AS cleaner_phone,
      c.is_active AS cleaner_active,
      c.sub_account_id AS cleaner_sub_account_id
    FROM cleaning_assignments ca
    LEFT JOIN cleaners c ON c.id = ca.cleaner_id
    WHERE ca.user_id = $1
    `,
    [userId]
  );

  const map = {};
  for (const row of result.rows) {
    if (row.cleaner_active === false) continue;
    if (!row.property_id || !row.cleaner_id) continue;

    map[row.property_id] = {
      cleanerId: row.cleaner_id,
      name: row.cleaner_name,
      email: row.cleaner_email,
      phone: row.cleaner_phone,
      sub_account_id: row.cleaner_sub_account_id
    };
  }

  // Compléter avec les cleaners par défaut pour les logements sans assignation
  try {
    const defaults = await pool.query(
      `SELECT pdc.property_id, pdc.cleaner_id, c.name, c.email, c.phone, c.is_active, c.sub_account_id
       FROM property_default_cleaners pdc
       LEFT JOIN cleaners c ON c.id = pdc.cleaner_id
       WHERE pdc.user_id = $1`,
      [userId]
    );

    for (const row of defaults.rows) {
      if (row.is_active === false) continue;
      // Ne pas écraser une assignation spécifique existante
      if (!map[row.property_id]) {
        map[row.property_id] = {
          cleanerId: row.cleaner_id,
          name: row.name,
          email: row.email,
          phone: row.phone,
          sub_account_id: row.sub_account_id
        };
      }
    }
  } catch (e) {
    // Table peut ne pas encore exister
    console.error('Fallback defaults cleaners:', e.message);
  }

  return map;
}

/**
 * Envoie les emails de notifications de nouvelles réservations / annulations,
 * en respectant les préférences de l'utilisateur.
 * 
 * VERSION CORRIGÉE AVEC LOGS DÉTAILLÉS POUR DEBUGGING WHATSAPP
 */
async function notifyOwnersAboutBookings(newReservations, cancelledReservations) {
   // ===================================================================
  // 🛑 EMAILS DÉSACTIVÉS : Nouvelles réservations et annulations
  // Si vous voulez les réactiver plus tard, supprimez juste le "return;" ci-dessous
  // ===================================================================
  console.log('ℹ️ notifyOwnersAboutBookings appelée mais DÉSACTIVÉE (pas d\'emails envoyés)');
  return;
  const brevoKey = process.env.BREVO_API_KEY && process.env.BREVO_API_KEY.trim();
  if (!brevoKey) {
    console.log(
      "⚠️ BREVO_API_KEY manquant : aucune notification propriétaire (nouvelle résa / annulation) ne sera envoyée."
    );
    return;
  }

  const from = process.env.EMAIL_FROM || "Boostinghost <no-reply@boostinghost.fr>";
  const tasks = [];

  const handleReservation = (res, type) => {
    const userId = res.userId;
    if (!userId) {
      console.log("⚠️  Réservation sans userId, notification ignorée :", res.uid || res.id);
      return;
    }

    tasks.push(
      (async () => {
        const user = await getUserForNotifications(userId);
        if (!user || !user.email) {
          console.log(`⚠️  Aucun email trouvé pour user ${userId}, notification ignorée`);
          return;
        }

        // 🔔 Récupérer les préférences de notifications
        let settings;
        try {
          settings = await getNotificationSettings(userId);
          console.log(
            `📋 Settings récupérés pour user ${userId}:`,
            JSON.stringify(settings, null, 2)
          );
        } catch (e) {
          console.error(
            "Erreur lors de la récupération des préférences de notifications pour user",
            userId,
            e
          );
          settings = { ...DEFAULT_NOTIFICATION_SETTINGS };
        }

        // Pour l'instant, on utilise la même option pour nouvelles résas & annulations
        if (settings && settings.newReservation === false) {
          console.log(
            `ℹ️ Notifications de réservations désactivées pour user ${userId}, email non envoyé.`
          );
          return;
        }

        const propertyName =
          (res.property && displayName(res.property)) ||
          res.propertyInternalName || res.internalName ||
          res.propertyName || res.property_name || "Votre logement";

        const guest = res.guestName || res.guest_name || res.guest || res.name || "Un voyageur";

        const source = res.source || res.platform || "une plateforme";

        const start = formatDateForEmail(res.start || res.startDate || res.checkIn || res.checkin);
        const end = formatDateForEmail(res.end || res.endDate || res.checkOut || res.checkout);

        const hello = user.firstName ? `Bonjour ${user.firstName},` : "Bonjour,";

        let subject;
        let textBody;
        let htmlBody;

        if (type === "new") {
          subject = `🛎️ Nouvelle réservation – ${propertyName}`;
          textBody = `${hello}

Une nouvelle réservation vient d'être enregistrée via ${source}.

Logement : ${propertyName}
Voyageur : ${guest}
Séjour  : du ${start} au ${end}

Vous pouvez retrouver tous les détails dans votre tableau de bord Boostinghost.`;

          htmlBody = bhEmailTemplate({
            icon: '🛎️',
            title: 'Nouvelle réservation',
            tag: propertyName,
            bodyHtml: `
              <p>${hello}</p>
              <p>Une nouvelle réservation vient d'être enregistrée via <strong>${source}</strong>.</p>
              <div class="info-card">
                <strong>Logement :</strong> ${propertyName}<br>
                <strong>Voyageur :</strong> ${guest}<br>
                <strong>Séjour :</strong> du ${start} au ${end}
              </div>
              <p>Retrouvez tous les détails dans votre tableau de bord Boostinghost.</p>
            `
          });
        } else {
          subject = `⚠️ Réservation annulée – ${propertyName}`;
          textBody = `${hello}

Une réservation vient d'être annulée sur ${source}.

Logement : ${propertyName}
Voyageur : ${guest}
Séjour initial : du ${start} au ${end}

Pensez à vérifier votre calendrier et vos blocages si nécessaire.`;

          htmlBody = bhEmailTemplate({
            icon: '⚠️',
            title: 'Réservation annulée',
            tag: propertyName,
            accentColor: '#D97706',
            bodyHtml: `
              <p>${hello}</p>
              <p>Une réservation vient d'être <strong>annulée</strong> sur <strong>${source}</strong>.</p>
              <div class="alert-card">
                <strong>Logement :</strong> ${propertyName}<br>
                <strong>Voyageur :</strong> ${guest}<br>
                <strong>Séjour initial :</strong> du ${start} au ${end}
              </div>
              <p>Pensez à vérifier votre calendrier et vos blocages si nécessaire.</p>
            `
          });
        }

        try {
          // 👉 Toujours via l'API Brevo
          console.log("📧 [Brevo API] Envoi email", type, "à", user.email);
          await sendEmailViaBrevo({
            to: user.email,
            subject,
            text: textBody,
            html: htmlBody,
          });

          console.log(
            `📧 Notification "${type}" envoyée à ${user.email} (resa uid=${res.uid || res.id})`
          );
        } catch (err) {
          console.error(
            `❌' Erreur envoi email de notification "${type}" à ${user.email} :`,
            err
          );
        }
      })()
    );
  };

  (newReservations || []).forEach((r) => handleReservation(r, "new"));
  (cancelledReservations || []).forEach((r) => handleReservation(r, "cancelled"));

  if (tasks.length === 0) {
    console.log("ℹ️ Aucune notification propriétaire à envoyer (listes vides).");
    return;
  }

  console.log(
    `📧 Notifications à envoyer – nouvelles: ${newReservations.length || 0}, annulées: ${
      cancelledReservations.length || 0
    }`
  );
  await Promise.all(tasks);
}
/**
 * Notifications ménage : pour chaque nouvelle réservation, si un logement a un cleaner assigné,
 * on envoie un email + (optionnel) un WhatsApp à ce cleaner.
 */
async function notifyCleanersAboutNewBookings(newReservations) {
  if (!newReservations || newReservations.length === 0) return;

  // ✅ Push cleaner sous-compte (indépendant de l'email)
  for (const res of newReservations) {
    const userId = res.userId || res.user_id;
    const propId = res.propertyId || res.property_id;
    if (!userId || !propId) { console.log('ℹ️ [ménage] userId/propertyId manquant'); continue; }
    let assignmentsMap = {};
    try { assignmentsMap = await getCleanerAssignmentsMapForUser(userId); } catch(e) { continue; }
    const assignment = assignmentsMap[propId];
    if (!assignment) { console.log(`ℹ️ [ménage] Aucun cleaner pour logement ${propId}`); continue; }
    if (!assignment.sub_account_id) { console.log(`ℹ️ [ménage] Cleaner sans sous-compte`); continue; }
    const propertyName = res.propertyName || res.property_name || 'Votre logement';
    try {
      const tokenRes = await pool.query(
        'SELECT fcm_token FROM user_fcm_tokens WHERE sub_account_id = $1 AND fcm_token IS NOT NULL',
        [assignment.sub_account_id]
      );
      if (tokenRes.rows.length > 0) {
        await sendNotificationToMultipleLogged(
          tokenRes.rows.map(r => r.fcm_token),
          '🧹 Nouveau ménage assigné',
          `${propertyName} — Vous avez un ménage à effectuer`,
          { type: 'cleaning_assigned', property_name: propertyName }
        );
        console.log(`✅ Push ménage envoyé au sous-compte ${assignment.sub_account_id}`);
      } else {
        console.log(`ℹ️ Sous-compte ${assignment.sub_account_id} sans token FCM`);
      }
    } catch(e) { console.error('❌ Push ménage:', e.message); }
  }

  // Emails (si configurés)
  const useBrevo = !!process.env.BREVO_API_KEY;
  const transporter = useBrevo ? null : getEmailTransporter();
  if (!useBrevo && !transporter) {
    console.log('⚠️  Pas d\'email configuré — push uniquement');
    return;
  }

  const from = process.env.EMAIL_FROM || 'Boostinghost <no-reply@boostinghost.fr>';
  const tasks = [];

  // On groupe par user, pour ne pas requêter 50 fois la base
  const byUser = new Map();
  for (const res of newReservations) {
    if (!res.userId || !res.propertyId) continue;
    if (!byUser.has(res.userId)) {
      byUser.set(res.userId, []);
    }
    byUser.get(res.userId).push(res);
  }

  for (const [userId, userReservations] of byUser.entries()) {
    let assignmentsMap = {};
    try {
      assignmentsMap = await getCleanerAssignmentsMapForUser(userId);
    } catch (err) {
      console.error('Erreur récupération assignations ménage pour user', userId, err);
      continue;
    }

    if (!assignmentsMap || Object.keys(assignmentsMap).length === 0) {
      continue;
    }

    for (const res of userReservations) {
      const assignment = assignmentsMap[res.propertyId];
      if (!assignment) {
        // Aucun cleaner assigné à ce logement → rien à envoyer
        continue;
      }

      const cleanerEmail = assignment.email;
      const cleanerPhone = assignment.phone;
      const cleanerName  = assignment.name || 'partenaire ménage';

      const propertyName =
        (res.property && displayName(res.property)) ||
        res.propertyInternalName || res.internalName ||
        res.propertyName || res.property_name ||
        'Votre logement';

      const guest =
        res.guestName ||
        res.guest_name ||
        res.guest ||
        res.name ||
        'Un voyageur';

      const start = formatDateForEmail(
        res.start || res.startDate || res.checkIn || res.checkin
      );
      const end = formatDateForEmail(
        res.end || res.endDate || res.checkOut || res.checkout
      );

      const hello = cleanerName ? `Bonjour ${cleanerName},` : 'Bonjour,';

            // Email
      if ((useBrevo || transporter) && cleanerEmail) {
        const subject = `🧹 Nouveau ménage à prévoir – ${propertyName}`;
        const textBody = `${hello}

Un nouveau séjour vient d'être réservé pour le logement ${propertyName}.

Voyageur : ${guest}
Séjour  : du ${start} au ${end}
Ménage à prévoir : le ${end} après le départ des voyageurs
(heure exacte de check-out à confirmer avec la conciergerie).

Merci beaucoup,
L'équipe Boostinghost`;

        const htmlBody = bhEmailTemplate({
          icon: '🧹',
          title: 'Nouveau ménage à prévoir',
          tag: propertyName,
          bodyHtml: `
            <p>${hello}</p>
            <p>Un nouveau séjour vient d'être réservé pour le logement <strong>${propertyName}</strong>.</p>
            <div class="info-card">
              <strong>Voyageur :</strong> ${guest}<br>
              <strong>Séjour :</strong> du ${start} au ${end}<br>
              <strong>Ménage à prévoir :</strong> le ${end} après le départ
            </div>
            <p>Heure exacte de check-out à confirmer avec la conciergerie.</p>
          `
        });

        tasks.push(
          (useBrevo
            ? sendEmailViaBrevo({
                to: cleanerEmail,
                subject,
                text: textBody,
                html: htmlBody
              })
            : transporter.sendMail({
                from,
                to: cleanerEmail,
                subject,
                text: textBody,
                html: htmlBody
              })
          )
            .then(() => {
              console.log(
                `📧 Notification ménage envoyée à ${cleanerEmail} (resa uid=${res.uid || res.id})`
              );
            })
            .catch((err) => {
              console.error('❌ Erreur envoi email notification ménage :', err);
            })
        );
      }
    }
  }

  await Promise.all(tasks);
}
/**
 * Envoie chaque jour un planning de ménage pour "demain"
 * à chaque cleaner assigné (email + WhatsApp si dispo).
 */
async function sendDailyCleaningPlan() {
  const useBrevo = !!process.env.BREVO_API_KEY;
  const transporter = useBrevo ? null : getEmailTransporter();

  if (!useBrevo && !transporter) {
    console.log(
      '⚠️  Ni email (Brevo/SMTP) ni WhatsApp configurés, planning ménage non envoyé'
    );
    return;
  }

  if (!PROPERTIES || !Array.isArray(PROPERTIES) || PROPERTIES.length === 0) {
    console.log('ℹ️ Aucun logement configuré, pas de planning ménage à envoyer.');
    return;
  }

  const now = new Date();
  const tomorrow = new Date(now.getFullYear(), now.getMonth(), now.getDate() + 1);
  const tomorrowIso = tomorrow.toISOString().slice(0, 10); // yyyy-mm-dd

  // 1) Construire un map propertyId -> { cleanerId, name, email, phone }
  const assignmentsByPropertyId = {};

  const userIds = [...new Set(PROPERTIES.map((p) => p.userId))];
  for (const userId of userIds) {
    const map = await getCleanerAssignmentsMapForUser(userId);
    Object.keys(map).forEach((propertyId) => {
      assignmentsByPropertyId[propertyId] = map[propertyId];
    });
  }

  // 2) Construire tâches par cleaner
  const tasksByCleanerId = {}; // cleanerId -> { cleaner, tasks: [] }

  for (const property of PROPERTIES) {
    const assignment = assignmentsByPropertyId[property.id];
    if (!assignment) continue;

    const reservations = reservationsStore.properties[property.id] || [];
    for (const r of reservations) {
      if (!r || !r.end) continue;
      if (r.type === 'block' || r.source === 'BLOCK') continue;

      const endDate = new Date(r.end);
      if (Number.isNaN(endDate.getTime())) continue;

      const endIso = endDate.toISOString().slice(0, 10);
      if (endIso !== tomorrowIso) continue; // checkout pas demain → ignore

      const cleanerId = assignment.cleanerId;
      if (!tasksByCleanerId[cleanerId]) {
        tasksByCleanerId[cleanerId] = {
          cleaner: assignment,
          tasks: []
        };
      }

      tasksByCleanerId[cleanerId].tasks.push({
        propertyName: displayName(property) || property.id,
        guestName: r.guestName || r.guest_name || r.name || 'Voyageur',
        start: formatDateForEmail(r.start || r.startDate || r.checkIn || r.checkin),
        end: formatDateForEmail(r.end)
      });
    }
  }

  const tasks = [];
  const from = process.env.EMAIL_FROM || 'Boostinghost <no-reply@boostinghost.fr>';

  Object.keys(tasksByCleanerId).forEach((cleanerId) => {
    const entry = tasksByCleanerId[cleanerId];
    const cleaner = entry.cleaner;
    const jobs = entry.tasks;

    if (!jobs || jobs.length === 0) return;

const cleanerName = cleaner.name || '';
const cleanerEmail = cleaner.email;
const cleanerPhone = cleaner.phone;

const hello = cleanerName ? `Bonjour ${cleanerName},` : 'Bonjour,';
const subject = `🧹 Planning ménage – ${tomorrowIso}`;

if ((useBrevo || transporter) && cleanerEmail) {
  // Construction du textBody
  let textBody = `${hello}\n\nPlanning ménage de demain (${tomorrowIso}):\n\n`;
  jobs.forEach((job, index) => {
    textBody += `${index + 1}. ${job.propertyName} – départ le ${job.end} (${job.guestName})\n`;
  });
  textBody += '\nMerci beaucoup,\nL\'équipe Boostinghost';

  // Construction du htmlBody
  const jobsHtml = jobs.map(job => `
    <div class="feat-row">
      <div class="feat-icon">🏠</div>
      <div class="feat-text"><strong>${job.propertyName}</strong> — départ le ${job.end} (${job.guestName})</div>
    </div>`).join('');
  let htmlBody = bhEmailTemplate({
    icon: '🧹',
    title: 'Planning ménage',
    tag: `Demain — ${tomorrowIso}`,
    bodyHtml: `
      <p>${hello}</p>
      <p>Voici votre planning ménage pour demain :</p>
      <div class="info-card">${jobsHtml}</div>
    `
  });

  tasks.push(
    (useBrevo
      ? sendEmailViaBrevo({
          to: cleanerEmail,
          subject,
          text: textBody,
          html: htmlBody
        })
      : transporter.sendMail({
          from,
          to: cleanerEmail,
          subject,
          text: textBody,
          html: htmlBody
        })
    )
      .then(() => {
        console.log(
          `📧 Planning ménage envoyé à ${cleanerEmail} pour ${tomorrowIso}`
        );
      })
      .catch((err) => {
        console.error('❌ Erreur envoi planning ménage (email) :', err);
      })
  );
  }
    // WhatsApp
  });

  await Promise.all(tasks);

  console.log('✅ Planning ménage quotidien envoyé (si tâches détectées).');
}

