// ============================================
// GET /api/subscription/features
// Retourne les features accessibles pour l'utilisateur courant
// ============================================
app.get('/api/subscription/features', authenticateAny, async (req, res) => {
  try {
    const userId = req.user?.isSubAccount ? req.user.parentUserId : req.user?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const subResult = await pool.query(
      `SELECT plan_type, status, trial_end_date FROM subscriptions WHERE user_id = $1 ORDER BY created_at DESC LIMIT 1`,
      [userId]
    );
    const sub = subResult.rows[0];
    const isTrial = sub && (sub.status === 'trial' || sub.status === 'trialing');
    const trialValid = isTrial && sub.trial_end_date && new Date() < new Date(sub.trial_end_date);
    const basePlan = sub ? getBasePlanName(sub.plan_type) : 'starter';

    // En trial : accès complet
    const features = {};
    for (const [feature, plans] of Object.entries(PLAN_FEATURES)) {
      features[feature] = trialValid || plans.includes(basePlan);
    }

    res.json({
      plan: basePlan,
      planType: sub?.plan_type || 'starter',
      status: sub?.status || 'none',
      isTrial: trialValid,
      features
    });
  } catch(err) {
    console.error('GET /api/subscription/features:', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

app.get('/api/subscription/status', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.id;

    const result = await pool.query(
      `SELECT 
        status, 
        plan_type, 
        trial_end_date,
        current_period_end,
        stripe_subscription_id,
        sms_enabled
      FROM subscriptions 
      WHERE user_id = $1`,
      [userId]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Aucun abonnement trouvé' });
    }

    const sub = result.rows[0];
    const now = new Date();

    // Calculer les jours restants pour les trials
    let daysRemaining = null;
    if (sub.status === 'trial' && sub.trial_end_date) {
      const trialEnd = new Date(sub.trial_end_date);
      const diffTime = trialEnd - now;
      daysRemaining = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    }

    // ✅ Calculer le montant avec la fonction getPlanAmount
    const planAmount = getPlanAmount(sub.plan_type);

    // ✅ Message d'affichage
    let displayMessage = 'Abonnement';
    if (sub.status === 'trial') {
      displayMessage = 'Essai gratuit';
    } else if (sub.status === 'active') {
      displayMessage = `Abonnement ${getPlanDisplayName(sub.plan_type)}`;
    } else if (sub.status === 'expired') {
      displayMessage = 'Abonnement expiré';
    } else if (sub.status === 'canceled') {
      displayMessage = 'Abonnement annulé';
    }

    const basePlan = getBasePlanName(sub.plan_type || 'solo');
    const smsIncluded = basePlan === 'pro';
    const smsEnabled = smsIncluded || (sub.sms_enabled === true);

    res.json({
      status: sub.status,
      planType: sub.plan_type,
      planAmount: planAmount,
      trialEndDate: sub.trial_end_date,
      currentPeriodEnd: sub.current_period_end,
      daysRemaining: daysRemaining,
      displayMessage: displayMessage,
      showAlert: sub.status === 'trial' && daysRemaining !== null && daysRemaining <= 3,
      smsEnabled: smsEnabled,
      smsIncluded: smsIncluded
    });

  } catch (err) {
    console.error('Erreur subscription status:', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});
