// ============================================
// ROUTES API - BOOKINGS (alias pour réservations)
// Utilisé par le calendrier moderne (calendar-modern.js)
// ============================================

// GET - Liste des bookings pour l'utilisateur courant
app.get('/api/bookings', async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) {
      return res.status(401).json({ error: 'Non autorisé' });
    }

    const userProps = getUserProperties(user.id);
    const bookings = [];

    userProps.forEach(property => {
      const propertyReservations = reservationsStore.properties[property.id] || [];

      propertyReservations.forEach(r => {
        const checkIn = r.checkIn || r.start;
        const checkOut = r.checkOut || r.end;
        if (!checkIn || !checkOut) return;

        let platformRaw = r.platform || r.source || '';
        let platform = (platformRaw || '').toString().toLowerCase();
        if (platform.includes('airbnb')) platform = 'airbnb';
        else if (platform.includes('booking')) platform = 'booking';
        else if (platform.includes('vrbo') || platform.includes('abritel') || platform.includes('homeaway')) platform = 'vrbo';
        else if (platform.includes('expedia')) platform = 'expedia';
        else if (platform.includes('block')) platform = 'block';
        else if (!platform) platform = 'direct';

        bookings.push({
          id: r.uid || r.id || `${property.id}-${checkIn}-${checkOut}`,
          propertyId: property.id,
          propertyName: displayName(property),
          propertyColor: property.color,
          checkIn,
          checkOut,
          guestName: r.guestName || r.summary || '',
          platform,
          price: r.price || 0,
          type: r.type || (platform === 'block' ? 'block' : 'manual')
        });
      });
    });

    res.json(bookings);
  } catch (err) {
    console.error('Erreur GET /api/bookings :', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// POST - Créer un booking manuel (alias de /api/reservations/manual)
app.post('/api/bookings', async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) {
      return res.status(401).json({ error: 'Non autorisé' });
    }
    const { propertyId, checkIn, checkOut, guestName, platform, price } = req.body || {};
    if (!propertyId || !checkIn || !checkOut) {
      return res.status(400).json({ error: 'propertyId, checkIn et checkOut sont requis' });
    }
    const property = PROPERTIES.find(p => p.id === propertyId && p.userId === user.id);
    if (!property) {
      return res.status(404).json({ error: 'Logement non trouvé' });
    }
    const reservation = {
      uid: 'manual_' + Date.now(),
      start: checkIn,
      end: checkOut,
      source: platform || 'MANUEL',
      platform: platform || 'direct',
      type: 'manual',
      guestName: guestName || 'Réservation manuelle',
      price: typeof price === 'number' ? price : 0,
      createdAt: new Date().toISOString()
    };
    
    if (!MANUAL_RESERVATIONS[propertyId]) {
      MANUAL_RESERVATIONS[propertyId] = [];
    }
    MANUAL_RESERVATIONS[propertyId].push(reservation);
    setImmediate(() => syncAllCalendars());
    
    const bookingForClient = {
      id: reservation.uid,
      propertyId: property.id,
      propertyName: displayName(property),
      propertyColor: property.color,
      checkIn,
      checkOut,
      guestName: reservation.guestName,
      platform: reservation.platform,
      price: reservation.price,
      type: reservation.type
    };
    
    res.status(201).json(bookingForClient);
  } catch (err) {
    console.error('Erreur POST /api/bookings :', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// POST - Forcer une synchronisation
app.post('/api/sync', authenticateAny, async (req, res) => {
  // Déterminer l'userId (parent si sous-compte, sinon user direct)
  let userId;
  
  if (req.user.isSubAccount) {
    const subResult = await pool.query(
      'SELECT parent_user_id FROM sub_accounts WHERE id = $1',
      [req.user.subAccountId]
    );
    
    if (subResult.rows.length === 0) {
      return res.status(401).json({ error: 'Sous-compte introuvable' });
    }
    
    userId = subResult.rows[0].parent_user_id;
    console.log(`🔄 Sync demandé par sous-compte ${req.user.subAccountId} (parent: ${userId})`);
  } else {
    const user = await getUserFromRequest(req);
    if (!user) {
      return res.status(401).json({ error: 'Non autorisé' });
    }
    userId = user.id;
  }

  if (reservationsStore.syncStatus === 'syncing') {
    return res.status(409).json({
      error: 'Synchronisation déjà en cours',
      status: 'syncing'
    });
  }

  try {
    const result = await syncAllCalendars();
    const userProps = getUserProperties(userId);

    res.json({
      message: 'Synchronisation réussie',
      lastSync: result.lastSync,
      properties: userProps.map(p => ({
        id: p.id,
        name: p.name,
        count: (result.properties[p.id] || []).length
      }))
    });
  } catch (error) {
    res.status(500).json({
      error: 'Erreur lors de la synchronisation',
      details: error.message
    });
  }
});

app.get('/api/stats', async (req, res) => {
  const user = await getUserFromRequest(req);
  if (!user) {
    return res.status(401).json({ error: 'Non autorisé' });
  }

  const stats = {
    totalReservations: 0,
    upcomingReservations: 0,
    currentReservations: 0,
    byProperty: {},
    byMonth: {}
  };

  const now = new Date();
  const userProps = getUserProperties(user.id);

  userProps.forEach(property => {
    const reservations = reservationsStore.properties[property.id] || [];
    stats.totalReservations += reservations.length;

    const upcoming = reservations.filter(r => new Date(r.start) > now).length;
    const current = reservations.filter(r =>
      new Date(r.start) <= now && new Date(r.end) >= now
    ).length;

    stats.upcomingReservations += upcoming;
    stats.currentReservations += current;

    stats.byProperty[property.id] = {
      name: property.name,
      total: reservations.length,
      upcoming,
      current
    };

    reservations.forEach(r => {
      const month = new Date(r.start).toISOString().slice(0, 7);
      stats.byMonth[month] = (stats.byMonth[month] || 0) + 1;
    });
  });

  res.json(stats);
});

app.get('/api/availability/:propertyId', async (req, res) => {
  const user = await getUserFromRequest(req);
  if (!user) {
    return res.status(401).json({ error: 'Non autorisé' });
  }

  const { propertyId } = req.params;
  const { startDate, endDate } = req.query;

  const property = PROPERTIES.find(p => p.id === propertyId && p.userId === user.id);
  if (!property) {
    return res.status(404).json({ error: 'Logement non trouvé' });
  }

  const reservations = reservationsStore.properties[propertyId] || [];
  const start = new Date(startDate);
  const end = new Date(endDate);

  const overlappingReservations = reservations.filter(r => {
    const rStart = new Date(r.start);
    const rEnd = new Date(r.end);
    return (rStart <= end && rEnd >= start);
  });

  res.json({
    property: {
      id: property.id,
      name: property.name
    },
    period: { start: startDate, end: endDate },
    available: overlappingReservations.length === 0,
    overlappingReservations
  });
});

// ============================================
// ROUTE CORRIGÉE : /api/reservations-with-deposits
// AVEC INFOS VOYAGEUR (guest_first_name, guest_last_name)
// ============================================
// Remplacer la route existante dans server.js (vers ligne 6421)

app.get('/api/reservations-with-deposits', authenticateAny, loadSubAccountData(pool), async (req, res) => {
  try {
    // Résoudre userId (compte principal ou sous-compte)
    let userId;
    if (req.user.isSubAccount) {
      const sub = await pool.query('SELECT parent_user_id FROM sub_accounts WHERE id = $1', [req.user.subAccountId]);
      if (!sub.rows.length) return res.status(404).json({ error: 'Sous-compte introuvable' });
      userId = sub.rows[0].parent_user_id;
    } else {
      userId = req.user.id;
    }
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    // Propriétés accessibles — lire depuis la DB pour être sûr d'avoir toutes les props
    // (PROPERTIES en mémoire peut être désynchronisé si props créées après démarrage)
    const propsResult = await pool.query(
      `SELECT id, name, internal_name FROM properties WHERE user_id = $1`,
      [userId]
    );
    let userProps = propsResult.rows;
    if (req.user.isSubAccount && req.subAccountData?.accessible_property_ids?.length > 0) {
      userProps = userProps.filter(p => req.subAccountData.accessible_property_ids.includes(p.id));
    }
    const propIds = userProps.map(p => p.id);
    console.log('[deposits-kpi] propIds=' + propIds.length + ': ' + propIds.join(', '));
    if (!propIds.length) return res.json([]);



    // ── 1. Tous les deposits de l'utilisateur ──────────────────────────────
    const depositsResult = await pool.query(
      `SELECT id, reservation_uid, amount_cents, status, checkout_url, stripe_session_id, created_at
       FROM deposits WHERE user_id = $1`,
      [userId]
    );
    const depositsMap = new Map();
    depositsResult.rows.forEach(d => {
      const obj = {
        id: d.id,
        amountCents: d.amount_cents,
        status: d.status,
        checkoutUrl: d.checkout_url,
        stripeSessionId: d.stripe_session_id,
        createdAt: d.created_at
      };
      // Garder le deposit ABOUTI en priorité (capturé/payé/autorisé), puis le
      // plus récent — pour éviter d'afficher un lien "En attente" alors qu'un
      // autre lien de la même réservation a bien été réglé.
      const depRank = (s) => ({ captured: 5, paid: 5, authorized: 4, processing: 2, pending: 1 }[s] || 0);
      const setIfNewer = (key) => {
        if (!key) return;
        const cur = depositsMap.get(key);
        if (!cur) { depositsMap.set(key, obj); return; }
        const better = depRank(obj.status) > depRank(cur.status)
          || (depRank(obj.status) === depRank(cur.status) && cur.createdAt < obj.createdAt);
        if (better) depositsMap.set(key, obj);
      };

      // Indexer par reservation_uid tel quel (ex: 'CHX_xxx' ou 'manual_xxx')
      setIfNewer(d.reservation_uid);

      // Si le uid commence par 'CHX_', indexer aussi sans le préfixe
      // → pour matcher r.channex_booking_id directement
      if (d.reservation_uid && d.reservation_uid.startsWith('CHX_')) {
        setIfNewer(d.reservation_uid.slice(4)); // sans 'CHX_'
      }
    });

    console.log('[deposits-kpi] userId=' + userId + ' | deposits trouvés en DB=' + depositsResult.rows.length + ' | statuts=' + JSON.stringify(depositsResult.rows.map(d => ({uid: d.reservation_uid, status: d.status}))));

    // ── 2. Toutes les réservations depuis la DB (TOUTES sources) ──────────
    // On lit directement depuis reservations — pas depuis reservationsStore
    // qui ne contient que les résas iCal/Channex.
    const placeholders = propIds.map((_, i) => '$' + (i + 2)).join(',');

    // Récupérer d'abord les uids de deposits actifs pour cet user (pour inclure résas annulées)
    const activeDepUids = await pool.query(
      `SELECT reservation_uid FROM deposits WHERE user_id = $1 AND status IN ('authorized','captured')`,
      [userId]
    );
    const activeDepUidList = activeDepUids.rows.map(r => r.reservation_uid).filter(Boolean);

    // Construire la condition pour les résas annulées avec deposit actif
    let cancelledWithDepCondition = 'FALSE';
    let extraParams = [];
    if (activeDepUidList.length > 0) {
      const depPlaceholders = activeDepUidList.map((_, i) => '$' + (propIds.length + 2 + i)).join(',');
      cancelledWithDepCondition = 'r.uid IN (' + depPlaceholders + ')';
      extraParams = activeDepUidList;
    }

    const resaResult = await pool.query(
      'SELECT' +
      ' r.uid, r.channex_booking_id, r.property_id, r.start_date, r.end_date,' +
      ' r.guest_name, r.guest_first_name, r.guest_last_name,' +
      ' r.guest_email, r.guest_phone, r.guest_country,' +
      ' r.occupancy_adults, r.occupancy_children,' +
      ' r.amount_total, r.amount_rooms, r.amount_taxes,' +
      ' r.amount_cleaning, r.ota_commission, r.host_payout,' +
      ' r.currency, r.source, r.platform, r.ota_name,' +
      ' p.name as prop_name, p.internal_name as prop_internal_name' +
      ' FROM reservations r' +
      ' LEFT JOIN properties p ON p.id = r.property_id' +
      ' WHERE r.user_id = $1' +
      ' AND r.property_id IN (' + placeholders + ')' +
' AND (r.status != \'cancelled\' OR ' + cancelledWithDepCondition + ')' +
      ' ORDER BY r.start_date DESC',
      [userId, ...propIds, ...extraParams]
    );


    // ── 3. Construire le résultat ──────────────────────────────────────────
    const result = resaResult.rows.map(r => {
      // Chercher le deposit : d'abord par uid exact, puis par channex_booking_id
      // (les deposits Channex ont reservation_uid = 'CHX_' + channex_booking_id)
      const deposit = depositsMap.get(r.uid)
        || (r.channex_booking_id ? depositsMap.get('CHX_' + r.channex_booking_id) : null)
        || (r.channex_booking_id ? depositsMap.get(r.channex_booking_id) : null)
        || null;
      const propMeta = userProps.find(p => p.id === r.property_id);
      const propName = r.prop_internal_name || r.prop_name
        || (propMeta ? (propMeta.internal_name || propMeta.name) : null)
        || r.property_id;

      const gFirst   = r.guest_first_name || '';
      const gLast    = r.guest_last_name  || '';
      const gDisplay = gFirst ? (gLast ? gFirst + ' ' + gLast : gFirst) : (r.guest_name || '');

      const toISO = d => d ? (d.toISOString ? d.toISOString() : String(d)) : null;

      return {
        reservationUid:    r.uid,
        propertyId:        r.property_id,
        propertyName:      propName,
        startDate:         toISO(r.start_date),
        endDate:           toISO(r.end_date),
        guestName:         gDisplay || r.guest_name || '',
        guestFirstName:    gFirst,
        guestLastName:     gLast,
        guestDisplayName:  gDisplay,
        guestPhone:        r.guest_phone  || '',
        guestEmail:        r.guest_email  || '',
        guestCountry:      r.guest_country || null,
        occupancyAdults:   r.occupancy_adults   || null,
        occupancyChildren: r.occupancy_children || 0,
        amountTotal:       r.amount_total    ? parseFloat(r.amount_total)    : null,
        amountRooms:       r.amount_rooms    ? parseFloat(r.amount_rooms)    : null,
        amountTaxes:       r.amount_taxes    ? parseFloat(r.amount_taxes)    : null,
        amountCleaning:    r.amount_cleaning ? parseFloat(r.amount_cleaning) : null,
        otaCommission:     r.ota_commission  ? parseFloat(r.ota_commission)  : null,
        currency:          r.currency || 'EUR',
        source:            r.ota_name || r.platform || r.source || 'direct',
        deposit:           deposit ? {
          id:           deposit.id,
          amountCents:  deposit.amountCents,
          status:       deposit.status,
          checkoutUrl:  deposit.checkoutUrl,
          createdAt:    deposit.createdAt
        } : null
      };
    });

    console.log('✅ /api/reservations-with-deposits: ' + result.length + ' résas, ' + depositsMap.size + ' deposits');
    res.json(result);

  } catch (error) {
    console.error('❌ Erreur /api/reservations-with-deposits:', error);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// ============================================
// GET /api/reservations/invoice-summary
// Agrège les réservations par plateforme sur une période + logements donnés
// Retourne le net hôte par plateforme pour pré-remplir une facture propriétaire
// ============================================
// ============================================
// GET /api/reservations-with-payments
// Même structure que reservations-with-deposits mais avec payments
// ============================================
app.get('/api/reservations-with-payments', authenticateAny, requirePermission(pool, 'can_view_payments'), loadSubAccountData(pool), async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;

    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    // Charger tous les paiements de l'utilisateur depuis PostgreSQL
    const paymentsResult = await pool.query(
      'SELECT * FROM payments WHERE user_id = $1 ORDER BY created_at DESC',
      [userId]
    );
    const paymentsRows = paymentsResult.rows;

    // Indexer par reservation_uid — en cas de plusieurs liens pour la même
    // réservation (ex: un 1er lien erroné puis un 2e), on garde EN PRIORITÉ le
    // paiement abouti (payé), puis le plus récent. Évite d'afficher "En attente"
    // alors qu'un des liens a bien été réglé.
    const payRank = (s) => ({ paid: 4, captured: 4, authorized: 3, processing: 2, pending: 1 }[s] || 0);
    const paymentByUid = {};
    paymentsRows.forEach(p => {
      const cand = {
        id: p.id,
        amountCents: p.amount_cents,
        status: p.status,
        checkoutUrl: p.checkout_url,
        description: p.metadata?.description || '',
        createdAt: p.created_at
      };
      const cur = paymentByUid[p.reservation_uid];
      if (!cur) { paymentByUid[p.reservation_uid] = cand; return; }
      const better = payRank(cand.status) > payRank(cur.status)
        || (payRank(cand.status) === payRank(cur.status) && new Date(cand.createdAt) > new Date(cur.createdAt));
      if (better) paymentByUid[p.reservation_uid] = cand;
    });

    // Charger toutes les réservations enrichies depuis la DB
    const dbResResult = await pool.query(`
      SELECT r.uid, r.property_id, r.start_date, r.end_date,
        r.guest_name, r.guest_first_name, r.guest_last_name,
        r.guest_email, r.guest_phone, r.guest_country,
        r.occupancy_adults, r.occupancy_children,
        r.amount_total, r.amount_rooms, r.amount_taxes,
        r.amount_cleaning, r.ota_commission, r.host_payout,
        r.currency, r.source, r.channex_booking_id, r.ota_name
      FROM reservations r WHERE r.user_id = $1
    `, [userId]);
    const dbResMap = new Map();
    dbResResult.rows.forEach(r => {
      dbResMap.set(r.uid, r);
      if (r.channex_booking_id) dbResMap.set('CHX_' + r.channex_booking_id, r);
      if (r.start_date) {
        const d = r.start_date.toISOString ? r.start_date.toISOString().split('T')[0] : String(r.start_date).split('T')[0];
        dbResMap.set(r.property_id + '_' + d, r);
      }
    });

    const result = [];
    const userProperties = PROPERTIES.filter(p => p.userId === userId);

    userProperties.forEach(property => {
      const propReservations = reservationsStore.properties[property.id] || [];
      propReservations.forEach(r => {
        if (!r.uid || r.type === 'block' || r.source === 'BLOCK') return;
        const payment = paymentByUid[r.uid] || null;
        const startDate = r.start ? new Date(r.start).toISOString().split('T')[0] : '';
        const dbData = dbResMap.get(r.uid) || dbResMap.get(property.id + '_' + startDate) || null;
        const gFirst = dbData?.guest_first_name || '';
        const gLast  = dbData?.guest_last_name  || '';
        const gDisplay = gFirst ? (gLast ? gFirst + ' ' + gLast : gFirst) : (dbData?.guest_name || r.guestName || '');
        result.push({
          reservationUid: r.uid,
          propertyId: property.id,
          propertyName: displayName(property),
          startDate: r.start,
          endDate: r.end,
          guestName: gDisplay || r.guestName || '',
          guestFirstName:  gFirst,
          guestLastName:   gLast,
          guestDisplayName: gDisplay,
          guestPhone:    dbData?.guest_phone   || '',
          guestEmail:    dbData?.guest_email   || '',
          guestCountry:  dbData?.guest_country || null,
          occupancyAdults:   dbData?.occupancy_adults   || null,
          occupancyChildren: dbData?.occupancy_children || 0,
          amountTotal:    dbData?.amount_total    ? parseFloat(dbData.amount_total)    : null,
          amountRooms:    dbData?.amount_rooms    ? parseFloat(dbData.amount_rooms)    : null,
          amountTaxes:    dbData?.amount_taxes    ? parseFloat(dbData.amount_taxes)    : null,
          amountCleaning: dbData?.amount_cleaning ? parseFloat(dbData.amount_cleaning) : null,
          otaCommission:  dbData?.ota_commission  ? parseFloat(dbData.ota_commission)  : null,
          currency: dbData?.currency || 'EUR',
          source: r.source || dbData?.source || '',
          payment
        });
      });
    });

    // Ajouter les résas Channex absentes du store iCal
    const storeUids = new Set(result.map(r => r.reservationUid));
    for (const [key, dbData] of dbResMap.entries()) {
      if (!key.startsWith('CHX_') && !key.includes('_20')) {
        if (dbData.source === 'channex' && !storeUids.has(dbData.uid)) {
          const prop = userProperties.find(p => p.id === dbData.property_id);
          if (!prop) continue;
          const payment = paymentByUid[dbData.uid] || null;
          const startD = dbData.start_date ? (dbData.start_date.toISOString ? dbData.start_date.toISOString() : String(dbData.start_date)) : null;
          const endD   = dbData.end_date   ? (dbData.end_date.toISOString   ? dbData.end_date.toISOString()   : String(dbData.end_date))   : null;
          const gFirst = dbData.guest_first_name || '';
          const gLast  = dbData.guest_last_name  || '';
          const gDisplay = gFirst ? (gLast ? gFirst + ' ' + gLast : gFirst) : (dbData.guest_name || '');
          result.push({
            reservationUid: dbData.uid,
            propertyId: prop.id, propertyName: displayName(prop),
            startDate: startD, endDate: endD,
            guestName: gDisplay || dbData.guest_name || '',
            guestFirstName: gFirst, guestLastName: gLast, guestDisplayName: gDisplay,
            guestPhone: dbData.guest_phone || '', guestEmail: dbData.guest_email || '',
            guestCountry: dbData.guest_country || null,
            guestAddress: dbData.guest_address || null,
            guestZip:     dbData.guest_zip     || null,
            occupancyAdults: dbData.occupancy_adults || null,
            occupancyChildren: dbData.occupancy_children || 0,
            amountTotal:    dbData.amount_total    ? parseFloat(dbData.amount_total)    : null,
            amountRooms:    dbData.amount_rooms    ? parseFloat(dbData.amount_rooms)    : null,
            amountTaxes:    dbData.amount_taxes    ? parseFloat(dbData.amount_taxes)    : null,
            amountCleaning: dbData.amount_cleaning ? parseFloat(dbData.amount_cleaning) : null,
            otaCommission:  dbData.ota_commission  ? parseFloat(dbData.ota_commission)  : null,
            currency: dbData.currency || 'EUR',
            source: dbData.ota_name || dbData.source || 'channex',
            payment
          });
          storeUids.add(dbData.uid);
        }
      }
    }

    // Trier: paiements en premier, puis par date de début
    result.sort((a, b) => {
      if (a.payment && !b.payment) return -1;
      if (!a.payment && b.payment) return 1;
      return new Date(a.startDate) - new Date(b.startDate);
    });

    res.json(result);
  } catch (error) {
    console.error('❌ Erreur /api/reservations-with-payments:', error);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// ============================================
// ✅ GET - Réservations enrichies (risque + checklist + sous-scores)
// ============================================
app.get('/api/reservations/enriched', authenticateAny, checkSubscription, async (req, res) => {
  const user = await getUserFromRequest(req);
  if (!user) return res.status(401).json({ error: 'Non autorisé' });

  try {
    // Pré-calcul turnover par property
    const turnoverByUid = new Map();

    const userProps = PROPERTIES.filter(p => p.userId === user.id);

    for (const property of userProps) {
      const list = (reservationsStore.properties[property.id] || [])
        .filter(r => r && r.start && r.end && r.type !== 'block' && r.source !== 'BLOCK');

      const sorted = [...list].sort((a, b) => new Date(a.start) - new Date(b.start));
      for (let i = 0; i < sorted.length; i++) {
        const cur = sorted[i];
        const prev = sorted[i - 1];
        if (!prev) continue;
        const gapHours = (new Date(cur.start) - new Date(prev.end)) / (1000 * 60 * 60);
        turnoverByUid.set(cur.uid, gapHours);
      }
    }

    const now = new Date();
    const result = [];

    for (const property of userProps) {
      const reservations = (reservationsStore.properties[property.id] || [])
        .filter(r => r && r.start && r.end && r.type !== 'block' && r.source !== 'BLOCK');

      for (const r of reservations) {
        // ✅ Checklist V1 auto (lazy)
        const chk = ensureChecklistForReservation({
          reservationUid: r.uid,
          propertyId: property.id,
          userId: userId
        });

        // ✅ Deposit (Stripe) via DEPOSITS JSON
        const dep = DEPOSITS.find(d => d.reservationUid === r.uid) || null;

        const channel = mapChannelFromReservation(r);

        const input = {
          startDate: r.start,
          endDate: r.end,
          bookedAt: r.createdAt || null,
          channel,
          checklistStatus: mapChecklistStatusFromChecklist(chk),
          depositStatus: mapDepositStatusFromDeposit(dep),

          // Champs optionnels (chemin A : defaults)
          propertySensitive: false,
          capacity: 2,
          propertyType: 'entire',
          expectedCheckinHour: parseHour(property.arrivalTime || property.arrival_time),
          turnoverHoursBefore: turnoverByUid.has(r.uid) ? turnoverByUid.get(r.uid) : null,
          lastIcalSyncAt: reservationsStore.lastSync || null,
        };

        const risk = computeRiskV1(input, now);

        result.push({
          ...r,
          propertyId: property.id,
          propertyName: displayName(property),
          deposit: dep,
          checklist: chk,

          riskScore: risk.score,
          riskLevel: risk.level,
          riskLabel: risk.label,
          riskSummary: risk.summary,
          riskTags: risk.tags,
          riskSubScores: risk.subScores,
          riskParts: risk.parts
        });
      }
    }

    // Tri : risque desc puis date
    result.sort((a, b) => (b.riskScore - a.riskScore) || (new Date(a.start) - new Date(b.start)));

    // Persister checklists si de nouvelles ont été créées
    await saveChecklists();

    res.json({ reservations: result });
  } catch (err) {
    console.error('Erreur /api/reservations/enriched :', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// ============================================
// ✅ Checklists V1 - toggle task
// ============================================
app.post('/api/checklists/:reservationUid/tasks/:taskId/toggle', authenticateAny, checkSubscription, async (req, res) => {
  const user = await getUserFromRequest(req);
  if (!user) return res.status(401).json({ error: 'Non autorisé' });

  const { reservationUid, taskId } = req.params;
  const chk = CHECKLISTS[reservationUid];
  if (!chk) return res.status(404).json({ error: 'Checklist introuvable' });
  if (chk.userId !== user.id) return res.status(403).json({ error: 'Accès refusé' });

  const task = chk.tasks.find(t => t.id === taskId);
  if (!task) return res.status(404).json({ error: 'Tâche introuvable' });

  task.completed = !task.completed;
  chk.updatedAt = new Date().toISOString();

  const allDone = chk.tasks.every(t => t.completed);
  chk.status = allDone ? 'completed' : (chk.tasks.some(t => t.completed) ? 'in_progress' : 'pending');

  await saveChecklists();
  res.json({ checklist: chk });
});

// ✅ Checklists V1 - complete all
app.post('/api/checklists/:reservationUid/complete', authenticateAny, checkSubscription, async (req, res) => {
  const user = await getUserFromRequest(req);
  if (!user) return res.status(401).json({ error: 'Non autorisé' });

  const { reservationUid } = req.params;
  const chk = CHECKLISTS[reservationUid];
  if (!chk) return res.status(404).json({ error: 'Checklist introuvable' });
  if (chk.userId !== user.id) return res.status(403).json({ error: 'Accès refusé' });

  chk.tasks = chk.tasks.map(t => ({ ...t, completed: true }));
  chk.status = 'completed';
  chk.updatedAt = new Date().toISOString();

  await saveChecklists();
  
  // ✅ Envoyer notification push au propriétaire
  if (await shouldSendNotification(user.id, 'notif_checklist_done')) {
  try {
    const tokensResult = await pool.query(
      'SELECT fcm_token FROM user_fcm_tokens WHERE user_id = $1',
      [user.id]
    );
    
    if (tokensResult.rows.length > 0) {
      const propertyName = chk.propertyName || chk.title || 'Logement';
      const notifData = {
        type: 'cleaning_completed',
        reservation_uid: reservationUid,
        property_name: propertyName
      };
      for (const tok of tokensResult.rows) {
        await sendNotificationLogged(
          tok.fcm_token,
          '✅ Ménage terminé',
          `${propertyName} - Checklist complétée`,
          notifData
        );
      }
      console.log(`✅ Notification ménage complété envoyée pour ${propertyName} (${tokensResult.rows.length} appareil(s))`);
    }
  } catch (notifError) {
    console.error('❌ Erreur notification ménage complété:', notifError.message);
  }
  } // end shouldSendNotification
  
  res.json({ checklist: chk });
});


