// ============================================
// Fonction helper : Envoyer l'email de vérification
// ============================================
async function sendVerificationEmail(email, firstName, token) {
  const appUrl = process.env.APP_URL || 'https://boostinghost.fr';
  const verificationUrl = `${appUrl}/verify-email.html?token=${token}`;

  const mailOptions = {
    from: EMAIL_FROM,
    to: email,
    subject: 'Vérifiez votre adresse email — Boostinghost',
    html: bhEmailTemplate({
      icon: '✉️',
      title: 'Confirmez votre email',
      subtitle: 'Une dernière étape avant de démarrer',
      footerNote: 'Si vous n\'avez pas créé de compte, ignorez cet email.',
      bodyHtml: `
        <p>Bonjour <strong>${firstName || 'nouveau membre'}</strong>,</p>
        <p>Merci de vous être inscrit sur Boostinghost. Pour activer votre compte, cliquez sur le bouton ci-dessous :</p>
        <div class="cta-block">
          <p>Lien valide pendant <strong>24 heures</strong></p>
          <a href="${verificationUrl}" class="btn">Vérifier mon adresse email →</a>
        </div>
        <div class="info-card">
          Une fois vérifié, vous accéderez à : calendrier unifié, messages automatiques IA, gestion du ménage, cautions Stripe, livrets d'accueil et bien plus.
        </div>
        <p class="link-fallback">Le bouton ne fonctionne pas ? Copiez ce lien :<br><a href="${verificationUrl}">${verificationUrl}</a></p>
      `
    })
  };

  try {
    await transporter.sendMail(mailOptions);
    console.log('Email de vérification envoyé à:', email);
    return true;
  } catch (error) {
    console.error('Erreur envoi email vérification:', error);
    return false;
  }
}
// ============================================
// SERVICE D'EMAILS AUTOMATIQUES - MIS À JOUR
// ============================================

// ============================================
// FONCTION : Vérifier si un email a déjà été envoyé
// ============================================
async function hasEmailBeenSent(userId, emailType) {
  const result = await pool.query(
    `SELECT id FROM email_logs 
     WHERE user_id = $1 AND email_type = $2`,
    [userId, emailType]
  );
  return result.rows.length > 0;
}

// ============================================
// FONCTION : Enregistrer l'envoi d'un email
// ============================================
async function logEmailSent(userId, emailType, emailData = {}) {
  try {
    await pool.query(
      `INSERT INTO email_logs (user_id, email_type, recipient_email, status, sent_at, metadata)
       VALUES ($1, $2, $3, 'sent', NOW(), $4)`,
      [userId, emailType, emailData.email || '', JSON.stringify(emailData)]
    );
  } catch (error) {
    console.error('❌ Erreur logEmailSent:', error.message);
    // Ne pas bloquer si le log échoue
  }
}

