// GET - Liste des tâches pour une personne de ménage (accès via PIN)
app.get('/api/cleaning/tasks/:pinCode', async (req, res) => {
  try {
    const { pinCode } = req.params;
    
    // Vérifier le PIN et récupérer le cleaner
    const cleanerResult = await pool.query(
      'SELECT id, user_id, name FROM cleaners WHERE pin_code = $1 AND is_active = TRUE',
      [pinCode]
    );
    
    if (cleanerResult.rows.length === 0) {
      return res.status(404).json({ error: 'Code PIN invalide' });
    }
    
    const cleaner = cleanerResult.rows[0];
    
    // Récupérer les assignations PAR RÉSERVATION de ce cleaner
    const assignmentsResult = await pool.query(
      'SELECT reservation_key, property_id FROM cleaning_assignments WHERE cleaner_id = $1',
      [cleaner.id]
    );
    
    // Récupérer aussi les logements où ce cleaner est le cleaner par défaut
    const defaultPropertiesResult = await pool.query(
      'SELECT property_id FROM property_default_cleaners WHERE cleaner_id = $1 AND user_id = $2',
      [cleaner.id, cleaner.user_id]
    );

    const now = new Date();
    const endOfNextMonth = new Date(now.getFullYear(), now.getMonth() + 2, 0).toISOString().slice(0, 10);
    const todayStr = now.toISOString().slice(0, 10);

    // Construire une map des assignations explicites (property_id+dates → true) pour éviter les doublons
    const explicitKeys = new Set(assignmentsResult.rows.map(a => a.reservation_key).filter(Boolean));

    // Pour dédupliquer même quand les reservation_key ont des formats différents (CHX_ vs propId_start_end)
    // On récupère les vraies dates depuis la DB pour chaque assignation explicite
    const explicitPropDates = new Set();
    for (const a of assignmentsResult.rows) {
      if (!a.reservation_key || !a.property_id) continue;
      // Format propId_YYYY-MM-DD_YYYY-MM-DD → extraire directement
      const parts = a.reservation_key.split('_');
      if (parts.length >= 3) {
        const start = parts[parts.length - 2];
        const end   = parts[parts.length - 1];
        if (start?.match(/^\d{4}-\d{2}-\d{2}$/) && end?.match(/^\d{4}-\d{2}-\d{2}$/)) {
          explicitPropDates.add(`${a.property_id}_${start}_${end}`);
          continue;
        }
      }
      // Format CHX_ → chercher les dates réelles en DB
      try {
        const r = await pool.query(
          `SELECT TO_CHAR(start_date,'YYYY-MM-DD') as s, TO_CHAR(end_date,'YYYY-MM-DD') as e
           FROM reservations WHERE reservation_key = $1 LIMIT 1`,
          [a.reservation_key]
        );
        if (r.rows.length) {
          explicitPropDates.add(`${a.property_id}_${r.rows[0].s}_${r.rows[0].e}`);
        }
      } catch(e) { /* ignore */ }
    }

    // Ajouter les résas futures des logements par défaut (sans assignation explicite)
    const defaultAssignments = [];
    for (const row of defaultPropertiesResult.rows) {
      const propId = row.property_id;
      try {
        const resaRows = await pool.query(
          `SELECT TO_CHAR(start_date, 'YYYY-MM-DD') as start,
                  TO_CHAR(end_date, 'YYYY-MM-DD') as end
           FROM reservations
           WHERE property_id = $1
           AND status != 'cancelled'
           AND DATE(end_date) >= $2
           AND DATE(end_date) <= $3`,
          [propId, todayStr, endOfNextMonth]
        );
        console.log(`📅 [TASKS] Réservations DB pour ${propId}: ${resaRows.rows.length} (entre ${todayStr} et ${endOfNextMonth})`);
        for (const r of resaRows.rows) {
          const rStart = r.start;
          const rEnd   = r.end;
          const rKey = propId + '_' + rStart + '_' + rEnd;
          if (explicitKeys.has(rKey)) continue;
          if (explicitPropDates.has(rKey)) continue; // dédup cross-format
          defaultAssignments.push({ reservation_key: rKey, property_id: propId, isDefault: true });
        }
      } catch(e) {
        // fallback cache mémoire
        const propReservations = reservationsStore.properties[propId] || [];
        // Dédupliquer par dates — garder la résa la plus récente
        const seenDates = new Map();
        for (const r of propReservations) {
          const rEnd   = String(r.end   || r.end_date   || '').slice(0, 10);
          const rStart = String(r.start || r.start_date || '').slice(0, 10);
          if (!rEnd || !rStart) continue;
          if (rEnd < todayStr || rEnd > endOfNextMonth) continue;
          const dk = `${rStart}_${rEnd}`;
          const rTs = String(r.updatedAt || r.updated_at || r.createdAt || r.created_at || '');
          const existing = seenDates.get(dk);
          if (!existing || rTs > existing.ts) seenDates.set(dk, { r, ts: rTs });
        }
        for (const { r } of seenDates.values()) {
          const rEnd   = String(r.end   || r.end_date   || '').slice(0, 10);
          const rStart = String(r.start || r.start_date || '').slice(0, 10);
          const rKey = propId + '_' + rStart + '_' + rEnd;
          if (explicitKeys.has(rKey)) continue;
          if (explicitPropDates.has(rKey)) continue;
          defaultAssignments.push({ reservation_key: rKey, property_id: propId, isDefault: true });
        }
      }
    }

    const allAssignments = [...assignmentsResult.rows, ...defaultAssignments];

    // ── Ajouter les checklists rejetées qui auraient été filtrées par date ──
    // (la résa est passée mais le complément n'a pas encore été corrigé)
    try {
      const rejectedRows = await pool.query(
        `SELECT reservation_key, property_id
         FROM cleaning_checklists
         WHERE cleaner_id = $1 AND owner_status = 'rejected'`,
        [cleaner.id]
      );
      for (const row of rejectedRows.rows) {
        const alreadyIn = allAssignments.some(a => a.reservation_key === row.reservation_key);
        if (!alreadyIn && row.reservation_key && row.property_id) {
          allAssignments.push({ reservation_key: row.reservation_key, property_id: row.property_id, isRejected: true });
        }
      }
    } catch(e) {
      console.warn('[TASKS] Erreur chargement checklists rejetées:', e.message);
    }

    if (allAssignments.length === 0) {
      return res.json({ tasks: [], cleaner: { id: cleaner.id, name: cleaner.name } });
    }

    // Construire la liste des tâches
    const tasks = [];

    for (const assignment of allAssignments) {
      const { reservation_key, property_id } = assignment;
      console.log('🔍 Assignment:', { reservation_key, property_id });
  console.log('🔍 reservationsStore.properties[property_id]:', reservationsStore.properties[property_id]);
      
      // Vérifier si c'est une assignation par réservation (nouveau système)
if (reservation_key && reservation_key !== null) {
  const parts = reservation_key.split('_');
  if (parts.length < 3) continue;
  
  // Le dernier élément est endDate, l'avant-dernier est startDate
  // Tout ce qui est avant est le propertyId
  const endDate = parts[parts.length - 1];
  const startDate = parts[parts.length - 2];
  const keyPropertyId = parts.slice(0, parts.length - 2).join('_');
  
  console.log('🔍 Parsed:', { keyPropertyId, startDate, endDate });
  
  // Ne garder que les réservations du mois en cours et du mois suivant
  // Exception : si une checklist rejected existe pour cette clé, on la garde quand même
  const now = new Date();
  const endOfNextMonth = new Date(now.getFullYear(), now.getMonth() + 2, 0).toISOString().slice(0, 10);
  const hasRejectedChecklist = await pool.query(
    `SELECT 1 FROM cleaning_checklists WHERE reservation_key = $1 AND cleaner_id = $2 AND owner_status = 'rejected' LIMIT 1`,
    [reservation_key, cleaner.id]
  ).then(r => r.rows.length > 0).catch(() => false);

  if ((endDate < todayStr || endDate > endOfNextMonth) && !hasRejectedChecklist) {
    console.log(`🚫 [TASKS] Filtrée: ${reservation_key} endDate=${endDate} todayStr=${todayStr}`);
    continue;
  }

  // ✅ Lire depuis la DB avec TO_CHAR pour avoir des strings ISO
  let guestName = '';
  try {
    const resaRow = await pool.query(
      `SELECT guest_name FROM reservations
       WHERE property_id = $1
       AND TO_CHAR(start_date, 'YYYY-MM-DD') = $2
       AND TO_CHAR(end_date, 'YYYY-MM-DD') = $3
       AND status != 'cancelled'
       LIMIT 1`,
      [property_id, startDate, endDate]
    );
    guestName = resaRow.rows[0]?.guest_name || '';
  } catch(e) {
    const r = (reservationsStore.properties[property_id] || []).find(r => {
      const rStart = String(r.start || '').slice(0, 10);
      const rEnd   = String(r.end   || '').slice(0, 10);
      return `${property_id}_${rStart}_${rEnd}` === reservation_key;
    });
    guestName = r?.guestName || r?.name || '';
  }

  const property = PROPERTIES.find(p => p.id === property_id);
  const propertyName = displayName(property) || property_id;
  
  tasks.push({
    reservationKey: reservation_key,
    propertyId: property_id,
    propertyName,
    guestName,
    checkoutDate: endDate,
    completed: false
  });
}
      // Sinon, c'est une ancienne assignation par logement
      else if (property_id) {
        // Récupérer toutes les réservations de ce logement
        const propertyReservations = reservationsStore.properties[property_id] || [];
        propertyReservations.forEach(r => {
          if (!r.end) return;
          const endStr = String(r.end).slice(0, 10);
          if (endStr < todayStr) return;
          
          const rStart = String(r.start || '').slice(0, 10);
          const rEnd   = String(r.end   || '').slice(0, 10);
          const reservationKey = `${property_id}_${rStart}_${rEnd}`;
          const propertyName = (r.property && displayName(r.property)) || r.propertyInternalName || r.propertyName || property_id;
          const guestName = r.guestName || r.name || '';
          
          tasks.push({
            reservationKey,
            propertyId: property_id,
            propertyName,
            guestName,
            checkoutDate: endStr,
            completed: false
          });
        });
      }
    }
    
    // Vérifier quelles checklists existent déjà
    const existingChecklists = await pool.query(
      `SELECT reservation_key, completed_at, owner_status, owner_notes
       FROM cleaning_checklists 
       WHERE cleaner_id = $1`,
      [cleaner.id]
    );
    
    const completedKeys = new Set(existingChecklists.rows.map(c => c.reservation_key));
    const checklistByKey = {};
    existingChecklists.rows.forEach(c => { checklistByKey[c.reservation_key] = c; });
    
    // Marquer les tâches complétées + statut propriétaire
    tasks.forEach(task => {
      const cl = checklistByKey[task.reservationKey];
      task.completed = completedKeys.has(task.reservationKey);
      task.ownerStatus = cl?.owner_status || null;
      task.ownerNotes  = cl?.owner_notes  || null;
    });
    
    // Trier par date de départ
    tasks.sort((a, b) => a.checkoutDate.localeCompare(b.checkoutDate));
    
    res.json({
      cleaner: { id: cleaner.id, name: cleaner.name },
      tasks
    });
  } catch (err) {
    console.error('Erreur GET /api/cleaning/tasks/:pinCode :', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});
// POST - Soumettre une checklist complétée (avec timer + notification propriétaire)
// Route upload photo ménage (upload immédiat vers Cloudinary pour éviter crash mémoire iOS)
app.post('/api/cleaning/photo-upload', async (req, res) => {
  try {
    const { pinCode, dataUrl } = req.body;
    if (!pinCode || !dataUrl) {
      return res.status(400).json({ error: 'Données manquantes' });
    }
    // Vérifier le PIN
    const cleanerResult = await pool.query(
      'SELECT id FROM cleaners WHERE pin_code = $1 AND is_active = TRUE',
      [pinCode]
    );
    if (cleanerResult.rows.length === 0) {
      return res.status(401).json({ error: 'Code PIN invalide' });
    }
    // Convertir base64 en buffer
    const base64Data = dataUrl.replace(/^data:image\/\w+;base64,/, '');
    const buffer = Buffer.from(base64Data, 'base64');
    const filename = `cleaning_${Date.now()}_${Math.random().toString(36).slice(2)}`;
    // Upload vers Cloudinary dans le dossier cleaning
    const url = await new Promise((resolve, reject) => {
      const uploadStream = cloudinary.uploader.upload_stream(
        { folder: 'lcc-cleaning', public_id: filename, resource_type: 'image' },
        (error, result) => error ? reject(error) : resolve(result.secure_url)
      );
      require('stream').Readable.from(buffer).pipe(uploadStream);
    });
    res.json({ success: true, url });
  } catch (err) {
    console.error('❌ Erreur upload photo ménage:', err);
    res.status(500).json({ error: 'Erreur upload photo' });
  }
});


