// PUT /api/cleaning/checklists/:id/validate — Validation propriétaire
app.put('/api/cleaning/checklists/:id/validate',
  authenticateAny,
  requirePermission(pool, 'can_manage_cleaning'),
  loadSubAccountData(pool),
  async (req, res) => {
    try {
      const userId = req.user.isSubAccount
        ? (await getRealUserId(pool, req))
        : (await getUserFromRequest(req))?.id;

      if (!userId) {
        return res.status(401).json({ error: 'Non autorisé' });
      }

      const { id } = req.params;

      const result = await pool.query(
        `UPDATE cleaning_checklists 
         SET owner_status = 'validated', 
             owner_validated_at = NOW(), 
             is_validated = TRUE,
             updated_at = NOW()
         WHERE id = $1 AND user_id = $2
         RETURNING *`,
        [id, userId]
      );

      if (result.rows.length === 0) {
        return res.status(404).json({ error: 'Checklist non trouvée' });
      }

      if (typeof io !== 'undefined' && io) {
        io.to(`user_${userId}`).emit('cleaning:validated', {
          checklistId: id,
          propertyId: result.rows[0].property_id
        });
      }

      console.log(`✅ Checklist ${id} validée par propriétaire ${userId}`);

      // 🔔 NOTIFICATION AU CLEANER
      try {
        const cl = result.rows[0];
        const property = PROPERTIES.find(p => p.id === cl.property_id);
        const propertyName = displayName(property) || cl.property_id;
        const checkoutFmt = cl.checkout_date ? new Date(cl.checkout_date).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' }) : '';

        // Collecter tous les tokens déjà notifiés pour éviter les doublons
        const alreadyNotifiedTokens = new Set();

        // Token FCM du cleaner — via sub_account_id en priorité, sinon user_id
        const cleanerRow = await pool.query(`
          SELECT c.user_id, c.name,
            COALESCE(uft_sub.fcm_token, uft_user.fcm_token) as fcm_token
          FROM cleaners c
          LEFT JOIN user_fcm_tokens uft_sub ON uft_sub.sub_account_id = c.sub_account_id AND c.sub_account_id IS NOT NULL
          LEFT JOIN user_fcm_tokens uft_user ON uft_user.user_id = c.user_id AND c.user_id IS NOT NULL AND c.sub_account_id IS NULL
          WHERE c.id = $1 LIMIT 1`, [cl.cleaner_id]);
        if (cleanerRow.rows.length > 0 && cleanerRow.rows[0].fcm_token) {
          alreadyNotifiedTokens.add(cleanerRow.rows[0].fcm_token);
          await sendNotificationLogged(
            cleanerRow.rows[0].fcm_token,
            '✅ Ménage validé — ' + propertyName,
            'Super travail ! Le ménage du ' + checkoutFmt + ' a été validé.',
            { type: 'cleaning_validated', checklistId: String(id), propertyId: cl.property_id }
          );
          console.log(`📱 Notif validation envoyée au cleaner ${cl.cleaner_id}`);
        }

        // Si cleaner est un sous-compte → notif sur son token de sous-compte
        const cleanerSubRow = await pool.query('SELECT uft.fcm_token FROM cleaners c JOIN sub_accounts sa ON sa.id = c.sub_account_id JOIN user_fcm_tokens uft ON uft.sub_account_id = sa.id WHERE c.id = $1 AND uft.fcm_token IS NOT NULL', [cl.cleaner_id]);
        for (const row of cleanerSubRow.rows) {
          if (!alreadyNotifiedTokens.has(row.fcm_token)) {
            alreadyNotifiedTokens.add(row.fcm_token);
            await sendNotificationLogged(
              row.fcm_token,
              '✅ Ménage validé — ' + propertyName,
              'Super travail ! Le ménage du ' + checkoutFmt + ' a été validé.',
              { type: 'cleaning_validated', checklistId: String(id), propertyId: cl.property_id }
            );
          }
        }
        if (cleanerSubRow.rows.length > 0) console.log(`📱 Notif validation envoyée au sous-compte cleaner`);

        // 🔔 Notif sous-comptes manager (can_view_cleaning) — checklist validée (en excluant tokens déjà notifiés)
        await sendNotificationToSubAccountsOf(
          userId, 'can_view_cleaning',
          '✅ Ménage validé — ' + propertyName,
          'Le ménage du ' + checkoutFmt + ' a été validé.',
          { type: 'cleaning_validated', checklistId: String(id), propertyId: cl.property_id },
          'notif_sub_cleaning_completed',
          null,
          alreadyNotifiedTokens
        );
        console.log(`📨 Notif validation envoyée aux sous-comptes managers`);
      } catch(notifErr) {
        console.error('❌ Erreur notif validation cleaner:', notifErr.message, notifErr.stack?.split('\n')[1]);
      }

      res.json({ success: true, checklist: result.rows[0] });

    } catch (err) {
      console.error('Erreur PUT /api/cleaning/checklists/:id/validate :', err);
      res.status(500).json({ error: 'Erreur serveur' });
    }
  }
);

// PUT /api/cleaning/checklists/:id/reject — Demande de complément
app.put('/api/cleaning/checklists/:id/reject',
  authenticateAny,
  requirePermission(pool, 'can_manage_cleaning'),
  loadSubAccountData(pool),
  async (req, res) => {
    try {
      const userId = req.user.isSubAccount
        ? (await getRealUserId(pool, req))
        : (await getUserFromRequest(req))?.id;

      if (!userId) {
        return res.status(401).json({ error: 'Non autorisé' });
      }

      const { id } = req.params;
      const { notes } = req.body;

      const result = await pool.query(
        `UPDATE cleaning_checklists 
         SET owner_status = 'rejected', 
             owner_notes = $3,
             updated_at = NOW()
         WHERE id = $1 AND user_id = $2
         RETURNING *`,
        [id, userId, notes || 'Merci de compléter le ménage']
      );

      if (result.rows.length === 0) {
        return res.status(404).json({ error: 'Checklist non trouvée' });
      }

      const checklist = result.rows[0];
      console.log(`⚠️ Checklist ${id} rejetée — complément demandé pour ${checklist.property_id}`);

      // Notifier le cleaner
      try {
        const cleanerResult = await pool.query(
          `SELECT c.email, c.phone, c.name, c.sub_account_id, c.user_id,
            COALESCE(uft_sub.fcm_token, uft_user.fcm_token) as fcm_token
           FROM cleaners c
           LEFT JOIN user_fcm_tokens uft_sub ON uft_sub.sub_account_id = c.sub_account_id AND c.sub_account_id IS NOT NULL
           LEFT JOIN user_fcm_tokens uft_user ON uft_user.user_id = c.user_id AND c.user_id IS NOT NULL AND c.sub_account_id IS NULL
           WHERE c.id = $1 LIMIT 1`,
          [checklist.cleaner_id]
        );
        if (cleanerResult.rows.length > 0) {
          const cleaner = cleanerResult.rows[0];
          const property = PROPERTIES.find(p => p.id === checklist.property_id);
          const propertyName = displayName(property) || checklist.property_id;
          const checkoutFmt = checklist.checkout_date ? new Date(checklist.checkout_date).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' }) : '';

          // 🔔 Push FCM
          const alreadyNotifiedTokens = new Set();
          if (cleaner.fcm_token) {
            alreadyNotifiedTokens.add(cleaner.fcm_token);
            await sendNotificationLogged(
              cleaner.fcm_token,
              `⚠️ Complément demandé — ${propertyName}`,
              notes ? notes : `Le propriétaire demande un complément pour le ménage du ${checkoutFmt}.`,
              { type: 'cleaning_complement', checklistId: String(id), propertyId: checklist.property_id }
            );
            console.log(`📱 Push complément envoyé au cleaner ${checklist.cleaner_id}`);
          }

          // Push sur sous-compte cleaner si applicable
          if (cleaner.sub_account_id) {
            const subTokens = await pool.query(
              'SELECT uft.fcm_token FROM user_fcm_tokens uft WHERE uft.sub_account_id = $1 AND uft.fcm_token IS NOT NULL',
              [cleaner.sub_account_id]
            );
            for (const row of subTokens.rows) {
              if (!alreadyNotifiedTokens.has(row.fcm_token)) {
                alreadyNotifiedTokens.add(row.fcm_token);
                await sendNotificationLogged(
                  row.fcm_token,
                  `⚠️ Complément demandé — ${propertyName}`,
                  notes ? notes : `Le propriétaire demande un complément pour le ménage du ${checkoutFmt}.`,
                  { type: 'cleaning_complement', checklistId: String(id), propertyId: checklist.property_id }
                );
              }
            }
          }

          // 📧 Email
          if (cleaner.email) {
            const subject = `⚠️ Complément demandé — ${propertyName}`;
            const htmlBody = bhEmailTemplate({
              icon: '⚠️',
              title: 'Complément de ménage demandé',
              tag: propertyName,
              accentColor: '#D97706',
              bodyHtml: `
                <p>Bonjour <strong>${cleaner.name}</strong>,</p>
                <p>Le propriétaire demande un complément pour le ménage de <strong>${propertyName}</strong>.</p>
                ${notes ? `<div class="alert-card"><strong>Message :</strong> ${notes}</div>` : ''}
                <p>Merci de repasser dès que possible.</p>
              `
            });

            const useBrevo = !!process.env.BREVO_API_KEY;
            if (useBrevo) {
              await sendEmailViaBrevo({ to: cleaner.email, subject, text: '', html: htmlBody });
            } else {
              const transporter = getEmailTransporter();
              if (transporter) {
                await transporter.sendMail({
                  from: process.env.EMAIL_FROM || 'Boostinghost <no-reply@boostinghost.fr>',
                  to: cleaner.email,
                  subject,
                  html: htmlBody
                });
              }
            }
            console.log(`📧 Notification de rejet envoyée à ${cleaner.email}`);
          }
        }
      } catch (notifErr) {
        console.error('Erreur notification rejet:', notifErr);
      }

      res.json({ success: true, checklist: result.rows[0] });

    } catch (err) {
      console.error('Erreur PUT /api/cleaning/checklists/:id/reject :', err);
      res.status(500).json({ error: 'Erreur serveur' });
    }
  }
);

// GET /api/cleaning/stats — Statistiques ménage
app.get('/api/cleaning/stats',
  authenticateAny,
  requirePermission(pool, 'can_view_cleaning'),
  loadSubAccountData(pool),
  async (req, res) => {
    try {
      const userId = req.user.isSubAccount
        ? (await getRealUserId(pool, req))
        : (await getUserFromRequest(req))?.id;

      if (!userId) {
        return res.status(401).json({ error: 'Non autorisé' });
      }

      const { period, month } = req.query;

      let dateFilter = '';
      if (month) {
        // Filtre par mois exact (format YYYY-MM)
        dateFilter = `AND TO_CHAR(cc.completed_at AT TIME ZONE 'Europe/Paris', 'YYYY-MM') = '${month.replace(/[^0-9-]/g, '')}'`;
      } else if (period === 'week') {
        dateFilter = `AND cc.completed_at >= NOW() - INTERVAL '7 days'`;
      } else if (period === 'month') {
        dateFilter = `AND cc.completed_at >= NOW() - INTERVAL '30 days'`;
      } else {
        dateFilter = `AND cc.completed_at >= NOW() - INTERVAL '365 days'`;
      }

      const globalStats = await pool.query(`
        SELECT 
          COUNT(*) as total_checklists,
          COUNT(CASE WHEN owner_status = 'validated' THEN 1 END) as validated,
          COUNT(CASE WHEN owner_status = 'pending' THEN 1 END) as pending,
          COUNT(CASE WHEN owner_status = 'rejected' THEN 1 END) as rejected
        FROM cleaning_checklists cc
        WHERE cc.user_id = $1 ${dateFilter}
      `, [userId]);

      const cleanerStats = await pool.query(`
        SELECT 
          c.id as cleaner_id,
          c.name as cleaner_name,
          COUNT(cc.id) as total,
          MAX(cc.completed_at) as last_completed_at,
          COUNT(CASE WHEN cc.owner_status = 'validated' THEN 1 END) as validated,
          COUNT(CASE WHEN cc.owner_status = 'rejected' THEN 1 END) as rejected
        FROM cleaning_checklists cc
        LEFT JOIN cleaners c ON c.id = cc.cleaner_id
        WHERE cc.user_id = $1 ${dateFilter}
        GROUP BY c.id, c.name
        ORDER BY total DESC
      `, [userId]);

      const propertyStats = await pool.query(`
        SELECT 
          cc.property_id,
          COUNT(cc.id) as total,
          MAX(cc.completed_at) as last_completed_at
        FROM cleaning_checklists cc
        WHERE cc.user_id = $1 ${dateFilter}
        GROUP BY cc.property_id
        ORDER BY total DESC
      `, [userId]);

      const enrichedPropertyStats = propertyStats.rows.map(row => {
        const property = PROPERTIES.find(p => p.id === row.property_id);
        return {
          ...row,
          property_name: property?.name || property?.title || row.property_id,
        };
      });

      const global = globalStats.rows[0] || {};

      res.json({
        success: true,
        stats: {
          total: parseInt(global.total_checklists) || 0,
          validated: parseInt(global.validated) || 0,
          pending: parseInt(global.pending) || 0,
          rejected: parseInt(global.rejected) || 0,
          validationRate: global.total_checklists > 0
            ? Math.round((global.validated / global.total_checklists) * 100) : 0,
          byCleaner: cleanerStats.rows,
          byProperty: enrichedPropertyStats
        }
      });

    } catch (err) {
      console.error('Erreur GET /api/cleaning/stats :', err);
      res.status(500).json({ error: 'Erreur serveur' });
    }
  }
);

