app.get('/api/reporting', authenticateAny, requirePermission(pool, 'can_view_reporting'), async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) return res.status(401).json({ error: 'Non autorisé' });

    const { year, property_id, month } = req.query;
    const selectedYear = parseInt(year) || new Date().getFullYear();
    const selectedMonth = month ? parseInt(month) : null;

    // Récupérer les propriétés de l'utilisateur avec leurs configs financières
    const propsResult = await pool.query(`
      SELECT id, name, color,
             base_price, weekend_price,
             cleaning_fee, tourist_tax_per_night, concierge_pct,
             COALESCE(airbnb_commission_pct, 3) as airbnb_commission_pct,
             COALESCE(booking_commission_pct, 15) as booking_commission_pct
      FROM properties WHERE user_id = $1
      ${property_id ? 'AND id = $2' : ''}
      ORDER BY display_order ASC, created_at ASC
    `, property_id ? [user.id, property_id] : [user.id]);
    const properties = propsResult.rows;

    if (properties.length === 0) {
      return res.json({ year: selectedYear, properties: [], summary: {} });
    }

    const propIds = properties.map(p => p.id);

    // Récupérer toutes les réservations confirmées de l'année
    const resaResult = await pool.query(`
      SELECT
        r.uid, r.property_id, r.start_date, r.end_date,
        r.price, r.platform, r.ota_name, r.status,
        r.guest_name, r.nb_guests,
        r.amount_total, r.ota_commission, r.host_payout,
        r.amount_rooms, r.amount_cleaning, r.amount_taxes,
        EXTRACT(YEAR FROM r.start_date) as year,
        EXTRACT(MONTH FROM r.start_date) as month,
        (r.end_date::date - r.start_date::date) as nights
      FROM reservations r
      WHERE r.user_id = $1
        AND r.status = 'confirmed'
        AND r.property_id = ANY($3)
        AND (
          EXTRACT(YEAR FROM r.start_date) = $2
          OR EXTRACT(YEAR FROM r.end_date) = $2
          OR (EXTRACT(YEAR FROM r.start_date) = $2 - 1 AND (r.ota_name ILIKE '%booking%' OR r.platform ILIKE '%booking%'))
        )
      ORDER BY r.start_date ASC
    `, [user.id, selectedYear, propIds]);
    const reservations = resaResult.rows;

    // Récupérer les overrides de prix (pour les réservations manuelles sans prix)
    const overridesResult = await pool.query(`
      SELECT property_id, TO_CHAR(date, 'YYYY-MM-DD') as date, price
      FROM pricing_overrides
      WHERE user_id = $1
        AND EXTRACT(YEAR FROM date) = $2
    `, [user.id, selectedYear]);
    const overridesMap = {};
    overridesResult.rows.forEach(o => {
      overridesMap[`${o.property_id}_${o.date}`] = parseFloat(o.price);
    });

    // Construire un index des properties pour lookup rapide
    const propMap = {};
    properties.forEach(p => { propMap[p.id] = p; });

    // ── Calculer les métriques par réservation ──────────────────
    const enrichedResas = reservations.map(r => {
      const prop = propMap[r.property_id] || {};
      const nights = parseInt(r.nights) || 1;
      const nbGuests = parseInt(r.nb_guests) || 1;

      // ── Date de paiement effective selon la plateforme ──────────
      const platformRawStr = (r.ota_name || r.platform || '').toLowerCase();
      const isAirbnbResa  = platformRawStr.includes('abb') || platformRawStr.includes('airbnb');
      const isBookingResa = platformRawStr.includes('bdc') || platformRawStr.includes('booking');

      const startDt = new Date(r.start_date);
      const endDt   = r.end_date ? new Date(r.end_date) : startDt;

      let paymentDate;
      if (isAirbnbResa) {
        paymentDate = new Date(startDt);
        paymentDate.setDate(paymentDate.getDate() + 1);
      } else if (isBookingResa) {
        paymentDate = new Date(endDt);
        paymentDate.setDate(paymentDate.getDate() + 1);
      } else {
        paymentDate = new Date(startDt);
      }
      const paymentMonth = paymentDate.getMonth() + 1;
      const paymentYear  = paymentDate.getFullYear();

      // Prix brut — ordre de priorité : amount_total > r.price > overrides > calcul
      let rawPrice = parseFloat(r.amount_total || r.amount_rooms || r.price) || 0;
      if (!rawPrice) {
        // Calculer depuis les overrides ou le prix de base
        let total = 0;
        const start = new Date(r.start_date);
        for (let i = 0; i < nights; i++) {
          const d = new Date(start);
          d.setDate(start.getDate() + i);
          const dateStr = d.toISOString().split('T')[0];
          const key = `${r.property_id}_${dateStr}`;
          const dow = d.getDay();
          const isPremium = (dow === 5 || dow === 6);
          const nightPrice = overridesMap[key] != null
            ? overridesMap[key]
            : (isPremium && prop.weekend_price ? parseFloat(prop.weekend_price) : (prop.base_price ? parseFloat(prop.base_price) : 0));
          total += nightPrice;
        }
        rawPrice = total;
      }

      // Frais de ménage
      const cleaningFee = prop.cleaning_fee != null ? parseFloat(prop.cleaning_fee) : 0;

      // Taxe de séjour (par nuit × nb nuits × nb voyageurs)
      const touristTaxTotal = prop.tourist_tax_per_night != null
        ? parseFloat(prop.tourist_tax_per_night) * nights * Math.max(nbGuests, 1)
        : 0;

      // Revenu brut hors taxes = prix + ménage
      const grossRevenue = rawPrice + cleaningFee;

      // Revenu net (hors taxe de séjour)
      const netRevenue = rawPrice; // sans ménage ni taxe

      // Commission conciergerie
      const conciergePct = prop.concierge_pct != null ? parseFloat(prop.concierge_pct) : 0;
      const conciergeAmount = Math.round(rawPrice * conciergePct / 100 * 100) / 100;

      // Revenu propriétaire = prix - commission conciergerie
      const ownerRevenue = Math.round((rawPrice - conciergeAmount) * 100) / 100;

      // Commission OTA — priorité : valeur réelle Channex > pourcentage configuré
      const airbnbCommPct  = prop.airbnb_commission_pct  != null ? parseFloat(prop.airbnb_commission_pct)  : 3;
      const bookingCommPct = prop.booking_commission_pct != null ? parseFloat(prop.booking_commission_pct) : 15;
      let otaCommissionAmount = 0;
      let otaCommissionPct    = 0;
      if (r.ota_commission && parseFloat(r.ota_commission) > 0) {
        otaCommissionAmount = parseFloat(r.ota_commission);
        otaCommissionPct    = rawPrice > 0 ? Math.round(otaCommissionAmount / rawPrice * 100 * 10) / 10 : 0;
      } else {
        if (isAirbnbResa)        otaCommissionPct = airbnbCommPct;
        else if (isBookingResa)  otaCommissionPct = bookingCommPct;
        otaCommissionAmount = Math.round(rawPrice * otaCommissionPct / 100 * 100) / 100;
      }
      const realHostPayout = r.host_payout ? parseFloat(r.host_payout) : null;

      // Marge nette = prix brut - commission OTA - frais ménage - commission conciergerie
      const netMargin = Math.round((rawPrice - otaCommissionAmount - cleaningFee - conciergeAmount) * 100) / 100;
      const netMarginPct = rawPrice > 0 ? Math.round(netMargin / rawPrice * 100 * 10) / 10 : 0;

      // Plateforme normalisée
      const platform = (() => {
        const raw = (r.ota_name || r.platform || '').toLowerCase();
        if (raw.includes('abb') || raw.includes('airbnb')) return 'Airbnb';
        if (raw.includes('bdc') || raw.includes('booking')) return 'Booking.com';
        if (raw.includes('exp') || raw.includes('expedia')) return 'Expedia';
        if (raw.includes('vrbo') || raw.includes('homeaway')) return 'Vrbo';
        if (raw === 'direct' || raw === '' || raw === 'manuel' || raw === 'manual') return 'Direct';
        return raw.charAt(0).toUpperCase() + raw.slice(1);
      })();

      return {
        uid: r.uid,
        propertyId: r.property_id,
        propertyName: prop.name || 'Logement',
        propertyColor: prop.color || '#10B981',
        guestName: r.guest_name || '—',
        startDate: r.start_date,
        endDate: r.end_date,
        month: parseInt(r.month),
        paymentMonth,
        paymentYear,
        paymentDate: paymentDate.toISOString().split('T')[0],
        nights,
        nbGuests,
        platform,
        rawPrice: Math.round(rawPrice * 100) / 100,
        cleaningFee: Math.round(cleaningFee * 100) / 100,
        touristTax: Math.round(touristTaxTotal * 100) / 100,
        grossRevenue: Math.round(grossRevenue * 100) / 100,
        netRevenue: Math.round(netRevenue * 100) / 100,
        conciergeAmount: Math.round(conciergeAmount * 100) / 100,
        ownerRevenue: Math.round(ownerRevenue * 100) / 100,
        hostPayout: realHostPayout != null ? Math.round(realHostPayout * 100) / 100 : null,
        conciergePct,
        otaCommissionPct,
        otaCommissionAmount: Math.round(otaCommissionAmount * 100) / 100,
        netMargin: Math.round(netMargin * 100) / 100,
        netMarginPct
      };
    });

    // Filtrer par mois de paiement si un mois est sélectionné
    const filteredResas = selectedMonth
      ? enrichedResas.filter(r => r.paymentYear === selectedYear && r.paymentMonth === selectedMonth)
      : enrichedResas;

    // ── Agrégats par mois ───────────────────────────────────────
    const monthlyData = Array.from({ length: 12 }, (_, i) => ({
      month: i + 1,
      label: new Date(selectedYear, i, 1).toLocaleDateString('fr-FR', { month: 'short' }),
      bookings: 0, nights: 0,
      grossRevenue: 0, netRevenue: 0,
      touristTax: 0, cleaningFee: 0,
      conciergeAmount: 0, ownerRevenue: 0,
      otaCommissionAmount: 0, netMargin: 0
    }));

    filteredResas.forEach(r => {
      // Exclure les blocs (pas des réservations réelles)
      if ((r.platform || '').toLowerCase().includes('block') ||
          (r.platform || '').toLowerCase() === 'bloc') return;
      // Grouper par mois de PAIEMENT effectif
      const payMonthIdx = r.paymentYear === selectedYear ? r.paymentMonth - 1 : -1;
      const m = payMonthIdx >= 0 ? monthlyData[payMonthIdx] : null;
      if (!m) return;
      m.bookings++;
      m.nights += r.nights;
      m.grossRevenue        += r.grossRevenue;
      m.netRevenue          += r.netRevenue;
      m.touristTax          += r.touristTax;
      m.cleaningFee         += r.cleaningFee;
      m.conciergeAmount     += r.conciergeAmount;
      m.ownerRevenue        += r.ownerRevenue;
      m.otaCommissionAmount += r.otaCommissionAmount;
      m.netMargin           += r.netMargin;
      if (r.hostPayout != null) m.hostPayout = (m.hostPayout || 0) + r.hostPayout;
      // Détail par plateforme
      if (!m.byPlatform) m.byPlatform = {};
      if (!m.byPlatform[r.platform]) m.byPlatform[r.platform] = {
        platform: r.platform, bookings: 0, grossRevenue: 0,
        otaCommissionAmount: 0, hostPayout: 0, netMargin: 0, paymentDates: []
      };
      const mp = m.byPlatform[r.platform];
      mp.bookings++;
      mp.grossRevenue        += r.grossRevenue;
      mp.otaCommissionAmount += r.otaCommissionAmount;
      mp.hostPayout          += r.hostPayout != null ? r.hostPayout : (r.grossRevenue - r.otaCommissionAmount);
      mp.netMargin           += r.netMargin;
      if (!mp.paymentDates.includes(r.paymentDate)) mp.paymentDates.push(r.paymentDate);
    });
    monthlyData.forEach(m => {
      m.grossRevenue        = Math.round(m.grossRevenue * 100) / 100;
      m.netRevenue          = Math.round(m.netRevenue * 100) / 100;
      m.touristTax          = Math.round(m.touristTax * 100) / 100;
      m.cleaningFee         = Math.round(m.cleaningFee * 100) / 100;
      m.conciergeAmount     = Math.round(m.conciergeAmount * 100) / 100;
      m.ownerRevenue        = Math.round(m.ownerRevenue * 100) / 100;
      m.otaCommissionAmount = Math.round(m.otaCommissionAmount * 100) / 100;
      m.netMargin           = Math.round(m.netMargin * 100) / 100;
      m.netMarginPct        = m.grossRevenue > 0 ? Math.round(m.netMargin / m.grossRevenue * 100 * 10) / 10 : 0;
    });

    // ── Agrégats par logement ───────────────────────────────────
    const byProperty = {};
    properties.forEach(p => {
      byProperty[p.id] = {
        id: p.id, name: p.name, color: p.color,
        bookings: 0, nights: 0, occupancyRate: 0,
        grossRevenue: 0, netRevenue: 0,
        touristTax: 0, cleaningFee: 0,
        conciergeAmount: 0, ownerRevenue: 0,
        otaCommissionAmount: 0, netMargin: 0,
        conciergePct: p.concierge_pct || 0,
        airbnbCommissionPct: parseFloat(p.airbnb_commission_pct) || 3,
        bookingCommissionPct: parseFloat(p.booking_commission_pct) || 15,
        platforms: {}
      };
    });

    filteredResas.forEach(r => {
      const p = byProperty[r.propertyId];
      if (!p) return;
      if (r.paymentYear !== selectedYear) return; // Exclure si paiement hors année sélectionnée
      p.bookings++;
      p.nights += r.nights;
      p.grossRevenue    += r.grossRevenue;
      p.netRevenue      += r.netRevenue;
      p.touristTax      += r.touristTax;
      p.cleaningFee     += r.cleaningFee;
      p.conciergeAmount     += r.conciergeAmount;
      p.ownerRevenue        += r.ownerRevenue;
      p.otaCommissionAmount += r.otaCommissionAmount;
      p.netMargin           += r.netMargin;
      p.platforms[r.platform] = (p.platforms[r.platform] || 0) + 1;
    });

    // Taux d'occupation (jours réservés / jours dans l'année)
    const daysInYear = 365;
    Object.values(byProperty).forEach(p => {
      p.occupancyRate   = Math.round(p.nights / daysInYear * 100);
      p.grossRevenue    = Math.round(p.grossRevenue * 100) / 100;
      p.netRevenue      = Math.round(p.netRevenue * 100) / 100;
      p.touristTax      = Math.round(p.touristTax * 100) / 100;
      p.cleaningFee     = Math.round(p.cleaningFee * 100) / 100;
      p.conciergeAmount     = Math.round(p.conciergeAmount * 100) / 100;
      p.ownerRevenue        = Math.round(p.ownerRevenue * 100) / 100;
      p.otaCommissionAmount = Math.round(p.otaCommissionAmount * 100) / 100;
      p.netMargin           = Math.round(p.netMargin * 100) / 100;
      p.netMarginPct        = p.grossRevenue > 0 ? Math.round(p.netMargin / p.grossRevenue * 100 * 10) / 10 : 0;
    });

    // ── Répartition par plateforme (global) ────────────────────
    const platformStats = {};
    filteredResas.forEach(r => {
      if (!platformStats[r.platform]) {
        platformStats[r.platform] = { bookings: 0, nights: 0, revenue: 0 };
      }
      platformStats[r.platform].bookings++;
      platformStats[r.platform].nights    += r.nights;
      platformStats[r.platform].revenue   += r.grossRevenue;
    });
    const totalBookings = filteredResas.length;
    const platformArray = Object.entries(platformStats).map(([name, stats]) => ({
      name,
      bookings: stats.bookings,
      nights: stats.nights,
      revenue: Math.round(stats.revenue * 100) / 100,
      pct: totalBookings > 0 ? Math.round(stats.bookings / totalBookings * 100) : 0
    })).sort((a, b) => b.bookings - a.bookings);

    // ── Résumé global ───────────────────────────────────────────
    const summary = {
      totalBookings,
      totalNights:            filteredResas.reduce((s, r) => s + r.nights, 0),
      totalGrossRevenue:      Math.round(filteredResas.reduce((s, r) => s + r.grossRevenue, 0) * 100) / 100,
      totalNetRevenue:        Math.round(filteredResas.reduce((s, r) => s + r.netRevenue, 0) * 100) / 100,
      totalTouristTax:        Math.round(filteredResas.reduce((s, r) => s + r.touristTax, 0) * 100) / 100,
      totalCleaningFee:       Math.round(filteredResas.reduce((s, r) => s + r.cleaningFee, 0) * 100) / 100,
      totalConcierge:         Math.round(filteredResas.reduce((s, r) => s + r.conciergeAmount, 0) * 100) / 100,
      totalOwnerRevenue:      Math.round(filteredResas.reduce((s, r) => s + r.ownerRevenue, 0) * 100) / 100,
      totalOtaCommission:     Math.round(filteredResas.reduce((s, r) => s + r.otaCommissionAmount, 0) * 100) / 100,
      avgNightsPerBooking: totalBookings > 0
        ? Math.round(filteredResas.reduce((s, r) => s + r.nights, 0) / totalBookings * 10) / 10
        : 0
    };

    res.json({
      year: selectedYear,
      month: selectedMonth,
      summary,
      monthly: monthlyData,
      byProperty: Object.values(byProperty),
      platforms: platformArray,
      reservations: filteredResas
    });

  } catch (err) {
    console.error('❌ GET /api/reporting:', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// ============================================
// EXPORT COMPTABLE — RÉSERVATIONS CSV
// ============================================
app.get('/api/export/reservations', authenticateAny, async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) return res.status(401).json({ error: 'Non autorise' });

    const { month, year, property_id } = req.query;
    const selectedYear  = parseInt(year)  || new Date().getFullYear();
    const selectedMonth = parseInt(month) || null;

    let dateFilter = `EXTRACT(YEAR FROM r.start_date) = $2`;
    const params = [user.id, selectedYear];
    if (selectedMonth) {
      dateFilter += ` AND EXTRACT(MONTH FROM r.start_date) = $${params.length + 1}`;
      params.push(selectedMonth);
    }
    if (property_id) {
      dateFilter += ` AND r.property_id = $${params.length + 1}`;
      params.push(property_id);
    }

    // Pas de blocages, seulement les vraies réservations
    const result = await pool.query(`
      SELECT
        r.uid, r.property_id, r.start_date, r.end_date,
        r.price, r.platform, r.ota_name, r.status,
        r.guest_name, r.nb_guests,
        (r.end_date::date - r.start_date::date) AS nights
      FROM reservations r
      WHERE r.user_id = $1
        AND r.status IN ('confirmed', 'completed')
        AND r.uid NOT LIKE 'block_%'
        AND COALESCE(r.source, '') NOT IN ('BLOCK', 'BLOCAGE')
        AND COALESCE(r.platform, '') NOT IN ('BLOCK', 'Block')
        AND ${dateFilter}
      ORDER BY r.start_date ASC
    `, params);

    // Propriétés avec configs financières
    const propsResult = await pool.query(
      `SELECT id, name, base_price, weekend_price, cleaning_fee, tourist_tax_per_night FROM properties WHERE user_id = $1`,
      [user.id]
    );
    const propMap = {};
    propsResult.rows.forEach(p => { propMap[p.id] = p; });

    // Overrides de prix
    const overridesResult = await pool.query(
      `SELECT property_id, TO_CHAR(date, 'YYYY-MM-DD') as date, price FROM pricing_overrides WHERE user_id = $1 AND EXTRACT(YEAR FROM date) = $2`,
      [user.id, selectedYear]
    );
    const overridesMap = {};
    overridesResult.rows.forEach(o => { overridesMap[`${o.property_id}_${o.date}`] = parseFloat(o.price); });

    // Infos utilisateur
    const userInfo = await pool.query('SELECT first_name, last_name, company, email FROM users WHERE id = $1', [user.id]);
    const u = userInfo.rows[0] || {};
    const userName = u.company || `${u.first_name || ''} ${u.last_name || ''}`.trim() || u.email;

    // Nom de fichier sans accents
    const periodFile = selectedMonth ? `${String(selectedMonth).padStart(2,'0')}-${selectedYear}` : `${selectedYear}`;
    const periodDisplay = selectedMonth ? `${String(selectedMonth).padStart(2,'0')}/${selectedYear}` : `Annee ${selectedYear}`;

    const normPlatform = (ota, plat) => {
      const raw = (ota || plat || '').toLowerCase();
      if (raw.includes('abb') || raw.includes('airbnb')) return 'Airbnb';
      if (raw.includes('bdc') || raw.includes('booking') || raw.includes('bookingcom')) return 'Booking.com';
      if (raw.includes('exp') || raw.includes('expedia')) return 'Expedia';
      if (raw.includes('vrbo') || raw.includes('homeaway')) return 'Vrbo';
      if (raw.includes('guest') || raw.includes('boostinghost')) return 'Boostinghost Guest';
      if (!raw || raw === 'direct' || raw === 'manuel' || raw === 'manual') return 'Direct';
      return raw.charAt(0).toUpperCase() + raw.slice(1);
    };

    const fmt = v => (parseFloat(v) || 0).toFixed(2).replace('.', ',');
    const fmtDate = d => {
      if (!d) return '';
      const dt = new Date(d);
      const day = String(dt.getUTCDate()).padStart(2,'0');
      const mon = String(dt.getUTCMonth()+1).padStart(2,'0');
      const yr  = dt.getUTCFullYear();
      return `${day}/${mon}/${yr}`;
    };

    const lines = [];
    lines.push(`# Export Boostinghost.fr - Reservations`);
    lines.push(`# Compte : ${userName}`);
    lines.push(`# Periode : ${periodDisplay}`);
    lines.push(`# Genere le : ${fmtDate(new Date())} a ${new Date().toLocaleTimeString('fr-FR', {hour:'2-digit',minute:'2-digit'})}`);
    lines.push(`# boostinghost.fr`);
    lines.push('');
    lines.push(['N reservation','Logement','Voyageur','Nb voyageurs','Plateforme','Arrivee','Depart','Nuits','Prix sejour (EUR)','Frais menage (EUR)','Taxe sejour (EUR)','Total (EUR)','Statut'].join(';'));

    let totalGeneral = 0;

    for (const r of result.rows) {
      const prop = propMap[r.property_id] || {};
      const nights = parseInt(r.nights) || 1;
      const nbGuests = parseInt(r.nb_guests) || 1;

      // Prix : r.price > overrides jour par jour > base_price/weekend_price
      let rawPrice = parseFloat(r.price) || 0;
      if (!rawPrice) {
        let total = 0;
        const start = new Date(r.start_date);
        for (let i = 0; i < nights; i++) {
          const d = new Date(start);
          d.setUTCDate(start.getUTCDate() + i);
          const dateStr = d.toISOString().split('T')[0];
          const key = `${r.property_id}_${dateStr}`;
          const dow = d.getUTCDay();
          const isPremium = (dow === 5 || dow === 6);
          const nightPrice = overridesMap[key] != null
            ? overridesMap[key]
            : (isPremium && prop.weekend_price ? parseFloat(prop.weekend_price) : (parseFloat(prop.base_price) || 0));
          total += nightPrice;
        }
        rawPrice = total;
      }

      const cleaningFee = parseFloat(prop.cleaning_fee) || 0;
      const touristTax  = (parseFloat(prop.tourist_tax_per_night) || 0) * nights * Math.max(nbGuests, 1);
      const totalLine   = rawPrice + cleaningFee + touristTax;
      totalGeneral += totalLine;

      lines.push([
        r.uid,
        `"${(prop.name || '').replace(/"/g,'""')}"`,
        `"${(r.guest_name || '').replace(/"/g,'""')}"`,
        nbGuests,
        normPlatform(r.ota_name, r.platform),
        fmtDate(r.start_date),
        fmtDate(r.end_date),
        nights,
        fmt(rawPrice),
        fmt(cleaningFee),
        fmt(touristTax),
        fmt(totalLine),
        r.status
      ].join(';'));
    }

    lines.push('');
    lines.push(`;;;;;;;;;Total;;${fmt(totalGeneral)};`);

    const filename = `boostinghost_reservations_${periodFile}.csv`;
    res.setHeader('Content-Type', 'text/csv; charset=utf-8');
    res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);
    res.send('\uFEFF' + lines.join('\n'));
  } catch (err) {
    console.error('Export reservations:', err);
    res.status(500).json({ error: 'Erreur export' });
  }
});

// ============================================
// EXPORT COMPTABLE — FACTURES PROPRIETAIRES CSV
// ============================================
app.get('/api/export/invoices', authenticateAny, async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) return res.status(401).json({ error: 'Non autorise' });

    const { month, year } = req.query;
    const selectedYear  = parseInt(year)  || new Date().getFullYear();
    const selectedMonth = parseInt(month) || null;

    let dateFilter = `EXTRACT(YEAR FROM i.issue_date) = $2`;
    const params = [user.id, selectedYear];
    if (selectedMonth) {
      dateFilter += ` AND EXTRACT(MONTH FROM i.issue_date) = $${params.length + 1}`;
      params.push(selectedMonth);
    }

    const result = await pool.query(`
      SELECT
        COALESCE(i.invoice_number, 'Brouillon #' || i.id::text) AS invoice_number,
        i.issue_date, i.due_date, i.period_start, i.period_end,
        COALESCE(c.company_name, c.first_name || ' ' || c.last_name) AS client_name,
        c.email AS client_email,
        i.subtotal_ht, i.subtotal_debours, i.vat_amount, i.total_ttc,
        i.status, i.is_credit_note
      FROM owner_invoices i
      JOIN owner_clients c ON c.id = i.client_id
      WHERE i.user_id = $1 AND ${dateFilter}
      ORDER BY i.issue_date ASC, i.id ASC
    `, params);

    const userInfo = await pool.query('SELECT first_name, last_name, company, email FROM users WHERE id = $1', [user.id]);
    const u = userInfo.rows[0] || {};
    const userName = u.company || `${u.first_name || ''} ${u.last_name || ''}`.trim() || u.email;

    const periodFile    = selectedMonth ? `${String(selectedMonth).padStart(2,'0')}-${selectedYear}` : `${selectedYear}`;
    const periodDisplay = selectedMonth ? `${String(selectedMonth).padStart(2,'0')}/${selectedYear}` : `Annee ${selectedYear}`;

    const fmtDate = d => {
      if (!d) return '';
      const dt = new Date(d);
      const day = String(dt.getUTCDate()).padStart(2,'0');
      const mon = String(dt.getUTCMonth()+1).padStart(2,'0');
      return `${day}/${mon}/${dt.getUTCFullYear()}`;
    };
    const fmtNum = v => v != null ? parseFloat(v).toFixed(2).replace('.',',') : '0,00';

    const lines = [];
    lines.push(`# Export Boostinghost.fr - Factures proprietaires`);
    lines.push(`# Compte : ${userName}`);
    lines.push(`# Periode : ${periodDisplay}`);
    lines.push(`# Genere le : ${fmtDate(new Date())} a ${new Date().toLocaleTimeString('fr-FR', {hour:'2-digit',minute:'2-digit'})}`);
    lines.push(`# boostinghost.fr`);
    lines.push('');
    lines.push(['N facture','Date emission','Date echeance','Periode debut','Periode fin','Client','Email client','Sous-total HT (EUR)','Debours (EUR)','TVA (EUR)','Total TTC (EUR)','Statut','Type'].join(';'));

    for (const inv of result.rows) {
      lines.push([
        inv.invoice_number,
        fmtDate(inv.issue_date),
        fmtDate(inv.due_date),
        fmtDate(inv.period_start),
        fmtDate(inv.period_end),
        `"${(inv.client_name || '').replace(/"/g,'""')}"`,
        inv.client_email || '',
        fmtNum(inv.subtotal_ht),
        fmtNum(inv.subtotal_debours),
        fmtNum(inv.vat_amount),
        fmtNum(inv.total_ttc),
        inv.status || '',
        inv.is_credit_note ? 'Avoir' : 'Facture'
      ].join(';'));
    }

    const totalTTC = result.rows.reduce((s, i) => s + (parseFloat(i.total_ttc) || 0), 0);
    lines.push('');
    lines.push(`;;;;;;;;;Total;;;${fmtNum(totalTTC)};`);

    const filename = `boostinghost_factures_${periodFile}.csv`;
    res.setHeader('Content-Type', 'text/csv; charset=utf-8');
    res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);
    res.send('\uFEFF' + lines.join('\n'));
  } catch (err) {
    console.error('Export factures:', err);
    res.status(500).json({ error: 'Erreur export' });
  }
});

// ============================================
// SCORE QUALITE PAR LOGEMENT
// ============================================
app.get('/api/quality-score', authenticateAny, async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) return res.status(401).json({ error: 'Non autorise' });

    const { year } = req.query;
    const selectedYear = parseInt(year) || new Date().getFullYear();
    const daysInYear = 365;

    // 1. Récupérer tous les logements de l'utilisateur
    const propsResult = await pool.query(
      `SELECT id, name, color, channex_property_id, channex_enabled FROM properties WHERE user_id = $1 ORDER BY display_order ASC, created_at ASC`,
      [user.id]
    );
    const properties = propsResult.rows;
    if (!properties.length) return res.json({ scores: [] });

    const propIds = properties.map(p => p.id);

    // 2. Taux d'occupation : nuits réservées / 365
    const occResult = await pool.query(`
      SELECT
        r.property_id,
        SUM(r.end_date::date - r.start_date::date) AS nights
      FROM reservations r
      WHERE r.user_id = $1
        AND r.status IN ('confirmed','completed')
        AND r.uid NOT LIKE 'block_%'
        AND COALESCE(r.source,'') NOT IN ('BLOCK','BLOCAGE')
        AND EXTRACT(YEAR FROM r.start_date) = $2
        AND r.property_id = ANY($3)
      GROUP BY r.property_id
    `, [user.id, selectedYear, propIds]);

    const occMap = {};
    occResult.rows.forEach(r => { occMap[r.property_id] = parseInt(r.nights) || 0; });

    // 3. Ménages validés à temps (avant l'arrivée du voyageur)
    // On compare completed_at vs start_date de la réservation liée
    const cleanResult = await pool.query(`
      SELECT
        cc.property_id,
        COUNT(*) AS total,
        SUM(CASE WHEN cc.is_validated = TRUE THEN 1 ELSE 0 END) AS validated
      FROM cleaning_checklists cc
      JOIN reservations r ON r.uid = cc.reservation_key
      WHERE cc.user_id = $1
        AND EXTRACT(YEAR FROM r.start_date) = $2
        AND cc.property_id = ANY($3)
      GROUP BY cc.property_id
    `, [user.id, selectedYear, propIds]);

    const cleanMap = {};
    cleanResult.rows.forEach(r => {
      cleanMap[r.property_id] = {
        total: parseInt(r.total) || 0,
        validated: parseInt(r.validated) || 0
      };
    });

    // 4. Délai de réponse aux messages (sender_type = 'guest' puis 'owner')
    // On calcule le délai moyen entre message guest et première réponse owner
    const msgResult = await pool.query(`
      SELECT
        c.property_id,
        AVG(EXTRACT(EPOCH FROM (m_owner.created_at - m_guest.created_at))/3600) AS avg_response_hours
      FROM conversations c
      JOIN messages m_guest ON m_guest.conversation_id = c.id AND m_guest.sender_type = 'guest'
      JOIN LATERAL (
        SELECT created_at FROM messages
        WHERE conversation_id = c.id
          AND sender_type = 'owner'
          AND created_at > m_guest.created_at
        ORDER BY created_at ASC LIMIT 1
      ) m_owner ON TRUE
      WHERE c.user_id = $1
        AND c.property_id = ANY($2)
        AND EXTRACT(YEAR FROM m_guest.created_at) = $3
      GROUP BY c.property_id
    `, [user.id, propIds, selectedYear]);

    const responseMap = {};
    msgResult.rows.forEach(r => {
      responseMap[r.property_id] = parseFloat(r.avg_response_hours) || null;
    });

    // 5. Note moyenne avis Channex (appel API pour chaque logement connecté)
    const reviewMap = {};
    const { channexAPI } = require('./channex');
    for (const prop of properties) {
      if (!prop.channex_enabled || !prop.channex_property_id) continue;
      try {
        const scoresRes = await channexAPI.get('/reviews/scores', {
          params: { 'filter[property_id]': prop.channex_property_id }
        });
        const rawScores = scoresRes.data?.data || [];
        let totalScore = 0, count = 0;
        rawScores.forEach(s => {
          const attrs = s.attributes || s;
          if (attrs.score != null) { totalScore += parseFloat(attrs.score); count++; }
          if (attrs.scores) {
            Object.values(attrs.scores).forEach(v => { if (v != null) { totalScore += parseFloat(v); count++; } });
          }
        });
        if (count > 0) reviewMap[prop.id] = Math.round((totalScore / count) * 10) / 10;
      } catch (e) {
        // Channex non dispo pour ce logement, on ignore
      }
    }

    // 6. Calcul du score final pour chaque logement
    const scores = properties.map(prop => {
      const nights    = occMap[prop.id] || 0;
      const occupancy = Math.min(nights / daysInYear * 100, 100);

      // Score taux d'occupation /25 (100% occ = 25pts, 50% = 12.5pts)
      const scoreOcc = Math.round(occupancy / 100 * 25);

      // Score avis /35 (note sur 10 → /10 * 35)
      const avgRating = reviewMap[prop.id] || null;
      const scoreReview = avgRating != null ? Math.round(avgRating / 10 * 35) : null;

      // Score ménages /25 (% validés)
      const clean = cleanMap[prop.id];
      let scoreClean = null;
      if (clean && clean.total > 0) {
        scoreClean = Math.round(clean.validated / clean.total * 25);
      }

      // Score réponse /15 (< 1h = 15pts, < 3h = 10pts, < 24h = 5pts, > 24h = 0pts)
      const avgHours = responseMap[prop.id];
      let scoreResponse = null;
      if (avgHours != null) {
        if (avgHours < 1)  scoreResponse = 15;
        else if (avgHours < 3)  scoreResponse = 10;
        else if (avgHours < 24) scoreResponse = 5;
        else scoreResponse = 0;
      }

      // Total : on ne compte que les critères disponibles
      let total = 0, maxTotal = 0;
      total += scoreOcc; maxTotal += 25;
      if (scoreReview  != null) { total += scoreReview;   maxTotal += 35; }
      if (scoreClean   != null) { total += scoreClean;    maxTotal += 25; }
      if (scoreResponse != null){ total += scoreResponse; maxTotal += 15; }

      // Ramener sur 100 selon les critères disponibles
      const finalScore = maxTotal > 0 ? Math.round(total / maxTotal * 100) : null;

      // Couleur selon score
      const color = finalScore == null ? '#9CA3AF'
        : finalScore >= 75 ? '#10B981'
        : finalScore >= 50 ? '#F59E0B'
        : '#EF4444';

      return {
        property_id:   prop.id,
        property_name: prop.name,
        property_color: prop.color,
        score:         finalScore,
        color,
        details: {
          occupancy:    { score: scoreOcc,      max: 25, value: Math.round(occupancy) + '%', label: "Taux d'occupation" },
          reviews:      { score: scoreReview,   max: 35, value: avgRating != null ? avgRating + '/10' : null, label: 'Note moyenne avis' },
          cleaning:     { score: scoreClean,    max: 25, value: clean?.total > 0 ? Math.round(clean.validated/clean.total*100) + '%' : null, label: 'Ménages validés' },
          response:     { score: scoreResponse, max: 15, value: avgHours != null ? (avgHours < 1 ? '< 1h' : Math.round(avgHours) + 'h') : null, label: 'Délai de réponse' }
        }
      };
    });

    res.json({ year: selectedYear, scores });

  } catch (err) {
    console.error('❌ GET /api/quality-score:', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// ============================================
// MODIFIER UN LOGEMENT
// ============================================
// PATCH /api/properties/:propertyId — Mettre à jour owner_id uniquement
app.patch('/api/properties/:propertyId', authenticateAny, async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) return res.status(401).json({ error: 'Non autorisé' });

    const { propertyId } = req.params;
    const { ownerId } = req.body;

    // Vérifier que le logement appartient à cet user
    const check = await pool.query('SELECT id FROM properties WHERE id = $1 AND user_id = $2', [propertyId, user.id]);
    if (!check.rows.length) return res.status(404).json({ error: 'Logement non trouvé' });

    await pool.query(
      'UPDATE properties SET owner_id = $1 WHERE id = $2',
      [ownerId || null, propertyId]
    );

    // ✅ Recharger le store en mémoire pour que la logique Stripe soit immédiatement à jour
    await loadProperties();

    return res.json({ success: true, propertyId, ownerId: ownerId || null });
  } catch (err) {
    console.error('Erreur PATCH /api/properties/:propertyId :', err);
    res.status(500).json({ error: err.message });
  }
});

app.put('/api/properties/:propertyId', 
  authenticateAny,
  requirePermission(pool, 'can_edit_properties'),
  loadSubAccountData(pool),
  upload.single('photo'), 
  async (req, res) => {
  try {
    const userId = req.user.isSubAccount 
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    
    if (!userId) {
      return res.status(401).json({ error: 'Non autorisé' });
    }
    
    const { propertyId } = req.params;
    
    // ✅ Vérifier accès propriété si sous-compte
    if (req.user.isSubAccount && req.subAccountData.accessible_property_ids.length > 0) {
      if (!req.subAccountData.accessible_property_ids.includes(propertyId)) {
        return res.status(403).json({ error: 'Accès refusé à cette propriété' });
      }
    }
    
    let body;
    try {
      body = parsePropertyBody(req);
    } catch (e) {
      return res.status(400).json({ error: e.message });
    }
    
    const {
      name,
      color,
      icalUrls,
      address,
      arrivalTime,
      departureTime,
      depositAmount,
      photoUrl: existingPhotoUrl,
      welcomeBookUrl,
      accessCode,
      wifiName,
      wifiPassword,
      accessInstructions,
      arrivalMessage,
      ownerId,
      amenities,
      houseRules,
      practicalInfo,
      autoResponsesEnabled,
      chatPin,
      quickReplies,
      basePrice,
      weekendPrice,
      cleaningFee,
      touristTaxPerNight,
      conciergePct,
      maxGuests,
      bedrooms,
      beds,
      bathrooms,
      internal_name,
      customAutoResponses,
      booking_id,
      abritel_id,
      expedia_id,
      channex_property_id: channex_property_id_ext
    } = body;
    
    const property = PROPERTIES.find(p => p.id === propertyId && p.userId === userId);
    if (!property) {
      return res.status(404).json({ error: 'Logement non trouvé' });
    }

    // Gérer la mise à jour du PIN (garder l'ancien si non fourni)
    const newChatPin = 
      chatPin !== undefined 
        ? (chatPin || property.chat_pin) 
        : (property.chat_pin || null);

    const newName = name || property.name;
    const newColor = color || property.color;

    const newAddress =
      address !== undefined ? address : (property.address || null);

    const newArrivalTime =
      arrivalTime !== undefined
        ? arrivalTime
        : (property.arrival_time || property.arrivalTime || null);

    const newDepartureTime =
      departureTime !== undefined
        ? departureTime
        : (property.departure_time || property.departureTime || null);

    const newDepositAmount =
      depositAmount !== undefined
        ? (depositAmount === '' || depositAmount == null
            ? null
            : Number(depositAmount))
        : (property.deposit_amount ?? property.depositAmount ?? null);

    const newWelcomeBookUrl = 
      welcomeBookUrl !== undefined 
        ? (welcomeBookUrl || null) 
        : (property.welcome_book_url || null);

    const newAccessCode = 
      accessCode !== undefined 
        ? (accessCode || null) 
        : (property.access_code || null);

    const newWifiName = 
      wifiName !== undefined 
        ? (wifiName || null) 
        : (property.wifi_name || null);

    const newWifiPassword = 
      wifiPassword !== undefined 
        ? (wifiPassword || null) 
        : (property.wifi_password || null);

    const newAccessInstructions = 
      accessInstructions !== undefined 
        ? (accessInstructions || null) 
        : (property.access_instructions || null);

    // ✅ NOUVEAUX CHAMPS
    const newAmenities = 
      amenities !== undefined 
        ? amenities 
        : (property.amenities || '{}');

    const newHouseRules = 
      houseRules !== undefined 
        ? houseRules 
        : (property.house_rules || '{}');

    const newPracticalInfo = 
      practicalInfo !== undefined 
        ? practicalInfo 
        : (property.practical_info || '{}');

    const newAutoResponsesEnabled = 
      autoResponsesEnabled !== undefined 
        ? autoResponsesEnabled 
        : (property.auto_responses_enabled !== undefined ? property.auto_responses_enabled : true);
    
    const newArrivalMessage = 
      arrivalMessage !== undefined 
        ? arrivalMessage 
        : (property.arrival_message || null);  // ✅ NOUVEAU

    const newQuickReplies = quickReplies !== undefined
      ? (Array.isArray(quickReplies) ? quickReplies : [])
      : (property.quick_replies || []);

    const newBasePrice = basePrice !== undefined
      ? (basePrice !== '' && basePrice !== null ? parseFloat(basePrice) : null)
      : (property.basePrice != null ? property.basePrice : null);

    const newWeekendPrice = weekendPrice !== undefined
      ? (weekendPrice !== '' && weekendPrice !== null ? parseFloat(weekendPrice) : null)
      : (property.weekendPrice != null ? property.weekendPrice : null);

    const newCustomAutoResponses = customAutoResponses !== undefined
      ? (Array.isArray(customAutoResponses) ? JSON.stringify(customAutoResponses) : customAutoResponses || '[]')
      : JSON.stringify(property.custom_auto_responses || []);

    const newInternalName = internal_name !== undefined
      ? (internal_name !== null && String(internal_name).trim() !== '' ? String(internal_name).trim() : null)
      : (property.internal_name || property.internalName || null);

    const newMaxGuests = maxGuests !== undefined
      ? (maxGuests !== '' && maxGuests !== null ? parseInt(maxGuests, 10) : null)
      : (property.max_guests ?? property.maxGuests ?? null);

    const newBedrooms = bedrooms !== undefined
      ? (bedrooms !== '' && bedrooms !== null ? parseInt(bedrooms, 10) : null)
      : (property.bedrooms ?? null);

    const newBeds = beds !== undefined
      ? (beds !== '' && beds !== null ? parseInt(beds, 10) : null)
      : (property.beds ?? null);

    const newBathrooms = bathrooms !== undefined
      ? (bathrooms !== '' && bathrooms !== null ? parseInt(bathrooms, 10) : null)
      : (property.bathrooms ?? null);

    const newBookingId = booking_id !== undefined ? (booking_id || null) : (property.booking_id || null);
    const newAbritelId = abritel_id !== undefined ? (abritel_id || null) : (property.abritel_id || null);
    const newExpediaId = expedia_id !== undefined ? (expedia_id || null) : (property.expedia_id || null);
    const newChannexPropertyIdExt = channex_property_id_ext !== undefined ? (channex_property_id_ext || null) : (property.channex_property_id_ext || null);

    let newPhotoUrl =
      existingPhotoUrl !== undefined
        ? (existingPhotoUrl || null)
        : (property.photo_url || property.photoUrl || null);

    // Upload vers Cloudinary si une nouvelle photo est fournie
    if (req.file) {
      try {
        newPhotoUrl = await uploadPhotoToCloudinary(req.file);
      } catch (uploadError) {
        console.error('Erreur upload Cloudinary:', uploadError);
        return res.status(500).json({ error: 'Erreur lors de l\'upload de la photo' });
      }
    }

    let newIcalUrls;
    if (icalUrls !== undefined) {
      newIcalUrls = Array.isArray(icalUrls)
        ? icalUrls
            .map(item => {
              if (typeof item === 'string') {
                return {
                  url: item,
                  platform: 'iCal'
                };
              }
              if (item && typeof item === 'object' && item.url) {
                const url = item.url;
                const platform =
                  item.platform && item.platform.trim().length > 0
                    ? item.platform.trim()
                    : 'iCal';
                return { url, platform };
              }
              return null;
            })
            .filter(Boolean)
        : [];
    } else {
      // on garde ce qui est en base
      newIcalUrls = property.icalUrls || property.ical_urls || [];
    }

    const newOwnerId = ownerId || null;
    
    console.log('💾 UPDATE - Valeurs à sauvegarder:', {
      newAmenities,
      newHouseRules,
      newPracticalInfo,
      newAutoResponsesEnabled,
      propertyId,
userId: userId
    });
    
    const result = await pool.query(
      `UPDATE properties
       SET
         name = $1,
         color = $2,
         ical_urls = $3,
         address = $4,
         arrival_time = $5,
         departure_time = $6,
         deposit_amount = $7,
         photo_url = $8,
         welcome_book_url = $9,
         access_code = $10,
         wifi_name = $11,
         wifi_password = $12,
         access_instructions = $13,
         owner_id = $14,
         chat_pin = $15,
         amenities = $16,
         house_rules = $17,
         practical_info = $18,
         auto_responses_enabled = $19,
         arrival_message = $20,
         quick_replies = $21,
         internal_name = $24,
         base_price = $25,
         weekend_price = $26,
         cleaning_fee = $27,
         tourist_tax_per_night = $28,
         concierge_pct = $29,
         max_guests = $30,
         bedrooms = $31,
         beds = $32,
         bathrooms = $33,
         custom_auto_responses = $34,
         booking_id = $35,
         abritel_id = $36,
         expedia_id = $37,
         channex_property_id_ext = $38,
         airbnb_commission_pct = $39,
         booking_commission_pct = $40,
         updated_at = NOW()
       WHERE id = $22 AND user_id = $23`,
      [
        newName, newColor, JSON.stringify(newIcalUrls || []), newAddress,
        newArrivalTime, newDepartureTime, newDepositAmount, newPhotoUrl,
        newWelcomeBookUrl, newAccessCode, newWifiName, newWifiPassword,
        newAccessInstructions, newOwnerId, newChatPin,
        typeof newAmenities === 'string' ? newAmenities : JSON.stringify(newAmenities || {}),
        typeof newHouseRules === 'string' ? newHouseRules : JSON.stringify(newHouseRules || {}),
        typeof newPracticalInfo === 'string' ? newPracticalInfo : JSON.stringify(newPracticalInfo || {}),
        newAutoResponsesEnabled,
        newArrivalMessage,
        JSON.stringify(newQuickReplies),
        propertyId, userId,
        newInternalName,
        newBasePrice,
        newWeekendPrice,
        cleaningFee != null && cleaningFee !== '' ? parseFloat(cleaningFee) : (property.cleaningFee ?? null),
        touristTaxPerNight != null && touristTaxPerNight !== '' ? parseFloat(touristTaxPerNight) : (property.touristTaxPerNight ?? null),
        conciergePct != null && conciergePct !== '' ? parseFloat(conciergePct) : (property.conciergePct ?? null),
        newMaxGuests,
        newBedrooms,
        newBeds,
        newBathrooms,
        newCustomAutoResponses,
        newBookingId,
        newAbritelId,
        newExpediaId,
        newChannexPropertyIdExt,
        body.airbnbCommissionPct != null && body.airbnbCommissionPct !== '' ? parseFloat(body.airbnbCommissionPct) : (property.airbnb_commission_pct ?? 3),
        body.bookingCommissionPct != null && body.bookingCommissionPct !== '' ? parseFloat(body.bookingCommissionPct) : (property.booking_commission_pct ?? 15)
      ]
    );
    
    console.log('✅ UPDATE terminé, lignes affectées:', result.rowCount);
    console.log('💰 [COMMISSION DEBUG] airbnb:', body.airbnbCommissionPct, '| booking:', body.bookingCommissionPct);
    
    await loadProperties();

    // Lire directement depuis la DB pour éviter les race conditions avec le cache
    const dbRow = await pool.query(
      'SELECT * FROM properties WHERE id = $1 AND user_id = $2',
      [propertyId, userId]
    );
    const updated = dbRow.rows[0] ? {
      ...dbRow.rows[0],
      airbnbCommissionPct: parseFloat(dbRow.rows[0].airbnb_commission_pct) || 3,
      bookingCommissionPct: parseFloat(dbRow.rows[0].booking_commission_pct) || 15,
    } : PROPERTIES.find(p => p.id === propertyId && p.userId === userId);
    res.json({
      message: 'Logement modifié avec succès',
      property: updated
    });
  } catch (err) {
    console.error('❌ Erreur modification logement:', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

