// PUT - Sauvegarder l'ordre complet des logements
app.put('/api/properties/reorder-bulk', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const { order } = req.body;
    if (!Array.isArray(order) || !order.length) {
      return res.status(400).json({ error: 'Ordre invalide' });
    }

    // Mettre à jour display_order pour chaque logement
    for (let i = 0; i < order.length; i++) {
      await pool.query(
        `UPDATE properties SET display_order = $1 WHERE id = $2 AND user_id = $3`,
        [i + 1, order[i], userId]
      );
    }

    console.log(`✅ [REORDER] Ordre sauvegardé pour user ${userId}: ${order.join(', ')}`);
    res.json({ success: true });
  } catch (err) {
    console.error('Erreur PUT reorder-bulk:', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

app.put('/api/properties/:propertyId/reorder', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount 
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    
    if (!userId) {
      return res.status(401).json({ error: 'Non autorise' });
    }
    
    const { propertyId } = req.params;
    const { direction } = req.body;

    if (!['up', 'down'].includes(direction)) {
      return res.status(400).json({ error: 'Direction invalide' });
    }

    // Logement courant
    const currentRes = await pool.query(
      `SELECT id, display_order
       FROM properties
       WHERE id = $1 AND user_id = $2`,
      [propertyId, userId]
    );

    if (currentRes.rows.length === 0) {
      return res.status(404).json({ error: 'Logement introuvable' });
    }

    const current = currentRes.rows[0];
    const currentOrder = Number(current.display_order);

    // Voisin a echanger
    const neighborRes = await pool.query(
      direction === 'up'
        ? `
          SELECT id, display_order
          FROM properties
          WHERE user_id = $1 AND display_order < $2
          ORDER BY display_order DESC
          LIMIT 1
        `
        : `
          SELECT id, display_order
          FROM properties
          WHERE user_id = $1 AND display_order > $2
          ORDER BY display_order ASC
          LIMIT 1
        `,
      [userId, currentOrder]
    );

    if (neighborRes.rows.length === 0) {
      return res.status(400).json({
        error: direction === 'up'
          ? 'Déjà en première position'
          : 'Déjà en dernière position'
      });
    }

    const neighbor = neighborRes.rows[0];

    // 🔁 SWAP SÉCURISÉ (anti conflit UNIQUE)
    await pool.query('BEGIN');

    // 1️⃣ Mettre le courant en temporaire
    await pool.query(
      `UPDATE properties
       SET display_order = -1
       WHERE id = $1`,
      [current.id]
    );

    // 2️⃣ Déplacer le voisin
    await pool.query(
      `UPDATE properties
       SET display_order = $1
       WHERE id = $2`,
      [currentOrder, neighbor.id]
    );

    // 3️⃣ Mettre le courant à la place du voisin
    await pool.query(
      `UPDATE properties
       SET display_order = $1
       WHERE id = $2`,
      [neighbor.display_order, current.id]
    );

    await pool.query('COMMIT');

    // 🔄 Recharger le cache mémoire
    await loadProperties();

    return res.json({ success: true });

  } catch (err) {
    await pool.query('ROLLBACK');
    console.error('Erreur réorganisation logements:', err);

    return res.status(500).json({
      error: 'Erreur serveur lors de la réorganisation'
    });
  }
});
