app.post('/api/auth/register', async (req, res) => {
  try {
    const { company, firstName, lastName, email, password } = req.body;
    
    if (!firstName || !lastName || !email || !password) {
      return res.status(400).json({ error: 'Champs obligatoires manquants' });
    }

    // Vérifier si l'email existe déjà
    const existing = await pool.query(
      'SELECT id FROM users WHERE LOWER(email) = LOWER($1)',
      [email]
    );
    
    if (existing.rows.length > 0) {
      return res.status(409).json({ error: 'Un compte existe déjà avec cet e-mail' });
    }

    // Hasher le mot de passe
    const passwordHash = await bcrypt.hash(password, 10);
    
    // Générer l'ID utilisateur
    const id = `u_${Date.now().toString(36)}`;

    // Générer le token de vérification
    const verificationToken = crypto.randomBytes(32).toString('hex');
    const tokenExpires = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 heures

    // Créer l'utilisateur avec email_verified = FALSE
    await pool.query(
      `INSERT INTO users (
        id, company, first_name, last_name, email, password_hash, 
        created_at, stripe_account_id,
        email_verified, verification_token, verification_token_expires
      )
      VALUES ($1, $2, $3, $4, $5, $6, NOW(), NULL, $7, $8, $9)`,
      [id, company, firstName, lastName, email, passwordHash, false, verificationToken, tokenExpires]
    );

    // Créer l'abonnement trial (seulement s'il n'existe pas déjà)
    const existingSub = await pool.query(
      'SELECT id FROM subscriptions WHERE user_id = $1',
      [id]
    );

    if (existingSub.rows.length === 0) {
      const trialStartDate = new Date();
      const trialEndDate = new Date(Date.now() + 14 * 24 * 60 * 60 * 1000);

      await pool.query(
        `INSERT INTO subscriptions (
          id, user_id, status, plan_type, plan_amount,
          trial_start_date, trial_end_date,
          created_at, updated_at
        ) VALUES ($1, $2, $3, $4, $5, $6, $7, NOW(), NOW())`,
        [
          `sub_${Date.now()}`,
          id,
          'trial',
          'pro',
          0,
          trialStartDate,
          trialEndDate
        ]
      );
    }

    // Envoyer l'email de vérification
    const appUrl = process.env.APP_URL || 'https://boostinghost.fr';
    const verificationUrl = `${appUrl}/verify-email.html?token=${verificationToken}`;

    const mailOptions = {
      from: EMAIL_FROM,
      to: email,
      subject: 'Vérifiez votre adresse email — Boostinghost',
      html: bhEmailTemplate({
        icon: '✉️',
        title: 'Confirmez votre email',
        subtitle: 'Une dernière étape avant de démarrer',
        footerNote: 'Si vous n\'avez pas créé de compte, ignorez cet email.',
        bodyHtml: `
          <p>Bonjour <strong>${firstName}</strong>,</p>
          <p>Merci de vous être inscrit sur Boostinghost. Pour activer votre compte, cliquez sur le bouton ci-dessous :</p>
          <div class="cta-block">
            <p>Lien valide pendant <strong>24 heures</strong></p>
            <a href="${verificationUrl}" class="btn">Vérifier mon adresse email →</a>
          </div>
          <p class="link-fallback">Le bouton ne fonctionne pas ? Copiez ce lien :<br><a href="${verificationUrl}">${verificationUrl}</a></p>
        `
      })
    };

    try {
      await transporter.sendMail(mailOptions);
      console.log('Email de vérification envoyé à:', email);
    } catch (emailErr) {
      console.error('Erreur envoi email:', emailErr);
      // On continue quand même
    }

    // 🔔 NOTIFICATION NOUVELLE INSCRIPTION
    try {
      await sendEmailViaBrevo({
  to: [
    'contact@boostinghost.fr',
    'charles.induni@gmail.com'
  ],
        subject: `🎉 Nouvelle inscription — ${firstName} ${lastName}`,
        html: bhEmailTemplate({
          icon: '🎉',
          title: 'Nouvelle inscription',
          tag: 'Notification admin',
          bodyHtml: `
            <div class="info-card">
              <strong>Nom :</strong> ${firstName} ${lastName}<br>
              <strong>Email :</strong> ${email}<br>
              <strong>Société :</strong> ${company || '—'}<br>
              <strong>Date :</strong> ${new Date().toLocaleString('fr-FR')}<br>
              <strong>Trial jusqu'au :</strong> ${new Date(Date.now() + 14 * 24 * 60 * 60 * 1000).toLocaleDateString('fr-FR')}
            </div>
          `
        })
      });
      console.log('✅ Notification inscription envoyée à charles.induni@gmail.com');
    } catch (notifErr) {
      console.error('❌ Erreur notification inscription (non bloquant):', notifErr?.response?.body || notifErr?.message || notifErr);
      // Non bloquant
    }

// Retourner succès
    res.status(201).json({
      success: true,
      message: 'Compte créé ! Vérifiez votre email pour activer votre compte.',
      emailSent: true,
      email: email
    });

  } catch (err) {
    console.error('Erreur register:', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

