// NOTE : Cette route utilise l'API Brevo au lieu de SMTP
// car Render bloque parfois le port 587



// ============================================
// FONCTION GLOBALE - Génération PDF facture
// ============================================
async function generateInvoicePdf(outputPath, data, user, ownerInfo) {
  const {
    clientName = '', clientEmail = '', clientAddress = '', clientPostalCode = '',
    clientCity = '', clientSiret = '', clientCompany = '', freeNote = '',
    clientNationality = '', platform = '',
    propertyName = '', propertyAddress = '',
    checkinDate = '', checkoutDate = '', nights = 0,
    rentAmount = 0, touristTaxAmount = 0, cleaningFee = 0,
    vatRate = 0, invoiceNumber = ''
  } = data;

  const subtotal = parseFloat(rentAmount || 0) + parseFloat(touristTaxAmount || 0) + parseFloat(cleaningFee || 0);
  const vatAmount = subtotal * (parseFloat(vatRate || 0) / 100);
  const total = subtotal + vatAmount;

  const emitterName  = ownerInfo ? (ownerInfo.company_name || `${ownerInfo.first_name||''} ${ownerInfo.last_name||''}`.replace(/\s+/g, ' ').trim()) : (data.emitterName || user?.company || 'Ma Conciergerie');
  const emitterAddr  = ownerInfo?.address     || data.emitterAddress    || '';
  const emitterCP    = ownerInfo?.postal_code || data.emitterPostalCode || '';
  const emitterCity  = ownerInfo?.city        || data.emitterCity       || '';
  const emitterEmail = ownerInfo?.email       || data.emitterEmail      || user?.email || '';
  const emitterSiret = ownerInfo?.siret       || data.emitterSiret      || '';

  return new Promise((resolve, reject) => {
    const doc = new PDFDocument({ size: 'A4', margin: 0 });
    const stream = fs.createWriteStream(outputPath);
    doc.pipe(stream);

    const W = 595, H = 842, mg = 50;
    const GREEN = '#1A7A5E', DARK = '#111827', GRAY = '#6B7280';
    const LIGHT = '#F3F4F6', BORDER = '#E5E7EB';

    // Bande verte haut
    doc.rect(0, 0, W, 8).fill(GREEN);

    // Nom émetteur
    let y = 32;
    doc.font('Helvetica-Bold').fontSize(20).fillColor(DARK).text(emitterName, mg, y, { width: 310 });
    y += 28;
    doc.font('Helvetica').fontSize(9).fillColor(GRAY);
    if (emitterAddr)  { doc.text(emitterAddr, mg, y);  y += 13; }
    if (emitterCP || emitterCity) { doc.text(`${emitterCP} ${emitterCity}`.trim(), mg, y); y += 13; }
    if (emitterEmail) { doc.text(emitterEmail, mg, y); y += 13; }
    if (emitterSiret) { doc.text(`SIRET : ${emitterSiret}`, mg, y); y += 13; }

    // Bloc FACTURE droite
    const bx = W - mg - 185, by = 28;
    doc.rect(bx, by, 185, 90).fill(LIGHT);
    doc.font('Helvetica-Bold').fontSize(20).fillColor(GREEN).text('FACTURE', bx+14, by+10);
    doc.font('Helvetica-Bold').fontSize(11).fillColor(DARK).text(`N° ${invoiceNumber}`, bx+14, by+38);
    doc.font('Helvetica').fontSize(9).fillColor(GRAY).text(`Date : ${new Date().toLocaleDateString('fr-FR')}`, bx+14, by+54);
    if (checkinDate && checkoutDate) {
      const ci = new Date(checkinDate).toLocaleDateString('fr-FR');
      const co = new Date(checkoutDate).toLocaleDateString('fr-FR');
      doc.text(`Du ${ci} au ${co}`, bx+14, by+68);
      doc.text(`${nights} nuit${nights>1?'s':''}`, bx+14, by+81);
    }

    // Séparateur
    y = 142;
    doc.rect(mg, y, W-mg*2, 1).fill(BORDER);
    y += 18;

    // Deux colonnes
    const colW = (W - mg*2 - 24) / 2;
    const col2 = mg + colW + 24;

    doc.font('Helvetica-Bold').fontSize(8).fillColor(GREEN);
    doc.text('ÉMIS PAR', mg, y);
    doc.text('FACTURÉ À', col2, y);
    y += 14;

    // ── Colonne gauche (émetteur) ──
    let yL = y;
    doc.font('Helvetica-Bold').fontSize(11).fillColor(DARK);
    doc.text(emitterName, mg, yL, { width: colW });
    yL += doc.heightOfString(emitterName, { width: colW }) + 5;
    doc.font('Helvetica').fontSize(9).fillColor(GRAY);
    if (emitterAddr)            { doc.text(emitterAddr, mg, yL, { width: colW }); yL += 13; }
    if (emitterCP||emitterCity) { doc.text(`${emitterCP} ${emitterCity}`.trim(), mg, yL); yL += 13; }
    if (emitterEmail)           { doc.text(emitterEmail, mg, yL); yL += 13; }

    // ── Colonne droite (client) ──
    let yR = y;
    doc.font('Helvetica-Bold').fontSize(11).fillColor(DARK);
    if (clientCompany) {
      doc.text(clientCompany, col2, yR, { width: colW });
      yR += doc.heightOfString(clientCompany, { width: colW }) + 5;
      doc.font('Helvetica').fontSize(9).fillColor(GRAY);
      doc.text(clientName, col2, yR, { width: colW }); yR += 13;
    } else {
      doc.text(clientName, col2, yR, { width: colW });
      yR += doc.heightOfString(clientName, { width: colW }) + 5;
    }
    doc.font('Helvetica').fontSize(9).fillColor(GRAY);
    if (clientAddress)    { doc.text(clientAddress, col2, yR, { width: colW }); yR += 13; }
    const cpCity = `${clientPostalCode||''} ${clientCity||''}`.trim();
    if (cpCity)           { doc.text(cpCity, col2, yR); yR += 13; }
    if (clientNationality){ doc.text(`Nationalité : ${clientNationality}`, col2, yR); yR += 13; }
    if (clientEmail)      { doc.text(clientEmail, col2, yR); yR += 13; }
    if (clientSiret)      { doc.text(`N° fiscal : ${clientSiret}`, col2, yR); yR += 13; }
    if (freeNote)         { doc.font('Helvetica-Oblique').text(freeNote, col2, yR, { width: colW }); yR += 13; doc.font('Helvetica'); }

    y = Math.max(yL, yR) + 22;

    // Logement
    doc.rect(mg, y, W-mg*2, 1).fill(BORDER);
    y += 14;
    doc.font('Helvetica-Bold').fontSize(8).fillColor(GREEN).text('LOGEMENT', mg, y);
    y += 14;
    doc.font('Helvetica-Bold').fontSize(11).fillColor(DARK).text(propertyName, mg, y);
    y += 15;
    doc.font('Helvetica').fontSize(9).fillColor(GRAY);
    if (propertyAddress) { doc.text(propertyAddress, mg, y); y += 13; }
    if (checkinDate && checkoutDate) {
      const ci = new Date(checkinDate).toLocaleDateString('fr-FR');
      const co = new Date(checkoutDate).toLocaleDateString('fr-FR');
      doc.text(`Séjour du ${ci} au ${co} · ${nights} nuit${nights>1?'s':''}`, mg, y); y += 13;
    }
    if (platform) {
      const platformLabels = {
        airbnb: 'Airbnb', booking: 'Booking.com', bookingcom: 'Booking.com',
        direct: 'Réservation directe', guest_app: 'BHGuest', bhguest: 'BHGuest',
        abritel: 'Abritel / VRBO', vrbo: 'VRBO', expedia: 'Expedia', hotels: 'Hotels.com',
        gites: 'Gîtes de France'
      };
      const pLabel = platformLabels[platform.toLowerCase()] || platform;
      doc.text(`Plateforme : ${pLabel}`, mg, y); y += 13;
    }
    y += 18;

    // Tableau header
    doc.rect(mg, y, W-mg*2, 28).fill(GREEN);
    doc.font('Helvetica-Bold').fontSize(9).fillColor('white')
       .text('DESCRIPTION', mg+12, y+9, { width: 300 })
       .text('MONTANT', W-mg-90, y+9, { width: 78, align: 'right' });
    y += 28;

    let alt = false;
    const addRow = (label, amount) => {
      if (parseFloat(amount||0) <= 0) return;
      if (alt) doc.rect(mg, y, W-mg*2, 26).fill('#F9FAFB');
      doc.font('Helvetica').fontSize(10).fillColor(DARK).text(label, mg+12, y+7, { width: 300 });
      doc.font('Helvetica-Bold').fontSize(10).fillColor(DARK).text(`${Number(amount).toFixed(2)} €`, W-mg-90, y+7, { width: 78, align: 'right' });
      doc.rect(mg, y+26, W-mg*2, 0.5).fill(BORDER);
      y += 26; alt = !alt;
    };
    addRow(`Séjour${nights ? ' (' + nights + ' nuit' + (nights > 1 ? 's' : '') + ')' : ''}`, rentAmount);
    addRow('Taxe de séjour', touristTaxAmount);
    addRow('Frais de ménage', cleaningFee);
    y += 18;

    // Totaux
    const totW = 220, totX = W - mg - totW;
    doc.rect(totX, y, totW, 0.5).fill(GREEN); y += 8;
    doc.font('Helvetica').fontSize(9).fillColor(GRAY)
       .text('Sous-total HT', totX, y, { width: 120 })
       .text(`${subtotal.toFixed(2)} €`, totX+120, y, { width: 88, align: 'right' });
    y += 16;
    if (vatAmount > 0) {
      doc.text(`TVA (${vatRate}%)`, totX, y, { width: 120 })
         .text(`${vatAmount.toFixed(2)} €`, totX+120, y, { width: 88, align: 'right' });
      y += 16;
    }
    doc.rect(totX, y, totW, 0.5).fill(GREEN); y += 6;
    doc.rect(totX, y, totW, 36).fill(GREEN);
    doc.font('Helvetica-Bold').fontSize(13).fillColor('white')
       .text('TOTAL TTC', totX+12, y+10, { width: 108 })
       .text(`${total.toFixed(2)} €`, totX+120, y+10, { width: 88, align: 'right' });

    // Pied de page
    doc.rect(0, H-44, W, 44).fill(GREEN);
    doc.font('Helvetica').fontSize(8).fillColor('rgba(255,255,255,0.7)')
       .text('Facture générée grâce à', mg, H-34, { width: W-mg*2, align: 'center' });
    doc.font('Helvetica-Bold').fontSize(10).fillColor('white')
       .text('Boostinghost.fr', mg, H-22, { width: W-mg*2, align: 'center' });

    doc.end();
    stream.on('finish', resolve);
    stream.on('error', reject);
  });
}

// ============================================
// POST - Renvoyer une facture par numéro
// ============================================
app.post('/api/invoice/resend',
  authenticateAny,
  requirePermission(pool, 'can_manage_invoices'),
  async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const { invoiceNumber } = req.body;
    if (!invoiceNumber) return res.status(400).json({ error: 'invoiceNumber requis' });

    // Récupérer les métadonnées
    const result = await pool.query(
      `SELECT file_path FROM invoice_download_tokens WHERE user_id = $1 AND invoice_number = $2 ORDER BY created_at DESC LIMIT 1`,
      [userId, invoiceNumber]
    );
    if (result.rows.length === 0) return res.status(404).json({ error: 'Facture introuvable' });

    let meta = {};
    try { meta = JSON.parse(result.rows[0].file_path || '{}'); } catch(e) {}

    if (!meta.clientEmail) return res.status(400).json({ error: 'Email client introuvable pour cette facture' });

    // Récupérer profil utilisateur
    const profileResult = await pool.query('SELECT * FROM users WHERE id = $1', [userId]);
    const user = profileResult.rows[0];
    if (!user) return res.status(401).json({ error: 'Non autorisé' });

    // Récupérer owner si dispo
    let ownerInfo = null;
    if (meta.ownerId) {
      const ownerRes = await pool.query('SELECT * FROM owner_clients WHERE id = $1 AND user_id = $2', [meta.ownerId, userId]);
      if (ownerRes.rows.length > 0) ownerInfo = ownerRes.rows[0];
    }

    // Régénérer le PDF
    const pdfPath = path.join(INVOICE_PDF_DIR, `${invoiceNumber}_resend.pdf`);
    
    // Reconstituer les variables pour generateInvoicePdfToFile
    const savedVars = {
      clientName: meta.clientName, clientEmail: meta.clientEmail,
      clientAddress: meta.clientAddress, clientPostalCode: meta.clientPostalCode,
      clientCity: meta.clientCity, clientSiret: meta.clientSiret,
      propertyName: meta.propertyName, propertyAddress: meta.propertyAddress,
      checkinDate: meta.checkinDate, checkoutDate: meta.checkoutDate,
      nights: meta.nights, rentAmount: meta.rentAmount,
      touristTaxAmount: meta.touristTaxAmount, cleaningFee: meta.cleaningFee,
      vatRate: meta.vatRate, invoiceNumber
    };

    await generateInvoicePdf(pdfPath, savedVars, user, ownerInfo);
    const pdfBuffer = fs.readFileSync(pdfPath);

    const checkinFr  = meta.checkinDate  ? new Date(meta.checkinDate).toLocaleDateString('fr-FR',  {day:'2-digit', month:'long', year:'numeric'}) : '';
    const checkoutFr = meta.checkoutDate ? new Date(meta.checkoutDate).toLocaleDateString('fr-FR', {day:'2-digit', month:'long', year:'numeric'}) : '';
    const emitterName = ownerInfo ? (ownerInfo.company_name || `${ownerInfo.first_name||''} ${ownerInfo.last_name||''}`.trim()) : (user.company || 'Ma Conciergerie');
    const total = parseFloat(meta.total || 0);

    await transporter.sendMail({
      from: process.env.EMAIL_FROM || 'Boostinghost <no-reply@boostinghost.fr>',
      to: meta.clientEmail,
      subject: `Facture ${invoiceNumber} – Séjour à ${meta.propertyName || ''}${meta.checkinDate ? ' du ' + new Date(meta.checkinDate).toLocaleDateString('fr-FR') : ''}`,
      html: bhEmailTemplate({
        icon: '📄',
        title: `Facture ${invoiceNumber}`,
        subtitle: `${meta.propertyName || ''}${checkinFr ? ' · du ' + checkinFr + ' au ' + checkoutFr : ''}`,
        bodyHtml: `
          <p>Bonjour <strong>${meta.clientName || ''}</strong>,</p>
          <p>Veuillez trouver ci-joint votre facture <strong>${invoiceNumber}</strong>${meta.propertyName ? ` pour votre séjour à <strong>${meta.propertyName}</strong>` : ''}${checkinFr ? ` du ${checkinFr} au ${checkoutFr}` : ''}.</p>
          <div class="success-card">📎 Votre facture PDF est jointe à cet email.</div>
          <p>Pour toute question, n'hésitez pas à nous contacter.</p>
          <p>Cordialement,<br><strong>${emitterName}</strong></p>
        `
      }),
      attachments: [{ filename: `${invoiceNumber}.pdf`, content: pdfBuffer, contentType: 'application/pdf' }]
    });

    try { fs.unlinkSync(pdfPath); } catch(e) {}
    res.json({ success: true, message: `Facture renvoyée à ${meta.clientEmail}` });
  } catch (err) {
    console.error('Erreur /api/invoice/resend:', err);
    res.status(500).json({ error: err.message || 'Erreur serveur' });
  }
});


// ============================================
// POST - Générer et télécharger PDF directement
// (données passées en body, pas de lecture BDD)
// ============================================
app.post('/api/invoice/generate-pdf',
  authenticateAny,
  async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const profileResult = await pool.query('SELECT * FROM users WHERE id = $1', [userId]);
    const user = profileResult.rows[0];
    if (!user) return res.status(401).json({ error: 'Non autorisé' });

    const data = req.body;
    const invoiceNumber = data.invoiceNumber || 'FACT-XXX';

    // Récupérer ownerInfo si ownerId fourni
    let ownerInfo = null;
    if (data.ownerId) {
      const ownerRes = await pool.query('SELECT * FROM owner_clients WHERE id = $1 AND user_id = $2', [data.ownerId, userId]);
      if (ownerRes.rows.length > 0) ownerInfo = ownerRes.rows[0];
    }

    const pdfPath = path.join(INVOICE_PDF_DIR, `${invoiceNumber}_direct.pdf`);
    await generateInvoicePdf(pdfPath, data, user, ownerInfo);

    res.setHeader('Content-Type', 'application/pdf');
    res.setHeader('Content-Disposition', `attachment; filename="${invoiceNumber}.pdf"`);
    const stream = fs.createReadStream(pdfPath);
    stream.pipe(res);
    stream.on('end', () => { try { fs.unlinkSync(pdfPath); } catch(e) {} });
  } catch (err) {
    console.error('Erreur generate-pdf:', err);
    res.status(500).json({ error: err.message || 'Erreur serveur' });
  }
});

