// ROUTES STRIPE - À COPIER DANS server.js
// Placer APRÈS les autres routes API, AVANT server.listen()
// ============================================
// WEBHOOK SMS ENTRANT — Réponses des cleaners
// ============================================
app.post('/api/sms/incoming', async (req, res) => {
  try {
    res.status(200).json({ ok: true }); // Répondre immédiatement à SMS Gateway

    const payload = req.body?.payload || req.body;
    const from = payload?.phoneNumber || payload?.from;
    const text = payload?.message || payload?.text || payload?.body;

    if (!from || !text) {
      console.log('📩 [SMS-IN] Payload incomplet:', JSON.stringify(req.body));
      return;
    }

    console.log(`📩 [SMS-IN] Message reçu de ${from}: "${text}"`);

    // Normaliser le numéro pour chercher dans la DB
    let normalizedPhone = from.replace(/\s|-/g, '');
    if (normalizedPhone.startsWith('+33')) {
      normalizedPhone = '0' + normalizedPhone.slice(3);
    }
    const phoneVariants = [from, normalizedPhone];

    // Chercher le cleaner correspondant à ce numéro
    const cleanerResult = await pool.query(
      `SELECT c.id, c.name, c.user_id
       FROM cleaners c
       WHERE c.phone = ANY($1) AND c.is_active = TRUE
       LIMIT 1`,
      [phoneVariants]
    );

    let senderName = from;
    let targetUserId = null;

    if (cleanerResult.rows.length > 0) {
      const cleaner = cleanerResult.rows[0];
      senderName = cleaner.name;
      targetUserId = cleaner.user_id;
      console.log(`📩 [SMS-IN] Cleaner identifié : ${cleaner.name} (user_id: ${cleaner.user_id})`);
    } else {
      // Pas un cleaner — chercher quand même à quel propriétaire notifier
      // (numéro inconnu → notifier tous les owners qui ont ce numéro en contact)
      console.log(`📩 [SMS-IN] Numéro inconnu : ${from}`);
    }

    if (!targetUserId) return;

    // Récupérer les tokens FCM du propriétaire
    const tokensResult = await pool.query(
      'SELECT fcm_token FROM user_fcm_tokens WHERE user_id = $1 AND fcm_token IS NOT NULL',
      [targetUserId]
    );

    if (!tokensResult.rows.length) {
      console.log(`📩 [SMS-IN] Aucun token FCM pour user ${targetUserId}`);
      return;
    }

    // Tronquer le message si trop long pour la notif
    const preview = text.length > 100 ? text.slice(0, 97) + '…' : text;

    for (const { fcm_token } of tokensResult.rows) {
      await sendNotificationLogged(
        fcm_token,
        `📩 ${senderName}`,
        preview,
        { type: 'sms_reply', from, cleanerName: senderName }
      );
    }

    console.log(`📩 [SMS-IN] Push envoyé à ${tokensResult.rows.length} token(s) pour réponse de ${senderName}`);
  } catch (err) {
    console.error('❌ [SMS-IN] Erreur:', err.message);
  }
});

// ============================================

// ============================================
// 1. FONCTION : Récupérer le Price ID Stripe
// ============================================
// ============================================
// GESTION DES PLANS STRIPE - VERSION FINALE
// ============================================

// ============================================
// 1. FONCTION : Obtenir le Price ID Stripe
// Nouveaux plans : starter / pro / agence
// Variables d'env à définir dans Render :
//   STRIPE_PRICE_STARTER_MONTHLY       = price_1T7HULFDAmyxvgFKj5pVnkbs
//   STRIPE_PRICE_STARTER_ANNUAL        = price_1T7HURFDAmyxvgFKCMsOZHFP
//   STRIPE_PRICE_STARTER_EXTRA_MONTHLY = price_1TbQ0hFDAmyxvgFKqMS4QUNV
//   STRIPE_PRICE_STARTER_EXTRA_ANNUAL  = price_1TbQ1zFDAmyxvgFK89R0shfR
//   STRIPE_PRICE_PRO_MONTHLY           = price_1TbPyvFDAmyxvgFKjIjF0EpS
//   STRIPE_PRICE_PRO_ANNUAL            = price_1T7HUnFDAmyxvgFKdfjMJiLe
//   STRIPE_PRICE_PRO_EXTRA_MONTHLY     = price_1T7HUsFDAmyxvgFKFaAzzTht
//   STRIPE_PRICE_PRO_EXTRA_ANNUAL      = price_1T7HUwFDAmyxvgFKnEdRoAWh
//   STRIPE_PRICE_AGENCE_MONTHLY        = price_1TbPzhFDAmyxvgFKhWSHzBUu
//   STRIPE_PRICE_AGENCE_ANNUAL         = price_1T7HToFDAmyxvgFKZtsSaEui
//   STRIPE_PRICE_AGENCE_EXTRA_MONTHLY  = price_1T7HTlFDAmyxvgFKLKmRpP51
//   STRIPE_PRICE_AGENCE_EXTRA_ANNUAL   = price_1T7HTiFDAmyxvgFKWR5EwhbH
// ============================================
function getPriceIdForPlan(plan) {
  const p = (plan || 'starter_monthly').toLowerCase();

  // ── Starter (15€/mois · 150€/an) ──────────────────────────────────────
  if (p === 'starter_monthly' || p === 'starter' || p === 'solo_monthly' || p === 'solo')
    return process.env.STRIPE_PRICE_STARTER_MONTHLY || 'price_1T7HULFDAmyxvgFKj5pVnkbs';
  if (p === 'starter_annual' || p === 'solo_annual')
    return process.env.STRIPE_PRICE_STARTER_ANNUAL  || 'price_1T7HURFDAmyxvgFKCMsOZHFP';
  if (p === 'starter_extra_monthly')
    return process.env.STRIPE_PRICE_STARTER_EXTRA_MONTHLY || 'price_1TbQ0hFDAmyxvgFKqMS4QUNV';
  if (p === 'starter_extra_annual')
    return process.env.STRIPE_PRICE_STARTER_EXTRA_ANNUAL  || 'price_1TbQ1zFDAmyxvgFK89R0shfR';

  // ── Pro (49€/mois · 490€/an) ──────────────────────────────────────────
  if (p === 'pro_monthly' || p === 'standard_monthly' || p === 'standard')
    return process.env.STRIPE_PRICE_PRO_MONTHLY     || 'price_1TbPyvFDAmyxvgFKjIjF0EpS';
  if (p === 'pro_annual' || p === 'standard_annual')
    return process.env.STRIPE_PRICE_PRO_ANNUAL      || 'price_1T7HUnFDAmyxvgFKdfjMJiLe';
  if (p === 'pro_extra_monthly' || p === 'standard_extra_monthly')
    return process.env.STRIPE_PRICE_PRO_EXTRA_MONTHLY || 'price_1T7HUsFDAmyxvgFKFaAzzTht';
  if (p === 'pro_extra_annual' || p === 'standard_extra_annual')
    return process.env.STRIPE_PRICE_PRO_EXTRA_ANNUAL  || 'price_1T7HUwFDAmyxvgFKnEdRoAWh';

  // ── Agence (299€/mois · 2990€/an) ────────────────────────────────────
  if (p === 'agence_monthly' || p === 'business_monthly')
    return process.env.STRIPE_PRICE_AGENCE_MONTHLY   || 'price_1TbPzhFDAmyxvgFKhWSHzBUu';
  if (p === 'agence_annual' || p === 'business_annual')
    return process.env.STRIPE_PRICE_AGENCE_ANNUAL    || 'price_1T7HToFDAmyxvgFKZtsSaEui';
  if (p === 'agence_extra_monthly')
    return process.env.STRIPE_PRICE_AGENCE_EXTRA_MONTHLY || 'price_1T7HTlFDAmyxvgFKLKmRpP51';
  if (p === 'agence_extra_annual')
    return process.env.STRIPE_PRICE_AGENCE_EXTRA_ANNUAL  || 'price_1T7HTiFDAmyxvgFKWR5EwhbH';

  // ── SMS Options ────────────────────────────────────────────────────────
  if (p === 'sms_starter')
    return process.env.STRIPE_PRICE_SMS_STARTER || 'price_1TbR8cFDAmyxvgFKyJkpmWFk';
  if (p === 'sms_pro')
    return process.env.STRIPE_PRICE_SMS_PRO     || 'price_1TbRBrFDAmyxvgFKqmlSIhze';
  if (p === 'sms_agence')
    return process.env.STRIPE_PRICE_SMS_AGENCE  || 'price_1TbRCJFDAmyxvgFKrzzmBuon';

  // ── Droits par profil (Pro uniquement — 5€/mois) ─────────────────────────
  if (p === 'droits_par_profil')
    return process.env.STRIPE_PRICE_DROITS_PAR_PROFIL || 'price_1TbRgXFDAmyxvgFKYcAOyaZK';

  console.warn(`⚠️ Plan inconnu: ${plan} — fallback starter_monthly`);
  return process.env.STRIPE_PRICE_STARTER_MONTHLY || 'price_1T7HULFDAmyxvgFKj5pVnkbs';
}

// ============================================
// 1b. FONCTION : Récupérer le nom du plan depuis un Price ID
// ============================================
function getPlanFromPriceId(priceId) {
  if (!priceId) return 'starter_monthly';

  const MAP = {
    // Starter
    [process.env.STRIPE_PRICE_STARTER_MONTHLY        || 'price_1T7HULFDAmyxvgFKj5pVnkbs']: 'starter_monthly',
    [process.env.STRIPE_PRICE_STARTER_ANNUAL         || 'price_1T7HURFDAmyxvgFKCMsOZHFP']: 'starter_annual',
    [process.env.STRIPE_PRICE_STARTER_EXTRA_MONTHLY  || 'price_1TbQ0hFDAmyxvgFKqMS4QUNV']: 'starter_extra_monthly',
    [process.env.STRIPE_PRICE_STARTER_EXTRA_ANNUAL   || 'price_1TbQ1zFDAmyxvgFK89R0shfR']: 'starter_extra_annual',
    // Pro
    [process.env.STRIPE_PRICE_PRO_MONTHLY            || 'price_1TbPyvFDAmyxvgFKjIjF0EpS']: 'pro_monthly',
    [process.env.STRIPE_PRICE_PRO_ANNUAL             || 'price_1T7HUnFDAmyxvgFKdfjMJiLe']: 'pro_annual',
    [process.env.STRIPE_PRICE_PRO_EXTRA_MONTHLY      || 'price_1T7HUsFDAmyxvgFKFaAzzTht']: 'pro_extra_monthly',
    [process.env.STRIPE_PRICE_PRO_EXTRA_ANNUAL       || 'price_1T7HUwFDAmyxvgFKnEdRoAWh']: 'pro_extra_annual',
    // Agence
    [process.env.STRIPE_PRICE_AGENCE_MONTHLY         || 'price_1TbPzhFDAmyxvgFKhWSHzBUu']: 'agence_monthly',
    [process.env.STRIPE_PRICE_AGENCE_ANNUAL          || 'price_1T7HToFDAmyxvgFKZtsSaEui']: 'agence_annual',
    [process.env.STRIPE_PRICE_AGENCE_EXTRA_MONTHLY   || 'price_1T7HTlFDAmyxvgFKLKmRpP51']: 'agence_extra_monthly',
    [process.env.STRIPE_PRICE_AGENCE_EXTRA_ANNUAL    || 'price_1T7HTiFdAmyxvgFKWR5EwhbH']: 'agence_extra_annual',
    // SMS options
    [process.env.STRIPE_PRICE_SMS_STARTER            || 'price_1TbR8cFDAmyxvgFKyJkpmWFk']: 'sms_starter',
    [process.env.STRIPE_PRICE_SMS_PRO                || 'price_1TbRBrFDAmyxvgFKqmlSIhze']: 'sms_pro',
    [process.env.STRIPE_PRICE_SMS_AGENCE             || 'price_1TbRCJFDAmyxvgFKrzzmBuon']: 'sms_agence',
    // Droits par profil
    [process.env.STRIPE_PRICE_DROITS_PAR_PROFIL      || 'price_1TbRgXFDAmyxvgFKYcAOyaZK']: 'droits_par_profil',
  };

  const found = MAP[priceId];
  if (found) return found;
  console.warn(`⚠️ Price ID inconnu: ${priceId} — fallback starter_monthly`);
  return 'starter_monthly';
}

// ============================================
// 2. FONCTION : Extraire le nom de base du plan
// ============================================
function getBasePlanName(plan) {
  const p = (plan || 'starter').toLowerCase();
  // Anciens noms → nouveaux (migration)
  if (p.includes('agence') || p.includes('business')) return 'agence';
  if (p.includes('pro') || p.includes('standard'))    return 'pro';
  if (p.includes('starter') || p.includes('solo'))    return 'starter';
  return 'starter';
}

// ============================================
// 3. FONCTION : Calculer le montant de base du plan (en euros)
// ============================================
function getPlanAmount(plan) {
  const basePlan = getBasePlanName(plan);
  const isAnnual = (plan || '').toLowerCase().includes('annual');
  // Prix lancement (200 premiers) — à terme géré via un flag is_launch en DB
  const prices = {
    starter: { monthly: 15, annual: 150 },
    pro:     { monthly: 49, annual: 490 },
    agence:  { monthly: 299, annual: 2990 },
  };
  return (prices[basePlan] || prices.starter)[isAnnual ? 'annual' : 'monthly'];
}

// ============================================
// 4. FONCTION : Nom d'affichage du plan
// ============================================
function getPlanDisplayName(plan) {
  const basePlan = getBasePlanName(plan);
  return { starter: 'Starter', pro: 'Pro', agence: 'Agence' }[basePlan] || 'Starter';
}

// ============================================
// 5. FONCTION : Limites du plan (logements)
// ============================================
function getPlanLimits(plan) {
  const basePlan = getBasePlanName(plan);
  const isAnnual = (plan || '').toLowerCase().includes('annual');
  const limits = {
    starter: { included: 1,  max: 3,   extraPrice: 9, extraPriceAnnual: 90  },
    pro:     { included: 4,  max: 50,  extraPrice: 7, extraPriceAnnual: 70  },
    agence:  { included: 51, max: 9999,extraPrice: 5, extraPriceAnnual: 50  },
  };
  return limits[basePlan] || limits.starter;
}

// ============================================
// PLAN_FEATURES — config centralisée des permissions par plan
// Utilisé par requireFeature() middleware
// ============================================
const PLAN_FEATURES = {
  // Disponible pour tous
  calendar:                  ['starter', 'pro', 'agence'],
  channex_sync:              ['starter', 'pro', 'agence'],
  ical:                      ['starter', 'pro', 'agence'],
  stripe_payments:           ['starter', 'pro', 'agence'],
  cautions:                  ['starter', 'pro', 'agence'], // starter: 3% com, pro/agence: sans com
  messaging_ai:              ['starter', 'pro', 'agence'],
  cleaning_basic:            ['starter', 'pro', 'agence'],
  welcome_book:              ['starter', 'pro', 'agence'],
  app_mobile:                ['starter', 'pro', 'agence'],
  bhguest:                   ['starter', 'pro', 'agence'],
  pricing_rules_basic:       ['starter', 'pro', 'agence'],
  reports_basic:             ['starter', 'pro', 'agence'],
  contracts_rental:          ['starter', 'pro', 'agence'],
  push_notifications:        ['starter', 'pro', 'agence'],

  // Pro + Agence uniquement
  cautions_no_commission:    ['pro', 'agence'],
  facturation_proprietaires: ['pro', 'agence'],
  invoices_clients:          ['pro', 'agence'],
  attestation_conciergerie:  ['pro', 'agence'],
  cleaning_advanced:         ['pro', 'agence'],
  sous_comptes:              ['pro', 'agence'],
  reports_advanced:          ['pro', 'agence'],
  pricing_rules_advanced:    ['pro', 'agence'],

  // Options payantes Pro (vérifier sms_enabled en DB)
  sms:                       ['pro', 'agence'], // option pour starter aussi mais vérif séparée
  droits_par_profil:         ['pro', 'agence'], // option +5€/mois pour Pro

  // Agence uniquement
  mode_agence:               ['agence'],
  multi_comptes_clients:     ['agence'],
  support_prioritaire:       ['agence'],
};

// ============================================
// requireFeature(feature) — middleware de vérification plan
// Usage: app.get('/api/...', authenticateAny, requireFeature('facturation_proprietaires'), ...)
// ============================================
function requireFeature(feature) {
  return async function(req, res, next) {
    try {
      const userId = req.user?.isSubAccount ? req.user.parentUserId : req.user?.id;
      if (!userId) return res.status(403).json({ error: 'Non authentifié', featureBlocked: true });

      const allowedPlans = PLAN_FEATURES[feature];
      if (!allowedPlans) {
        console.warn(`⚠️ [requireFeature] Feature inconnue: ${feature} — accès autorisé par défaut`);
        return next();
      }

      const subResult = await pool.query(
        `SELECT plan_type, status, trial_end_date, droits_enabled FROM subscriptions
         WHERE user_id = $1 ORDER BY created_at DESC LIMIT 1`,
        [userId]
      );
      const sub = subResult.rows[0];
      if (!sub) return res.status(403).json({ error: 'Aucun abonnement', featureBlocked: true, feature });

      const isTrial = sub.status === 'trial' || sub.status === 'trialing';
      const trialValid = isTrial && sub.trial_end_date && new Date() < new Date(sub.trial_end_date);
      if (trialValid) return next();

      const basePlan = getBasePlanName(sub.plan_type);
      if (!allowedPlans.includes(basePlan)) {
        return res.status(403).json({
          error: 'Cette fonctionnalité nécessite un plan supérieur.',
          featureBlocked: true, feature,
          requiredPlans: allowedPlans, currentPlan: basePlan, upgradeTo: allowedPlans[0]
        });
      }

      // Droits par profil : Pro doit avoir souscrit l'option, Agence = toujours inclus
      if (feature === 'droits_par_profil' && basePlan === 'pro' && !sub.droits_enabled) {
        return res.status(403).json({
          error: "L'option \"Droits par profil\" n'est pas activée (5€/mois).",
          featureBlocked: true, feature,
          optionRequired: true, optionPrice: '5€/mois',
          upgradeAction: '/api/billing/droits/subscribe'
        });
      }

      next();
    } catch(e) {
      console.error('requireFeature:', e.message);
      res.status(500).json({ error: 'Erreur serveur' });
    }
  };
}

// ============================================
// 6. FONCTION : Calculer le coût total
// ============================================
function calculateTotalCost(plan, propertyCount) {
  const basePlan = getBasePlanName(plan);
  const isAnnual = (plan || '').toLowerCase().includes('annual');
  const limits = getPlanLimits(basePlan);
  
  const basePrice = getPlanAmount(plan);
  const extraCount = Math.max(0, propertyCount - limits.included);
  
  let extraPrice = 0;
  if (extraCount > 0 && limits.extraPrice) {
    extraPrice = extraCount * (isAnnual ? limits.extraPriceAnnual : limits.extraPrice);
  }
  
  return basePrice + extraPrice;
}

// ============================================
// POST /api/billing/create-checkout-session
// Créer une session de paiement Stripe
// ============================================
app.post('/api/billing/create-checkout-session', async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) {
      return res.status(401).json({ error: 'Non autorisé' });
    }

    if (!stripe) {
      return res.status(500).json({ error: 'Stripe non configuré' });
    }

    // Validation du plan
    const { plan } = req.body || {};
    if (!plan) {
      return res.status(400).json({ 
        error: 'Plan requis',
        validPlans: ['solo_monthly', 'solo_annual', 'standard_monthly', 'standard_annual', 'pro_monthly', 'pro_annual']
      });
    }

    // ✅ Plans valides : starter, pro, agence (+ anciens noms pour compatibilité)
    const validPlans = [
      'starter_monthly', 'starter_annual',
      'pro_monthly', 'pro_annual',
      'agence_monthly', 'agence_annual',
      // Anciens noms acceptés pour compatibilité ascendante
      'solo_monthly', 'solo_annual',
      'standard_monthly', 'standard_annual',
    ];
    
    const planLower = plan.toLowerCase();
    if (!validPlans.includes(planLower)) {
      return res.status(400).json({ 
        error: 'Plan invalide',
        received: plan,
        validPlans: validPlans
      });
    }

    // Obtenir le Price ID de base
    const priceId = getPriceIdForPlan(plan);
    if (!priceId) {
      console.error(`❌ Aucun Price ID trouvé pour le plan: ${plan}`);
      return res.status(400).json({ 
        error: 'Plan non configuré dans Stripe',
        hint: `Vérifiez les variables STRIPE_PRICE_* dans vos variables d'environnement`
      });
    }

    // Logements supplémentaires
    const { extraProps = 0 } = req.body;
    const extraCount = Math.max(0, parseInt(extraProps) || 0);
    const isAnnual = plan.includes('annual');
    const basePlanName = getBasePlanName(plan);

    // Valider le nombre de logements extra selon le plan
    const planLimits = { starter: 2, pro: 46, agence: 9999 }; // max extra = max_total - inclus
    const maxExtra = planLimits[basePlanName] || 0;
    const cappedExtra = Math.min(extraCount, maxExtra);

    // Construire les line_items (plan de base + extra si besoin)
    const lineItems = [{ price: priceId, quantity: 1 }];
    if (cappedExtra > 0) {
      const extraPriceId = getPriceIdForPlan(`${basePlanName}_extra_${isAnnual ? 'annual' : 'monthly'}`);
      if (extraPriceId) {
        lineItems.push({ price: extraPriceId, quantity: cappedExtra });
      }
    }

    console.log('✅ Création session Stripe:', {
      user: user.email, userId: user.id,
      plan, priceId, extraProps: cappedExtra, lineItems: lineItems.length
    });

    const appUrl = process.env.APP_URL || 'https://boostinghost.fr';

    const session = await stripe.checkout.sessions.create({
      mode: 'subscription',
      payment_method_types: ['card'],
      line_items: lineItems,
      subscription_data: {
        metadata: {
          userId: user.id.toString(),
          plan: plan,
          planDisplay: getPlanDisplayName(plan),
          extraProps: String(cappedExtra)
        }
      },
      customer_email: user.email,
      client_reference_id: user.id.toString(),
      success_url: `${appUrl}/settings-account.html?tab=subscription&success=true`,
      cancel_url: `${appUrl}/pricing.html?cancelled=true`,
      locale: 'fr',
      // Permettre la modification de la quantité dans le checkout
      allow_promotion_codes: true
    });

    console.log('✅ Session créée avec succès:', session.id);

    res.json({ 
      url: session.url,
      sessionId: session.id
    });

  } catch (err) {
    console.error('❌ Erreur create-checkout-session:', err);
    console.error('Stack:', err.stack);
    
    res.status(500).json({ 
      error: 'Impossible de créer la session de paiement',
      details: process.env.NODE_ENV === 'development' ? err.message : undefined
    });
  }
});


