app.post('/api/manual-reservations/delete', async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) {
      console.log('❌ Suppression refusée : utilisateur non authentifié');
      return res.status(401).json({ error: 'Non autorisé' });
    }

    const { propertyId, uid } = req.body || {};
    console.log('🗑 Demande de suppression reçue :', { userId: user.id, propertyId, uid });

    if (!propertyId || !uid) {
      return res.status(400).json({ error: 'propertyId et uid sont requis' });
    }

    const property = PROPERTIES.find(p => p.id === propertyId && p.userId === user.id);
    if (!property) {
      return res.status(404).json({ error: 'Logement non trouvé' });
    }

    // ✅ SUPPRIMER DE LA DB EN PREMIER (source de vérité)
    let deleted = false;
    let deletedRow = null;
    try {
      const deleteResult = await pool.query(
        'DELETE FROM reservations WHERE uid = $1 AND user_id = $2 RETURNING *',
        [uid, user.id]
      );
      
      deleted = deleteResult.rowCount > 0;
      if (deleteResult.rows[0]) deletedRow = deleteResult.rows[0];
      
      if (deleted) {
        console.log(`✅ Réservation ${uid} supprimée de PostgreSQL`);
        
        // 📩 ENVOYER NOTIFICATION D'ANNULATION (pas pour les blocages manuels)
        const isBlockDeletion = deleteResult.rows[0] && (deleteResult.rows[0].source === 'BLOCK' || (deleteResult.rows[0].uid || '').startsWith('block_') || deleteResult.rows[0].reservation_type === 'block');
        if (!isBlockDeletion && await shouldSendNotification(user.id, 'notif_reservation_cancelled')) {
        try {
          const deletedReservation = deleteResult.rows[0];
          
          const tokensResult = await pool.query(
            'SELECT fcm_token, device_type FROM user_fcm_tokens WHERE user_id = $1',
            [user.id]
          );
          
          if (tokensResult.rows.length > 0) {
            const cancelDate = new Date(deletedReservation.start_date).toLocaleDateString('fr-FR', {
              day: 'numeric',
              month: 'short'
            });
            
            for (const tokenRow of tokensResult.rows) {
              await sendNotificationLogged(
                tokenRow.fcm_token,
                '❌ Réservation annulée',
                `${cleanGuestName(deletedReservation.guest_name, deletedReservation.source)} · ${displayName(property)} · ${cancelDate}`,
                {
                  type: 'reservation_cancelled',
                  reservation_id: uid,
                  property_name: displayName(property)
                }
              );
              
              console.log(`📩 Notification annulation envoyée au ${tokenRow.device_type}`);
            }
          }

          // ✅ Notif sous-comptes : annulation
          try {
            const cancelDate = new Date(deletedReservation.start_date).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' });
            await sendNotificationToSubAccountsOf(
              user.id, 'can_view_calendar',
              '❌ Réservation annulée — ' + displayName(property),
              cleanGuestName(deletedReservation.guest_name, deletedReservation.source) + ' · ' + displayName(property) + ' · ' + cancelDate,
              { type: 'reservation_cancelled', reservation_id: uid },
              'notif_sub_reservation_cancelled'
            );
          } catch(_e) { console.error('Notif sous-comptes annulation delete:', _e.message); }

        } catch (notifError) {
          console.error('❌ Erreur notification annulation:', notifError.message);
        }
        } // end shouldSendNotification
      } else {
        console.log(`⚠️ Réservation ${uid} non trouvée dans PostgreSQL`);
      }
    } catch (dbError) {
      console.error('❌ Erreur suppression DB:', dbError.message);
      return res.status(500).json({ error: 'Erreur lors de la suppression' });
    }

    // ✅ NETTOYER MANUAL_RESERVATIONS (si existe)
    if (MANUAL_RESERVATIONS[propertyId]) {
      const beforeLength = MANUAL_RESERVATIONS[propertyId].length;
      MANUAL_RESERVATIONS[propertyId] = MANUAL_RESERVATIONS[propertyId].filter(r => r.uid !== uid);
      const afterLength = MANUAL_RESERVATIONS[propertyId].length;
      
      if (beforeLength > afterLength) {
        console.log(`✅ Supprimé de MANUAL_RESERVATIONS (${beforeLength} → ${afterLength})`);
      }
    }

    // ✅ NETTOYER reservationsStore (si existe)
    if (reservationsStore.properties && reservationsStore.properties[propertyId]) {
      const beforeLength = reservationsStore.properties[propertyId].length;
      reservationsStore.properties[propertyId] = 
        reservationsStore.properties[propertyId].filter(r => r.uid !== uid);
      const afterLength = reservationsStore.properties[propertyId].length;
      
      if (beforeLength > afterLength) {
        console.log(`✅ Supprimé de reservationsStore (${beforeLength} → ${afterLength})`);
      }
    }

    // ✅ Si pas trouvé dans reservations, chercher dans bhguest_holds (uid = hold_{id})
    if (!deleted && uid.startsWith('hold_')) {
      try {
        const holdId = uid.replace('hold_', '');
        const holdResult = await pool.query(
          `UPDATE bhguest_holds SET status = 'cancelled'
           WHERE id = $1 AND user_id = $2 AND status IN ('pending','active')
           RETURNING id, property_id, checkin, checkout`,
          [holdId, user.id]
        );
        if (holdResult.rowCount > 0) {
          deleted = true;
          deletedRow = {
            start_date: holdResult.rows[0].checkin,
            end_date:   holdResult.rows[0].checkout
          };
          console.log(`✅ Hold BHGuest ${uid} annulé dans bhguest_holds`);
        } else {
          console.log(`⚠️ Hold ${uid} non trouvé ou déjà annulé dans bhguest_holds`);
        }
      } catch (holdErr) {
        console.error('❌ Erreur annulation hold:', holdErr.message);
      }
    }

    // ✅ Répondre avec succès (même si pas dans les caches)
    if (deleted) {
      // Nettoyer reservationsStore des holds mémoire
      if (reservationsStore.properties && reservationsStore.properties[propertyId]) {
        reservationsStore.properties[propertyId] =
          reservationsStore.properties[propertyId].filter(r => r.uid !== uid);
      }
      // Notifier le front via Socket.io pour rafraîchissement immédiat
      if (io) {
        io.to('user_' + user.id).emit('calendar:block_removed', { uid, propertyId });
      }
      // ✅ Channex sync — libérer les dates de la résa supprimée
      setImmediate(async () => {
        try {
          const targetDates = [];
          if (deletedRow?.start_date && deletedRow?.end_date) {
            const d = new Date(deletedRow.start_date);
            const end = new Date(deletedRow.end_date);
            while (d < end) { targetDates.push(d.toISOString().split('T')[0]); d.setDate(d.getDate() + 1); }
          }
          await triggerChannexAvailabilitySync(propertyId, targetDates.length > 0 ? targetDates : null);
          syncAllCalendars();
          if (io) {
            io.to('user_' + user.id).emit('reservations:updated', { propertyId });
          }
        } catch (bgErr) {
          console.error('❌ Erreur background sync après suppression:', bgErr.message);
        }
      });
      
      return res.status(200).json({
        success: true,
        message: 'Réservation supprimée'
      });
    } else {
      return res.status(404).json({
        error: 'Réservation non trouvée'
      });
    }

  } catch (err) {
    console.error('❌ Erreur suppression réservation:', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});
