// POST — envoyer un template manuellement sur une conversation
app.post('/api/message-templates/:id/send', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.id;
    const { conversation_id } = req.body;
    if (!conversation_id) return res.status(400).json({ error: 'conversation_id requis' });

    const tmpl = await pool.query('SELECT * FROM message_templates WHERE id = $1 AND user_id = $2', [req.params.id, userId]);
    if (!tmpl.rows[0]) return res.status(404).json({ error: 'Template non trouvé' });

    const conv = await pool.query('SELECT * FROM conversations WHERE id = $1 AND user_id = $2', [conversation_id, userId]);
    if (!conv.rows[0]) return res.status(404).json({ error: 'Conversation non trouvée' });

    const { sendBookingMessage } = require('./channex');
    const c = conv.rows[0];

    // Remplacer les variables dans le message
    const guestFirst = (c.guest_first_name || c.guest_name || '').split(' ')[0];
    // Récupérer les infos du logement pour les variables avancées
    const propInfo = await pool.query(
      'SELECT address, arrival_time, departure_time, access_code, wifi_name, wifi_password, practical_info, welcome_book_url FROM properties WHERE id = $1',
      [c.property_id]
    ).catch(() => ({ rows: [{}] }));
    const pi = propInfo.rows[0] || {};

    const msg = tmpl.rows[0].message
      .replace(/\{prenom\}/gi, guestFirst)
      .replace(/\{nom\}/gi, c.guest_name || '')
      .replace(/\{logement\}/gi, c.property_name || '')
      .replace(/\{arrivee\}/gi, c.reservation_start_date ? new Date(c.reservation_start_date).toLocaleDateString('fr-FR') : '')
      .replace(/\{depart\}/gi, c.reservation_end_date ? new Date(c.reservation_end_date).toLocaleDateString('fr-FR') : '')
      .replace(/\{adresse\}/gi, pi.address || '')
      .replace(/\{heure_arrivee\}/gi, pi.arrival_time || '')
      .replace(/\{heure_depart\}/gi, pi.departure_time || '')
      .replace(/\{departureTime\}/gi, pi.departure_time || '')
      .replace(/\{arrivalTime\}/gi, pi.arrival_time || '')
      .replace(/\{code_acces\}/gi, pi.access_code || '')
      .replace(/\{wifi_nom\}/gi, pi.wifi_name || '')
      .replace(/\{wifi_mdp\}/gi, pi.wifi_password || '')
      .replace(/\{instructions\}/gi, pi.practical_info || '')
      .replace(/\{livret\}/gi, pi.welcome_book_url || '');

    // Résoudre {code_serrure} (génération à la volée si nécessaire)
    if (msg.includes('{code_serrure}') || msg.includes('{lock_code}')) {
      const lockCode = await resolveOrGenerateLockCode(
        pool, c.property_id, userId,
        c.reservation_uid, c.reservation_start_date, c.reservation_end_date, c.guest_name
      );
      msg = msg.replace(/\{code_serrure\}/gi, lockCode).replace(/\{lock_code\}/gi, lockCode);
    }

    // Résoudre {caution_url} si présent
    let finalMsg = msg;
    let skipSend = false;
    if (finalMsg.includes('{caution_url}')) {
      try {
        const resRow2 = await pool.query(
          `SELECT uid FROM reservations
           WHERE property_id = $1 AND DATE(start_date) = DATE($2) AND status != 'cancelled'
           ORDER BY created_at DESC LIMIT 1`,
          [c.property_id, c.reservation_start_date]
        ).catch(() => ({ rows: [] }));
        let cautionUrl = '';
        const resUidCron = resRow2.rows[0]?.uid || null;
        if (resUidCron) {
          // Chercher par reservation_uid OU par channex_booking_id
          const dep2 = await pool.query(
            `SELECT id, checkout_url FROM deposits
             WHERE (reservation_uid = $1 OR reservation_uid = $2)
             AND status IN ('pending','authorized')
             ORDER BY created_at DESC LIMIT 1`,
            [resUidCron, c.channex_booking_id ? 'CHX_' + c.channex_booking_id : '__none__']
          ).catch(() => ({ rows: [] }));
          const dep2Row = dep2.rows[0];
          cautionUrl = dep2Row?.checkout_url
            ? await makeShortLink(pool, dep2Row.checkout_url, c.user_id, { depositId: dep2Row.id || null })
            : '';

          // ✅ Créer le deposit à la volée si absent (comme sendTemplateMessage)
          if (!cautionUrl) {
            try {
              const propD = await pool.query('SELECT * FROM properties WHERE id = $1', [c.property_id]);
              const depositAmount = parseFloat(propD.rows[0]?.deposit_amount || 0);
              if (depositAmount > 0) {
                const depositId = 'dep_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 5);
                const amountCents = Math.round(depositAmount * 100);
                const appUrl = (process.env.APP_URL || 'https://boostinghost.fr').replace(/\/$/, '');
                const stripeTarget = await getStripeForProperty(pool, c.property_id, c.user_id);
                const sessionOptions = stripeTarget.stripeAccountId ? { stripeAccount: stripeTarget.stripeAccountId } : {};
                const sessionParams = {
                  payment_method_types: ['card'],
                  mode: 'payment',
                  line_items: [{ price_data: { currency: 'eur', unit_amount: amountCents, product_data: { name: `Caution - ${propD.rows[0]?.name || c.property_id}`, description: `Réservation du ${c.reservation_start_date} au ${c.reservation_end_date}` } }, quantity: 1 }],
                  payment_intent_data: { capture_method: 'manual', metadata: { deposit_id: depositId, reservation_uid: resUidCron } }, // ⏸️ Commission BH en pause
                  metadata: { deposit_id: depositId, reservation_uid: resUidCron },
                  success_url: `${appUrl}/caution-success.html?depositId=${depositId}`,
                  cancel_url: `${appUrl}/caution-cancel.html?depositId=${depositId}`,
                };
                const session = await stripe.checkout.sessions.create(sessionParams, sessionOptions);
                await pool.query(
                  `INSERT INTO deposits (id, user_id, reservation_uid, property_id, amount_cents, status, stripe_session_id, checkout_url, created_at, updated_at)
                   VALUES ($1,$2,$3,$4,$5,'pending',$6,$7,NOW(),NOW())`,
                  [depositId, c.user_id, resUidCron, c.property_id, amountCents, session.id, session.url]
                );
                cautionUrl = await makeShortLink(pool, session.url, c.user_id, { depositId: depositId });
                await pool.query('UPDATE deposits SET stripe_session_expires_at = $1 WHERE id = $2', [new Date(session.expires_at * 1000).toISOString(), depositId]).catch(() => {});
                console.log(`✅ [CRON TPL] Deposit créé à la volée pour conv ${conversation_id}: ${depositId}`);
              }
            } catch(depErr) {
              console.warn(`⚠️ [CRON TPL] Erreur création deposit à la volée:`, depErr.message);
            }
          }
        }
        if (!cautionUrl) {
          // Si Airbnb : ne pas bloquer l'envoi, juste supprimer la variable
          const manualPlatform = (c.platform || '').toLowerCase().replace(/[_\-\s]/g, '');
          const isAirbnbManual = manualPlatform.includes('airbnb') || manualPlatform === 'abb';
          if (isAirbnbManual) {
            console.log(`ℹ️ [CRON TPL] Airbnb — {caution_url} supprimé (pas de caution BH)`);
            finalMsg = finalMsg.replace(/{caution_url}/gi, '');
          } else {
            console.warn(`⚠️ [CRON TPL] {caution_url} non résolu pour conv ${conversation_id} — message non envoyé`);
            skipSend = true;
          }
        } else {
          finalMsg = finalMsg.replace(/{caution_url}/gi, cautionUrl);
        }
      } catch(e) {
        finalMsg = finalMsg.replace(/{caution_url}/gi, '');
      }
    }

    if (!skipSend) {

    if (c.channex_booking_id) {
      try {
        await sendBookingMessage(c.channex_booking_id, finalMsg);
        console.log(`✅ [CRON TPL] Message envoyé via Channex (booking ${c.channex_booking_id})`);
      } catch(channexErr) {
        console.warn(`⚠️ [CRON TPL] Erreur Channex (non bloquant):`, channexErr.message);
      }
    }

    // Sauvegarder en DB
    const saved = await pool.query(
      `INSERT INTO messages (conversation_id, sender_type, sender_name, message, is_read, created_at)
       VALUES ($1, 'property', 'Hôte', $2, TRUE, NOW()) RETURNING *`,
      [conversation_id, finalMsg]
    );

    if (io) io.to(`conversation_${conversation_id}`).emit('new_message', saved.rows[0]);

    // Logger l'envoi
    try {
      await pool.query(
        `INSERT INTO message_template_logs
          (user_id, template_id, template_title, conversation_id, guest_name, property_name, trigger_type, message, status)
         VALUES ($1,$2,$3,$4,$5,$6,$7,$8,'sent')`,
        [userId, tmpl.rows[0].id, tmpl.rows[0].title, conversation_id,
         c.guest_name || null, c.property_name || null, 'manual', msg]
      );
    } catch(e) {}

    res.json({ success: true, message: saved.rows[0] });
    } // end if (!skipSend)
  } catch(e) {
    // Logger l'erreur
    try {
      await pool.query(
        `INSERT INTO message_template_logs (user_id, template_id, template_title, trigger_type, message, status, error_message)
         VALUES ($1,$2,$3,'manual','',$4,$5)`,
        [req.user.id, req.params.id, '', 'error', e.message]
      );
    } catch(le) {}
    res.status(500).json({ error: e.message });
  }
});

// GET — historique des logs d'envoi
// ── GET prochains envois planifiés (J+7) ───────────────────────
app.get('/api/message-template-scheduled', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.id;
    const nowParis = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Paris' }));

    // Récupérer tous les templates actifs de l'utilisateur
    const templates = await pool.query(
      `SELECT * FROM message_templates WHERE user_id = $1 AND active = TRUE
       AND trigger_type NOT IN ('on_booking')
       ORDER BY title`,
      [userId]
    );

    const scheduled = [];

    for (const tmpl of templates.rows) {
      const offsetDays = tmpl.trigger_offset_days || Math.round(Math.abs(tmpl.trigger_offset_hours || 0) / 24) || 0;
      const isBefore = tmpl.trigger_type.startsWith('before_');
      const isAfter  = tmpl.trigger_type.startsWith('after_');
      const isDepRelated = tmpl.trigger_type.includes('departure');
      const dateCol = isDepRelated ? 'reservation_end_date' : 'reservation_start_date';

      // Pour chaque jour dans J+7
      for (let d = 0; d <= 7; d++) {
        const checkDate = new Date(nowParis);
        checkDate.setDate(checkDate.getDate() + d);
        const checkDateStr = checkDate.toISOString().split('T')[0];

        // La date de réservation ciblée = checkDate ± offset
        let targetDate;
        if (isBefore) {
          const t = new Date(checkDate);
          t.setDate(t.getDate() + offsetDays);
          targetDate = t.toISOString().split('T')[0];
        } else if (isAfter) {
          const t = new Date(checkDate);
          t.setDate(t.getDate() - offsetDays);
          targetDate = t.toISOString().split('T')[0];
        } else {
          targetDate = checkDateStr;
        }

        // Construire le filtre property_ids
        const propIds = tmpl.property_ids
          ? (Array.isArray(tmpl.property_ids) ? tmpl.property_ids : (() => { try { return JSON.parse(tmpl.property_ids); } catch(e) { return []; } })())
          : (tmpl.property_id ? [tmpl.property_id] : []);
        const propFilter = propIds.length > 0
          ? `AND c.property_id IN (${propIds.map(id => `'${id.replace(/'/g,"''")}'`).join(',')})`
          : '';

        const convs = await pool.query(
          `SELECT c.id, c.guest_name, p.name as property_name, c.property_id, c.reservation_start_date,
                  COALESCE(c.reservation_end_date, c.reservation_start_date + INTERVAL '1 day') as reservation_end_date,
                  c.platform
           FROM conversations c
           LEFT JOIN properties p ON p.id = c.property_id
           WHERE c.user_id = $1
           AND DATE(c.${dateCol} AT TIME ZONE 'Europe/Paris') = $2
           AND c.status != 'cancelled'
           ${propFilter}`,
          [userId, targetDate]
        );

        for (const conv of convs.rows) {
          // Skip Airbnb si template contient {caution_url}
          if (tmpl.message && tmpl.message.includes('{caution_url}')) {
            const _plt = (conv.platform || '').toLowerCase();
            if (_plt.includes('airbnb') || _plt === 'abb') {
              console.log(`  ⏭️ Skip conv ${conv.id} : caution non applicable sur Airbnb`);
              continue;
            }
          }
          // Vérifier si déjà envoyé (anti-doublon 23h)
          const sent = await pool.query(
            `SELECT id FROM message_template_logs WHERE template_id = $1 AND conversation_id = $2 AND sent_at > NOW() - INTERVAL '23 hours' AND status = 'sent'`,
            [tmpl.id, conv.id]
          );
          if (sent.rows.length > 0) continue;

          // Vérifier si bloqué
          const blocked = await pool.query(
            `SELECT id FROM message_template_blocks WHERE template_id = $1 AND conversation_id = $2`,
            [tmpl.id, conv.id]
          );

          const TRIGGER_LABELS = {
            before_arrival: `J-${offsetDays} avant arrivée`,
            on_arrival: "Jour d'arrivée à 7h",
            after_arrival: `J+${offsetDays} après arrivée`,
            before_departure: `J-${offsetDays} avant départ`,
            on_departure: "Jour de départ à 15h",
            after_departure: `J+${offsetDays} après départ`,
          };

          scheduled.push({
            template_id: tmpl.id,
            template_title: tmpl.title,
            trigger_label: TRIGGER_LABELS[tmpl.trigger_type] || tmpl.trigger_type,
            send_date: checkDateStr,
            conversation_id: conv.id,
            guest_name: conv.guest_name,
            property_name: conv.property_name,
            platform: conv.platform,
            is_blocked: blocked.rows.length > 0,
          });
        }
      }
    }

    // Trier par date puis par nom voyageur
    scheduled.sort((a, b) => a.send_date.localeCompare(b.send_date) || (a.guest_name||'').localeCompare(b.guest_name||''));

    res.json({ scheduled });
  } catch(e) {
    console.error('❌ GET scheduled:', e.message);
    res.status(500).json({ error: e.message });
  }
});

