// ============================================
// 📨 INITIALISATION DU CRON JOB DES MESSAGES D'ARRIVÉE
// ============================================
// initArrivalMessagesCron désactivé — remplacé par les templates
// initArrivalMessagesCron(pool, io);
console.log("ℹ️ Cron arrival-messages désactivé (remplacé par templates)");

// ✅ Cron message_templates
// - before_arrival  : la veille à 7h (Europe/Paris)
// - on_arrival      : le jour J à 7h (Europe/Paris)
// - after_departure : le jour du départ à 15h (Europe/Paris)

// ============================================
// 💰 RAPPEL CAUTION J-2 (cron 9h00)
// Envoie un rappel aux voyageurs qui n'ont pas payé
// leur caution et dont l'arrivée est dans 2 jours
// ============================================
async function sendDepositReminderJ2Cron(pool, io) {
  const nowParis = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Paris' }));
  const j2 = new Date(nowParis);
  j2.setDate(j2.getDate() + 2);
  const j2Str = j2.toISOString().split('T')[0];

  console.log(`💰 [CAUTION J-2] Recherche cautions non payées pour arrivée le ${j2Str}`);

  const convs = await pool.query(
    `SELECT c.*, p.deposit_amount, p.name as property_name,
            r.uid as reservation_uid
     FROM conversations c
     LEFT JOIN properties p ON p.id = c.property_id
     LEFT JOIN reservations r ON (
       (r.channex_booking_id = c.channex_booking_id AND c.channex_booking_id IS NOT NULL)
       OR (r.property_id = c.property_id AND DATE(r.start_date) = DATE(c.reservation_start_date))
     )
     WHERE DATE(c.reservation_start_date AT TIME ZONE 'Europe/Paris') = $1
     AND c.status != 'cancelled'
     AND p.deposit_amount IS NOT NULL AND p.deposit_amount > 0
     AND NOT EXISTS (
       SELECT 1 FROM deposits d
       WHERE d.reservation_uid = r.uid
       AND d.status IN ('authorized', 'captured', 'paid')
     )
     -- Exclure Airbnb : caution geree par la plateforme
     AND COALESCE(r.ota_name, r.source, '') NOT ILIKE '%airbnb%'
     AND COALESCE(r.ota_name, r.source, '') NOT ILIKE '%ABB%'`,
    [j2Str]
  );

  if (convs.rows.length === 0) {
    console.log('✅ [CAUTION J-2] Aucune caution en attente');
    return { sent: 0, skipped: 0 };
  }

  console.log(`⚠️ [CAUTION J-2] ${convs.rows.length} caution(s) non payée(s)`);
  let sent = 0;

  for (const conv of convs.rows) {
    try {
      // Trouver un template before_arrival avec {caution_url} pour cet user/logement
      const tplResult = await pool.query(
        `SELECT * FROM message_templates
         WHERE user_id = $1 AND trigger_type = 'before_arrival' AND active = TRUE
         AND message ILIKE '%caution_url%'
         AND (property_id IS NULL OR property_id::text = $2::text
              OR (property_ids IS NOT NULL AND property_ids @> to_jsonb($2::text)))
         ORDER BY property_id NULLS LAST LIMIT 1`,
        [conv.user_id, conv.property_id]
      );

      if (tplResult.rows.length === 0) {
        console.log(`⏭️ [CAUTION J-2] Pas de template caution pour conv ${conv.id}`);
        continue;
      }

      // Vérifier anti-doublon — pas de rappel dans les 20h
      const alreadySent = await pool.query(
        `SELECT 1 FROM message_template_logs
         WHERE conversation_id = $1 AND template_id = $2
         AND sent_at > NOW() - INTERVAL '20 hours' AND status = 'sent' LIMIT 1`,
        [conv.id, tplResult.rows[0].id]
      );
      if (alreadySent.rows.length > 0) {
        console.log(`⏭️ [CAUTION J-2] Rappel déjà envoyé récemment pour conv ${conv.id}`);
        continue;
      }

      const propRow = await pool.query('SELECT * FROM properties WHERE id = $1', [conv.property_id]);
      await sendTemplateMessage(pool, io, {
        template: tplResult.rows[0],
        conv,
        property: propRow.rows[0] || {}
      });
      console.log(`✅ [CAUTION J-2] Rappel envoyé — ${conv.property_name} — ${conv.guest_name}`);
      sent++;
      await new Promise(r => setTimeout(r, 500));
    } catch(e) {
      console.error(`❌ [CAUTION J-2] Erreur conv ${conv.id}:`, e.message);
    }
  }

  console.log(`📊 [CAUTION J-2] ${sent} rappel(s) envoyé(s)`);
  return { sent, skipped: convs.rows.length - sent };
}

async function runTemplatesCron(triggerTypes) {
  try {
    // Calcul fiable de la date Paris — éviter le bug toLocaleString + toISOString
    const nowParis = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Paris' }));
    const pad = n => String(n).padStart(2, '0');
    const todayStr = `${nowParis.getFullYear()}-${pad(nowParis.getMonth()+1)}-${pad(nowParis.getDate())}`;

    const templates = await pool.query(
      `SELECT * FROM message_templates WHERE active = TRUE AND trigger_type = ANY($1)`,
      [triggerTypes]
    );
    console.log(`⏰ [TPL CRON] ${triggerTypes.join('/')} — ${templates.rows.length} template(s) actif(s)`);

    for (const tmpl of templates.rows) {
      try {
        // Calculer la date cible selon le déclencheur + offset en jours
        const offsetDays = tmpl.trigger_offset_days || Math.round(Math.abs(tmpl.trigger_offset_hours || 0) / 24) || 0;
        const isBefore = tmpl.trigger_type.startsWith('before_');
        const isAfter  = tmpl.trigger_type.startsWith('after_');
        const isOn     = tmpl.trigger_type.startsWith('on_') || tmpl.trigger_type === 'on_booking';

        let targetDate = todayStr;
        if (!isOn) {
          const d = new Date(nowParis);
          d.setDate(d.getDate() + (isBefore ? offsetDays : isAfter ? -offsetDays : 0));
          targetDate = d.toISOString().split('T')[0];
        }

        // Chercher les conversations éligibles
        const isDepRelated = tmpl.trigger_type.includes('departure') || tmpl.trigger_type === 'after_departure';
        const dateCol = isDepRelated ? 'reservation_end_date' : 'reservation_start_date';

        const convs = await pool.query(
          `SELECT c.*,
                  COALESCE(r.guest_country, '') as guest_country,
                  COALESCE(r.guest_language, '') as guest_language
           FROM conversations c
           LEFT JOIN reservations r ON (
             r.property_id = c.property_id
             AND DATE(r.start_date) = DATE(c.reservation_start_date)
             AND r.status != 'cancelled'
           )
           WHERE c.user_id = $1
           AND DATE(c.${dateCol} AT TIME ZONE 'Europe/Paris') = $2
           AND c.status != 'cancelled'
           ${(() => {
             const ids = tmpl.property_ids
               ? (Array.isArray(tmpl.property_ids) ? tmpl.property_ids : (() => { try { return JSON.parse(tmpl.property_ids); } catch(e) { return []; } })())
               : (tmpl.property_id ? [tmpl.property_id] : []);
             if (ids.length === 0) return '';
             if (ids.length === 1) return `AND c.property_id = '${ids[0].replace(/'/g,"''")}'`;
             return `AND c.property_id IN (${ids.map(id => `'${id.replace(/'/g,"''")}'`).join(',')})`;
           })()}`,
          [tmpl.user_id, targetDate]
        );

        console.log(`  Template "${tmpl.title}" → ${convs.rows.length} conversation(s) ciblée(s) pour ${targetDate}`);

        for (const conv of convs.rows) {
          // Skip Airbnb si template contient {caution_url} (Airbnb gere la caution)
          if (tmpl.message && tmpl.message.includes('{caution_url}')) {
            const convPlatform = (conv.platform || conv.channex_platform || '').toLowerCase();
            const isAirbnb = convPlatform.includes('airbnb') || convPlatform === 'abb'
              || (conv.ota_name || '').toUpperCase().includes('ABB')
              || (conv.ota_name || '').toLowerCase().includes('airbnb');
            if (isAirbnb) {
              console.log(`  ⏭️ Skip conv ${conv.id} : caution non applicable sur Airbnb`);
              continue;
            }
          }

          // Vérifier send_condition via le helper centralisé
          // ✅ Airbnb et BHGuest sont toujours exemptés de la vérification caution
          const sendCond = tmpl.send_condition || 'always';
          const condCheck = await shouldSkipForDepositCondition(pool, conv, sendCond);
          if (condCheck.skip) {
            console.log(`  ↳ Skip conv ${conv.id} : ${condCheck.reason}`);
            continue;
          }
          if (condCheck.reason) {
            console.log(`  ↳ ℹ️ Conv ${conv.id} : ${condCheck.reason} → envoi autorisé`);
          }

          // Check blocage : l'hôte a-t-il bloqué cet envoi pour cette conversation ?
          const isBlocked = await pool.query(
            `SELECT id FROM message_template_blocks WHERE template_id = $1 AND conversation_id = $2 LIMIT 1`,
            [tmpl.id, conv.id]
          );
          if (isBlocked.rows.length > 0) {
            console.log(`  ↳ Conv ${conv.id} bloquée pour template ${tmpl.id}, skip`);
            continue;
          }

          // Anti-doublon : check dans message_template_logs
          const alreadySentLog = await pool.query(
            `SELECT id FROM message_template_logs
             WHERE template_id = $1 AND conversation_id = $2
             AND sent_at > NOW() - INTERVAL '23 hours' AND status = 'sent'`,
            [tmpl.id, conv.id]
          );
          if (alreadySentLog.rows.length > 0) {
            console.log(`  ↳ Conv ${conv.id} déjà traitée (log), skip`);
            continue;
          }
          // ✅ Vérification caution pour on_arrival UNIQUEMENT
          // before_arrival = envoi de la caution elle-même → pas de vérif caution
          if (tmpl.trigger_type === 'on_arrival') {
            const platform = (conv.platform || '').toLowerCase();
            const isAirbnb = platform.includes('airbnb') || platform === 'abb';
            if (!isAirbnb) {
              try {
                // Vérifier d'abord si le logement a une caution configurée
                const propDepositRow = await pool.query(
                  `SELECT deposit_amount FROM properties WHERE id = $1`,
                  [conv.property_id]
                );
                const hasDepositConfig = propDepositRow.rows[0]?.deposit_amount > 0;

                // Si le logement n'a pas de caution configurée → pas de blocage
                if (hasDepositConfig) {
                  // Récupérer l'uid de la réservation via channex_booking_id (priorité) ou property+date
                  const resRow = await pool.query(
                    `SELECT uid FROM reservations
                     WHERE ($3::text IS NOT NULL AND channex_booking_id = $3)
                        OR (property_id = $1 AND DATE(start_date) = DATE($2) AND status != 'cancelled')
                     ORDER BY (channex_booking_id = $3) DESC NULLS LAST, created_at DESC LIMIT 1`,
                    [conv.property_id, conv.reservation_start_date, conv.channex_booking_id || null]
                  );
                  if (resRow.rows[0]) {
                    const dep = await pool.query(
                      `SELECT status FROM deposits WHERE reservation_uid = $1 ORDER BY created_at DESC LIMIT 1`,
                      [resRow.rows[0].uid]
                    ).catch(() => ({ rows: [] }));
                    const depStatus = dep.rows[0]?.status;
                    if (depStatus !== 'captured' && depStatus !== 'authorized') {
                      console.log(`  ↳ ⏭️ Caution non validée (status=${depStatus || 'aucune'}) pour conv ${conv.id} → on_arrival bloqué`);
                      continue;
                    }
                  }
                } else {
                  console.log(`  ↳ ℹ️ Logement ${conv.property_id} sans caution configurée → on_arrival autorisé`);
                }
              } catch(depErr) {
                console.warn(`  ↳ ⚠️ Erreur vérif caution conv ${conv.id}:`, depErr.message);
              }
            }
          }

          // Récupérer les infos du logement
          const propRow = await pool.query(
            `SELECT address, arrival_time, departure_time, access_code, wifi_name,
                    wifi_password, practical_info, welcome_book_url, name
             FROM properties WHERE id = $1`,
            [conv.property_id]
          );
          const property = propRow.rows[0] || {};

          await sendTemplateMessage(pool, io, {
            template: tmpl,
            conv: { ...conv, user_id: tmpl.user_id },
            property
          });
          console.log(`  ↳ ✅ Template "${tmpl.title}" envoyé → conv ${conv.id} (${conv.guest_name})`);
          await new Promise(r => setTimeout(r, 500)); // Éviter surcharge Channex
        }
      } catch(e) {
        console.warn(`  ↳ ⚠️ Erreur template ${tmpl.id}:`, e.message);
      }
    }
  } catch(e) {
    console.error('❌ [TPL CRON]', e.message);
  }
}

