// Endpoint pour sauvegarder le token FCM d'un utilisateur (principal ou sous-compte)
app.post('/api/save-token', authenticateAny, async (req, res) => {
  try {
    const { token, device_type } = req.body;
    const deviceType = device_type || 'ios';

    if (!token) {
      return res.status(400).json({ error: 'Token manquant' });
    }

    // ✅ Distinguer compte principal et sous-compte
    if (req.user.isSubAccount) {
      // --- SOUS-COMPTE ---
      const subAccountId = req.user.subAccountId;
      if (!subAccountId) {
        return res.status(400).json({ error: 'SubAccount ID manquant' });
      }

      console.log(`📱 [sous-compte ${subAccountId}] Enregistrement token FCM (${deviceType})`);

      // Le token FCM peut déjà exister (même iPhone = même token pour compte principal et sous-compte)
      // On utilise ON CONFLICT sur fcm_token pour mettre à jour la ligne existante
      await pool.query(
        `INSERT INTO user_fcm_tokens (sub_account_id, user_id, fcm_token, device_type, created_at, updated_at)
         VALUES ($1, NULL, $2, $3, NOW(), NOW())
         ON CONFLICT (fcm_token)
         DO UPDATE SET
           sub_account_id = EXCLUDED.sub_account_id,
           updated_at = NOW()`,
        [subAccountId, token, deviceType]
      );

      console.log(`✅ Token FCM enregistré pour sous-compte ${subAccountId}`);
      return res.json({ success: true, message: 'Token sauvegardé (sous-compte)' });

    } else {
      // --- COMPTE PRINCIPAL ---
      const userId = req.user.userId || req.user.id;
      if (!userId) {
        return res.status(400).json({ error: 'User ID manquant' });
      }

      const { device_id: deviceId } = req.body;
      console.log(`📱 [user ${userId}] Enregistrement token FCM (${deviceType}, device_id: ${deviceId || 'non fourni'})`);

      if (deviceId) {
        // ✅ Stratégie avec device_id : 1 ligne par appareil physique, sans doublon
        // Étape 1 : si ce token FCM appartient déjà à un autre device_id du même user → on met à jour ce device_id
        await pool.query(
          `UPDATE user_fcm_tokens SET device_id = $1, device_type = $2, updated_at = NOW()
           WHERE fcm_token = $3 AND user_id = $4 AND (device_id IS NULL OR device_id != $1)`,
          [deviceId, deviceType, token, userId]
        ).catch(() => {});

        // Étape 2 : upsert sur (user_id, device_id) → un seul enregistrement par appareil
        await pool.query(
          `INSERT INTO user_fcm_tokens (user_id, fcm_token, device_type, device_id, created_at, updated_at)
           VALUES ($1, $2, $3, $4, NOW(), NOW())
           ON CONFLICT (user_id, device_id) WHERE user_id IS NOT NULL AND device_id IS NOT NULL
           DO UPDATE SET fcm_token = EXCLUDED.fcm_token, device_type = EXCLUDED.device_type, updated_at = NOW()`,
          [userId, token, deviceType, deviceId]
        );
      } else {
        // Fallback sans device_id (anciens clients) : ON CONFLICT sur fcm_token uniquement
        await pool.query(
          `INSERT INTO user_fcm_tokens (user_id, fcm_token, device_type, created_at, updated_at)
           VALUES ($1, $2, $3, NOW(), NOW())
           ON CONFLICT (fcm_token)
           DO UPDATE SET user_id = EXCLUDED.user_id, device_type = EXCLUDED.device_type, updated_at = NOW()`,
          [userId, token, deviceType]
        );
      }

      console.log(`✅ Token FCM enregistré pour user ${userId} (device_id: ${deviceId || 'N/A'})`);

      // Nettoyage automatique : garder max 3 tokens par user (les plus récents)
      await pool.query(
        `DELETE FROM user_fcm_tokens
         WHERE user_id = $1
         AND sub_account_id IS NULL
         AND id NOT IN (
           SELECT id FROM user_fcm_tokens
           WHERE user_id = $1 AND sub_account_id IS NULL
           ORDER BY updated_at DESC
           LIMIT 3
         )`,
        [userId]
      ).catch(e => console.warn('⚠️ Nettoyage tokens FCM:', e.message));

      return res.json({ success: true, message: 'Token sauvegardé' });
    }

  } catch (error) {
    console.error('❌ Erreur sauvegarde token:', error);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

