// SUPPRESSION DE COMPTE
// ============================================
app.delete('/api/account/delete', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.id;
    console.log(`🗑️ Suppression compte demandée par user ${userId}`);

    // Récupérer l'email avant suppression pour l'email de confirmation
    const userRow = await pool.query('SELECT email, first_name FROM users WHERE id = $1', [userId]);
    const userEmail = userRow.rows[0]?.email;
    const userName = userRow.rows[0]?.first_name || 'Utilisateur';

    await pool.query('DELETE FROM user_fcm_tokens WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM sub_account_permissions WHERE sub_account_id IN (SELECT id FROM sub_accounts WHERE parent_user_id = $1)', [userId]);
    await pool.query('DELETE FROM sub_account_properties WHERE sub_account_id IN (SELECT id FROM sub_accounts WHERE parent_user_id = $1)', [userId]);
    await pool.query('DELETE FROM sub_accounts WHERE parent_user_id = $1', [userId]);
    await pool.query('DELETE FROM cleaning_checklists WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM cleaners WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM deposits WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM payments WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM messages WHERE conversation_id IN (SELECT id FROM conversations WHERE user_id = $1)', [userId]);
    await pool.query('DELETE FROM conversations WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM reservations WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM properties WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM invoices WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM subscriptions WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM users WHERE id = $1', [userId]);

    console.log(`✅ Compte ${userId} supprimé`);

    // Envoyer email de confirmation de suppression
    if (userEmail) {
      try {
        await sendEmail({
          from: `Boostinghost <${process.env.EMAIL_FROM}>`,
          to: userEmail,
          subject: 'Votre compte Boostinghost a été supprimé',
          html: bhEmailTemplate({
            icon: '🗑️',
            title: 'Compte supprimé',
            tag: 'Confirmation de suppression',
            bodyHtml: `
              <p>Bonjour <strong>${userName}</strong>,</p>
              <p>Votre compte Boostinghost associé à l'adresse <strong>${userEmail}</strong> a bien été supprimé le ${new Date().toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' })}.</p>
              <p>Toutes vos données ont été définitivement effacées de nos serveurs conformément à votre demande.</p>
              <div class="danger-card">Si vous n'êtes pas à l'origine de cette action, contactez-nous immédiatement à <a href="mailto:support@boostinghost.fr" style="color:#1A7A5E;">support@boostinghost.fr</a>.</div>
            `,
            footerNote: 'Cet email confirme la suppression définitive de votre compte.'
          })
        });
        console.log(`📧 Email confirmation suppression envoyé à ${userEmail}`);
      } catch(emailErr) {
        console.warn('⚠️ Email confirmation suppression échoué:', emailErr.message);
      }
    }

    res.json({ success: true });
  } catch (err) {
    console.error('❌ Erreur suppression compte:', err);
    res.status(500).json({ error: 'Erreur lors de la suppression du compte' });
  }
});

