app.post('/api/mandat/send', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const {
      // Conciergerie
      companyName, companyLegal, companyAddress, companySiret,
      companyRep, companyEmail, companyPhone, companyLogoUrl,
      companyFreeTitle, companyFreeValue,
      // Propriétaire
      ownerFirstName, ownerLastName, ownerAddress, ownerEmail, ownerPhone,
      ownerDOB, ownerSiren,
      // Bien
      propAddress, propType, propCapacity, minStay, maxStay,
      animals, smoking, parties, checkinTime, checkoutTime,
      // Missions
      missions, urgenceLimit, extrasFacturables,
      // Rémunération
      remuType, commissionRate, commissionBase,
      forfaitMensuel, forfaitResa, mixteRate, mixteForfait,
      tva, tarifPreavis, reversement,
      // Conditions
      dureeType, dateDebut, dureeMois, renouvellement, preavis,
      exclusivite, respPlafond, juridiction, confidentialite,
      clausesPersonnalisees,
      // Signature
      signatureData, signatureDate,
      // Token lié
      reservationUid
    } = req.body;

    if (!ownerEmail) return res.status(400).json({ error: 'Email du propriétaire requis' });
    if (!ownerFirstName || !ownerLastName) return res.status(400).json({ error: 'Nom du propriétaire requis' });

    const fmtDate = (d) => d ? new Date(d).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' }) : '—';
    const fmtDateShort = (d) => d ? new Date(d).toLocaleDateString('fr-FR') : '—';

    const propTypeLabels = { appartement: 'Appartement', maison: 'Maison', studio: 'Studio', villa: 'Villa', chambre: 'Chambre', gite: 'Gîte / Chalet', autre: 'Autre' };
    const remuLabels = {
      commission: `${commissionRate || '—'}% sur les revenus ${commissionBase === 'ttc' ? 'TTC' : 'HT'}`,
      forfait_mensuel: `Forfait mensuel : ${forfaitMensuel || '—'} €`,
      forfait_resa: `Forfait par réservation : ${forfaitResa || '—'} €`,
      mixte: `${mixteRate || '—'}% + ${mixteForfait || '—'} €/mois`,
      carte: 'Prestations à la carte'
    };
    const tvaLabels = { ht: 'HT — TVA en sus', ttc: 'TTC', franchise: 'Franchise en base de TVA' };
    const exclusiviteLabels = { non: 'Sans exclusivité', totale: 'Exclusivité totale', partielle: 'Exclusivité partielle (sur les plateformes)' };
    const reversementLabels = { par_resa: 'À chaque réservation', hebdo: 'Hebdomadaire', mensuel: 'Mensuel', encaissement_direct: 'Encaissement direct par le propriétaire' };

    // ── Génération PDF mandat ──
    const mandatNumber = `MAND-${Date.now()}`;
    const pdfPath = path.join(INVOICE_PDF_DIR, `${mandatNumber}.pdf`);

    // Charger le logo avant le Promise (await interdit dans callback non-async)
    let companyLogoBuffer = null;
    if (companyLogoUrl) {
      try {
        const lr = await axios.get(companyLogoUrl, { responseType: 'arraybuffer', timeout: 5000 });
        if (lr.data.byteLength > 0) companyLogoBuffer = Buffer.from(lr.data);
      } catch(e) { console.warn('⚠️ Logo mandat non chargé:', e.message); }
    }

    await new Promise((resolve, reject) => {
      const doc = new PDFDocument({ size: 'A4', margin: 50 });
      const stream = fs.createWriteStream(pdfPath);
      doc.pipe(stream);

      const green = '#1A7A5E', dark = '#0D1117', gray = '#7A8695', lightBg = '#F5F2EC';
      const pageW = doc.page.width - 100;

      // ── HEADER ──
      doc.rect(0, 0, doc.page.width, 52).fill(green);
      if (companyLogoBuffer) {
        try { doc.image(companyLogoBuffer, 50, 8, { height: 36, fit: [120, 36] }); } catch(e) {
          doc.fillColor('white').fontSize(14).font('Helvetica-Bold').text(companyName || 'BOOSTINGHOST', 50, 18);
        }
      } else {
        doc.fillColor('white').fontSize(14).font('Helvetica-Bold').text(companyName || 'BOOSTINGHOST', 50, 18);
      }
      doc.fillColor('white').fontSize(9).font('Helvetica').text(`Généré le ${fmtDateShort(new Date())}`, 0, 22, { align: 'right', width: doc.page.width - 50 });

      let y = 75;
      doc.fillColor(dark).fontSize(20).font('Helvetica-Bold')
        .text('Contrat de mandat de gestion', 50, y, { align: 'center', width: pageW });
      y += 28;
      doc.fillColor(gray).fontSize(9).font('Helvetica')
        .text('Location saisonnière / courte durée', 50, y, { align: 'center', width: pageW });
      y += 28;

      const sectionTitle = (title) => {
        if (y > 720) { doc.addPage(); y = 50; }
        doc.rect(50, y, pageW, 18).fill(lightBg);
        doc.fillColor(green).fontSize(8).font('Helvetica-Bold').text(title.toUpperCase(), 54, y + 5);
        doc.fillColor(dark); y += 23;
      };
      const row = (label, value) => {
        if (!value || value === '—') return;
        if (y > 750) { doc.addPage(); y = 50; }
        doc.fillColor(gray).fontSize(9).font('Helvetica').text(label, 54, y, { width: 160 });
        doc.fillColor(dark).font('Helvetica-Bold').text(String(value), 220, y, { width: pageW - 170 });
        y += 14;
      };
      const para = (text) => {
        if (y > 720) { doc.addPage(); y = 50; }
        doc.fillColor(dark).fontSize(8.5).font('Helvetica').text(text, 54, y, { width: pageW - 8, lineGap: 2 });
        y += doc.heightOfString(text, { width: pageW - 8, lineGap: 2 }) + 6;
      };
      const bullet = (text) => {
        if (y > 750) { doc.addPage(); y = 50; }
        doc.fillColor(dark).fontSize(9).font('Helvetica').text(`• ${text}`, 60, y, { width: pageW - 16 });
        y += 13;
      };

      // ART 1 — PARTIES
      sectionTitle('Article 1 — Parties');
      row('Conciergerie', companyName || '—');
      if (companyLegal) row('Forme juridique', companyLegal);
      if (companyAddress) row('Siège social', companyAddress);
      if (companySiret) row('SIRET', companySiret);
      if (companyRep) row('Représentée par', companyRep);
      if (companyEmail) row('Email', companyEmail);
      if (companyPhone) row('Téléphone', companyPhone);
      if (companyFreeTitle && companyFreeValue) row(companyFreeTitle, companyFreeValue);
      y += 6;
      row('Propriétaire', `${ownerFirstName} ${ownerLastName}`);
      if (ownerAddress) row('Adresse', ownerAddress);
      if (ownerEmail) row('Email', ownerEmail);
      if (ownerPhone) row('Téléphone', ownerPhone);
      if (ownerDOB) row('Date de naissance', fmtDateShort(ownerDOB));
      if (ownerSiren) row('SIREN', ownerSiren);
      y += 6;

      // ART 2 — BIEN
      sectionTitle('Article 2 — Bien confié');
      row('Adresse du bien', propAddress || '—');
      if (propType) row('Type de bien', propTypeLabels[propType] || propType);
      if (propCapacity) row('Capacité maximale', `${propCapacity} personne${parseInt(propCapacity) > 1 ? 's' : ''}`);
      if (minStay) row('Durée min. de séjour', `${minStay} nuit${parseInt(minStay) > 1 ? 's' : ''}`);
      if (maxStay) row('Durée max. de séjour', `${maxStay} nuits`);
      row('Animaux', animals === 'oui' ? 'Admis' : animals === 'conditions' ? 'Sous conditions' : 'Non admis');
      row('Fumeur', smoking === 'oui' ? 'Autorisé' : smoking === 'exterieur' ? 'Extérieur seulement' : 'Interdit');
      row('Fêtes / événements', parties === 'oui' ? 'Autorisés' : parties === 'conditions' ? 'Sous conditions' : 'Interdits');
      if (checkinTime) row('Heure d\'arrivée', checkinTime);
      if (checkoutTime) row('Heure de départ', checkoutTime);
      y += 6;

      // ART 3 — MISSIONS
      if (missions && missions.length > 0) {
        sectionTitle('Article 3 — Missions confiées');
        missions.forEach(m => bullet(m));
        if (urgenceLimit) { y += 4; para(`Plafond dépenses urgentes sans accord préalable : ${urgenceLimit} € TTC.`); }
        y += 6;
      }

      // ART 4 — EXCLUSIONS (standard)
      sectionTitle('Article 4 — Exclusions de mission');
      para('Sont exclues des missions de la conciergerie, sauf mention expresse contraire : les gros travaux, la gestion des sinistres en qualité d\'assuré, la représentation en justice, les obligations fiscales personnelles du propriétaire, et toute garantie d\'occupation ou de revenu.');
      y += 6;

      // ART 5 — RÉMUNÉRATION
      sectionTitle('Article 5 — Rémunération');
      row('Mode de rémunération', remuLabels[remuType] || '—');
      row('TVA', tvaLabels[tva] || '—');
      row('Préavis révision tarifaire', `${tarifPreavis || 60} jours`);
      row('Reversements', reversementLabels[reversement] || '—');
      if (extrasFacturables && extrasFacturables.length > 0) {
        y += 4;
        para('Prestations complémentaires facturables en sus :');
        extrasFacturables.forEach(e => bullet(e));
      }
      y += 6;

      // ART 6 — DURÉE
      sectionTitle('Article 6 — Durée et résiliation');
      row('Type de contrat', dureeType === 'determinee' ? `Durée déterminée — ${dureeMois || 12} mois` : 'Durée indéterminée');
      if (dateDebut) row('Date de début', fmtDate(dateDebut));
      if (dureeType === 'determinee' && renouvellement) row('Renouvellement', renouvellement === 'tacite' ? 'Tacite reconduction' : 'Renouvellement exprès uniquement');
      row('Préavis de résiliation', `${preavis || 30} jours`);
      y += 6;

      // ART 7 — CONDITIONS
      sectionTitle('Article 7 — Conditions générales');
      row('Exclusivité', exclusiviteLabels[exclusivite] || '—');
      row('Plafond responsabilité', respPlafond === '3mois' ? '3 mois d\'honoraires' : respPlafond === '12mois' ? '12 mois d\'honoraires' : '—');
      row('Confidentialité', `${confidentialite || 5} ans après fin de contrat`);
      y += 4;
      para('La conciergerie n\'est tenue que d\'une obligation de moyens. Elle ne garantit ni revenu minimal, ni taux de réservation. Les Parties rechercheront une solution amiable avant toute action judiciaire.');
      y += 6;

      // ART 8 — OBLIGATIONS (standard)
      sectionTitle('Article 8 — Obligations des parties');
      para('La Conciergerie s\'engage à exécuter ses prestations avec diligence, informer le propriétaire des incidents significatifs, et respecter la confidentialité des informations reçues. Le Propriétaire s\'engage à délivrer un logement conforme, maintenir le bien assuré, fournir des informations sincères et régler les factures dans les délais.');
      y += 6;

      // ART 9 — CLAUSES PERSONNALISÉES
      if (clausesPersonnalisees && clausesPersonnalisees.length > 0) {
        sectionTitle('Article 9 — Clauses particulières');
        clausesPersonnalisees.forEach((c, i) => { para(`${i + 1}. ${c}`); });
        y += 6;
      }

      // SIGNATURES
      if (y > 680) { doc.addPage(); y = 50; }
      y += 10;
      doc.fillColor(gray).fontSize(9).font('Helvetica')
        .text(`Fait le ${fmtDateShort(signatureDate || new Date())}`, 50, y);
      y += 20;

      const sigW = (pageW - 20) / 2;
      doc.fillColor(gray).fontSize(8).font('Helvetica')
        .text('La Conciergerie / Prestataire', 50, y)
        .text('Le Propriétaire / Mandant', 50 + sigW + 20, y);
      y += 5;
      doc.fillColor(dark).fontSize(8).font('Helvetica-Bold')
        .text(companyRep || companyName || '—', 50, y)
        .text(`${ownerFirstName} ${ownerLastName}`, 50 + sigW + 20, y);
      y += 5;

      if (signatureData && signatureData.startsWith('data:image/png;base64,')) {
        try { doc.image(Buffer.from(signatureData.replace('data:image/png;base64,', ''), 'base64'), 50, y, { width: sigW, height: 35 }); } catch(e) {}
      }
      doc.fillColor(gray).fontSize(9).font('Helvetica').text('En attente de signature...', 50 + sigW + 20, y + 10);

      y += 42;
      doc.moveTo(50, y).lineTo(50 + sigW, y).strokeColor('#AAAAAA').stroke();
      doc.moveTo(50 + sigW + 20, y).lineTo(50 + pageW, y).strokeColor('#AAAAAA').stroke();

      doc.rect(0, doc.page.height - 28, doc.page.width, 28).fill(lightBg);
      doc.fillColor(gray).fontSize(7).font('Helvetica')
        .text(`Contrat généré via Boostinghost — www.boostinghost.fr`, 0, doc.page.height - 18, { align: 'center', width: doc.page.width });

      doc.end();
      stream.on('finish', resolve);
      stream.on('error', reject);
    });

    // Nettoyage PDF (on n'envoie pas le PDF, seulement le lien de signature)
    try { fs.unlinkSync(pdfPath); } catch(e) {}

    // ── Sauvegarder en DB + générer token signature ──
    const contractId = 'mand_' + Date.now().toString(36) + crypto.randomBytes(4).toString('hex');
    const signToken = crypto.randomBytes(32).toString('hex');
    const signExpires = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);

    const contractData = {
      contractType: 'mandat',
      companyName, companyLegal, companyAddress, companySiret, companyRep, companyEmail, companyPhone,
      companyLogoUrl, companyFreeTitle, companyFreeValue,
      ownerFirstName, ownerLastName, ownerAddress, ownerEmail, ownerPhone, ownerDOB, ownerSiren,
      propAddress, propType, propCapacity, minStay, maxStay, animals, smoking, parties, checkinTime, checkoutTime,
      missions: missions || [], urgenceLimit, extrasFacturables: extrasFacturables || [],
      remuType, commissionRate, commissionBase, forfaitMensuel, forfaitResa, mixteRate, mixteForfait,
      tva, tarifPreavis, reversement,
      dureeType, dateDebut, dureeMois, renouvellement, preavis,
      exclusivite, respPlafond, juridiction, confidentialite,
      clausesPersonnalisees: clausesPersonnalisees || [],
      signatureDate
    };

    await pool.query(`
      INSERT INTO contracts (id, user_id, reservation_uid, property_id, status, contract_data, owner_signature, sign_token, sign_token_expires_at, created_at, updated_at)
      VALUES ($1, $2, $3, $4, 'sent', $5, $6, $7, $8, NOW(), NOW())
    `, [contractId, userId, reservationUid || null, propAddress || null, JSON.stringify(contractData), signatureData || null, signToken, signExpires]);

    // ── Email de signature au propriétaire ──
    const appUrl = (process.env.APP_URL || 'https://boostinghost.fr').replace(/\/$/, '');
    const signUrl = `${appUrl}/signer-contrat.html?token=${signToken}`;

    const signEmailHtml = bhEmailTemplate({
      icon: '✍️',
      title: 'Signature de votre mandat de gestion',
      subtitle: companyName || 'Votre conciergerie',
      bodyHtml: `
        <p>Bonjour <strong>${ownerFirstName} ${ownerLastName}</strong>,</p>
        <p>Un contrat de mandat de gestion vous a été préparé par <strong>${companyName || 'votre conciergerie'}</strong> pour le bien situé au :</p>
        <div class="info-card"><strong>${propAddress || '—'}</strong></div>
        <div class="cta-block">
          <p>Cliquez ci-dessous pour consulter et signer votre contrat :</p>
          <a href="${signUrl}" class="btn" style="display:inline-block;background:#1A7A5E;color:#fff;text-decoration:none;padding:14px 32px;border-radius:8px;font-size:15px;font-weight:700;">
            ✍️ Signer le mandat
          </a>
        </div>
        <div class="alert-card">⏰ Ce lien est valable <strong>7 jours</strong>.</div>
        <p style="font-size:13px;color:#666;">Lien direct : <a href="${signUrl}" style="color:#1A7A5E;word-break:break-all;">${signUrl}</a></p>
      `
    });

    await transporter.sendMail({
      from: process.env.EMAIL_FROM || 'Boostinghost <no-reply@boostinghost.fr>',
      to: ownerEmail,
      subject: `Action requise : signez votre mandat de gestion – ${companyName || 'Boostinghost'}`,
      html: signEmailHtml
    });

    console.log(`✅ Mandat ${contractId} créé — lien signature envoyé à ${ownerEmail}`);
    res.json({ success: true, message: `Mandat envoyé pour signature à ${ownerEmail}`, contractId });

  } catch (err) {
    console.error('❌ Erreur /api/mandat/send:', err);
    res.status(500).json({ error: err.message || 'Erreur serveur' });
  }
});

// ════════════════════════════════════════════════
// HISTORIQUE NOTIFICATIONS PUSH
// ════════════════════════════════════════════════

async function saveNotificationToHistory(userId, title, body, type, data) {
  if (!userId) return;
  try {
    const existing = await pool.query(
      `SELECT id FROM notification_history
       WHERE user_id = $1 AND title = $2 AND body = $3
       AND created_at > NOW() - INTERVAL '10 seconds'
       LIMIT 1`,
      [String(userId), title || '', body || '']
    );
    if (existing.rows.length > 0) return;
    await pool.query(
      `INSERT INTO notification_history (user_id, title, body, type, data)
       VALUES ($1, $2, $3, $4, $5)`,
      [String(userId), title || '', body || '', type || 'push', data ? JSON.stringify(data) : null]
    );
  } catch(e) {
    console.error('❌ saveNotificationToHistory:', e.message);
  }
}

// POST /api/notifications/history/push — appelé par push-notifications-handler.js côté client
app.post('/api/notifications/history/push', authenticateToken, async (req, res) => {
  try {
    const userId = String(req.user.id);
    const { title, body, type, data } = req.body;
    await pool.query(
      `INSERT INTO notification_history (user_id, title, body, type, data)
       VALUES ($1, $2, $3, $4, $5)`,
      [userId, title || '', body || '', type || 'push', data ? JSON.stringify(data) : null]
    );
    res.json({ success: true });
  } catch(e) {
    console.error('❌ POST /api/notifications/history/push:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// GET /api/notifications/history
app.get('/api/notifications/history', authenticateToken, async (req, res) => {
  try {
    const userId = String(req.user.id);
    const limit = Math.min(parseInt(req.query.limit) || 50, 100);
    const result = await pool.query(
      `SELECT id, title, body, type, data, is_read, created_at
       FROM notification_history
       WHERE user_id = $1
       ORDER BY created_at DESC
       LIMIT $2`,
      [userId, limit]
    );
    const unreadCount = result.rows.filter(r => !r.is_read).length;
    res.json({ notifications: result.rows, unreadCount });
  } catch(e) {
    console.error('❌ GET /api/notifications/history:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// PATCH /api/notifications/history/read — tout marquer comme lu
app.patch('/api/notifications/history/read', authenticateToken, async (req, res) => {
  try {
    await pool.query(
      `UPDATE notification_history SET is_read = TRUE WHERE user_id = $1`,
      [String(req.user.id)]
    );
    res.json({ success: true });
  } catch(e) {
    res.status(500).json({ error: e.message });
  }
});

// DELETE /api/notifications/history — vider l'historique
app.delete('/api/notifications/history', authenticateToken, async (req, res) => {
  try {
    await pool.query(`DELETE FROM notification_history WHERE user_id = $1`, [String(req.user.id)]);
    res.json({ success: true });
  } catch(e) {
    res.status(500).json({ error: e.message });
  }
});


// POST /api/messages/trigger-templates — déclencher manuellement les crons templates
app.post('/api/messages/trigger-templates', authenticateToken, async (req, res) => {
  try {
    const { triggerTypes } = req.body;
    if (!triggerTypes || !Array.isArray(triggerTypes)) {
      return res.status(400).json({ error: 'triggerTypes (array) requis' });
    }
    const allowed = ['before_arrival','on_arrival','after_departure','before_departure','after_arrival','on_booking'];
    const types = triggerTypes.filter(t => allowed.includes(t));
    if (types.length === 0) return res.status(400).json({ error: 'Aucun triggerType valide' });
    console.log(`🔧 [MANUAL TRIGGER] Types: ${types.join(', ')} — user ${req.user.id}`);
    // Lancer en async pour ne pas bloquer la réponse
    runTemplatesCron(types).catch(e => console.error('❌ Manual trigger error:', e.message));
    res.json({ success: true, message: `Cron déclenché pour : ${types.join(', ')}`, types });
  } catch(e) {
    res.status(500).json({ error: e.message });
  }
});


server.listen(PORT, async () => {
  console.log('');
  console.log('╔════════════════════════════════════════════════════════╗');
  console.log('║   🏠 LCC Booking Manager - Système de Réservations    ║');
  console.log('╚════════════════════════════════════════════════════════╝');
  console.log('');
  console.log(`🚀 Serveur démarré sur http://localhost:${PORT}`);
  console.log('');
  
  await initDb();
  
setPool(pool);
initializeFirebase();
console.log('✅ Service de notifications initialisé');
  
  // ✅ Enregistrer le webhook SMS entrant (réponses cleaners)
  try {
    const smsLogin = process.env.SMS_GATEWAY_LOGIN;
    const smsPassword = process.env.SMS_GATEWAY_PASSWORD;
    const appUrl = process.env.APP_URL || `https://${process.env.RENDER_EXTERNAL_HOSTNAME}`;
    if (smsLogin && smsPassword && appUrl) {
      const credentials = Buffer.from(`${smsLogin}:${smsPassword}`).toString('base64');
      const webhookUrl = `${appUrl}/api/sms/incoming`;
      // Vérifier si le webhook existe déjà
      const existing = await fetch('https://api.sms-gate.app/3rdparty/v1/webhooks', {
        headers: { 'Authorization': `Basic ${credentials}` }
      });
      const webhooks = await existing.json().catch(() => []);
      const alreadyRegistered = Array.isArray(webhooks) && webhooks.some(w => w.url === webhookUrl && w.event === 'sms:received');
      if (!alreadyRegistered) {
        const reg = await fetch('https://api.sms-gate.app/3rdparty/v1/webhooks', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Authorization': `Basic ${credentials}` },
          body: JSON.stringify({ url: webhookUrl, event: 'sms:received' })
        });
        if (reg.ok) {
          console.log(`✅ Webhook SMS entrant enregistré : ${webhookUrl}`);
        } else {
          const err = await reg.text();
          console.warn(`⚠️ Webhook SMS : erreur enregistrement : ${err}`);
        }
      } else {
        console.log('✅ Webhook SMS entrant déjà enregistré');
      }
    } else {
      console.log('ℹ️ Webhook SMS ignoré (SMS_GATEWAY_LOGIN/PASSWORD ou APP_URL manquant)');
    }
  } catch (webhookErr) {
    console.warn('⚠️ Webhook SMS entrant : erreur:', webhookErr.message);
  }
  await initWelcomeBookTables(pool);
  console.log('✅ Tables welcome_books initialisées');
  
  // ✅ Initialiser la table payments
  await ensurePaymentsTable();
  console.log('✅ Table payments initialisée');

  // ✅ Initialiser la table contracts
  await ensureContractsTable();
  console.log('✅ Table contracts initialisée');
  
  // ✅ Charger les propriétés
  await loadProperties();
  app.locals.PROPERTIES = PROPERTIES;
  
  // ✅ Charger les réservations depuis PostgreSQL
  await loadReservationsFromDB();
  
  // ✅ Charger les réservations manuelles depuis PostgreSQL (AVANT la synchro iCal)
  await loadManualReservationsFromDB();
  
  // Compatibilité : charger depuis JSON si présent
  await loadManualReservations();
  
  // ✅ Charger les cautions depuis PostgreSQL
  await loadDepositsFromDB();
  
  // ✅ Charger les checklists
  await loadChecklists();
  
  // Migration one-time (à décommenter UNE SEULE FOIS pour migrer)
  // await migrateManualReservationsToPostgres();
  // await migrateDepositsToPostgres();
  
  // Afficher les logements configurés
  console.log('');
  console.log('Logements configurés:');
  PROPERTIES.forEach(p => {
    const status = p.icalUrls && p.icalUrls.length > 0 ? '✅' : '⚠️';
    console.log(`  ${status} ${p.name} (${p.icalUrls.length} source${p.icalUrls.length > 1 ? 's' : ''})`);
  });
  console.log('');
  
  // ✅ Réactivation automatique des webhooks Channex au démarrage
  // (Channex les désactive si le serveur est indisponible lors d'un ping)
  setTimeout(async () => {
    try {
      const { channexAPI } = require('./channex');
      const appUrl = (process.env.APP_URL || 'https://www.boostinghost.fr').replace(/\/$/, '');
      const propsRes = await pool.query(
        `SELECT id, channex_property_id, name FROM properties WHERE channex_enabled = true AND channex_property_id IS NOT NULL`
      );
      console.log(`🔔 [WEBHOOK AUTO] Vérification webhooks pour ${propsRes.rows.length} logement(s) Channex...`);

      let billing_account_id = null;
      try {
        const baRes = await channexAPI.get('/billing_accounts');
        const accounts = baRes.data?.data || [];
        if (accounts.length > 0) billing_account_id = accounts[0].id || accounts[0].attributes?.id;
      } catch(e) { /* non bloquant */ }

      for (const prop of propsRes.rows) {
        try {
          // Vérifier si les webhooks existent et sont actifs
          const existingRes = await channexAPI.get(`/webhooks?property_id=${prop.channex_property_id}`);
          const existing = existingRes.data?.data || [];
          const hasActiveBooking = existing.some(w => {
            const a = w.attributes || w;
            return a.event_mask === 'booking' && a.is_active !== false;
          });
          const hasActiveMessage = existing.some(w => {
            const a = w.attributes || w;
            return a.event_mask === 'message' && a.is_active !== false;
          });

          // Réactiver les inactifs
          for (const wh of existing) {
            const a = wh.attributes || wh;
            if (a.is_active === false) {
              try {
                await channexAPI.put(`/webhooks/${wh.id}`, { webhook: { is_active: true } });
                console.log(`✅ [WEBHOOK AUTO] Réactivé: ${prop.name} (${a.event_mask})`);
              } catch(e) { /* non bloquant */ }
            }
          }

          // Créer si manquants
          const toCreate = [];
          if (!hasActiveBooking) toCreate.push({ event_mask: 'booking', callback_url: `${appUrl}/api/channex/webhook`, label: 'BH Bookings' });
          if (!hasActiveMessage) toCreate.push({ event_mask: 'message', callback_url: `${appUrl}/api/channex/webhook-message`, label: 'BH Messages' });

          for (const wh of toCreate) {
            const payload = { property_id: prop.channex_property_id, callback_url: wh.callback_url, event_mask: wh.event_mask, is_active: true, send_data: true, label: wh.label };
            if (billing_account_id) payload.billing_account_id = billing_account_id;
            await channexAPI.post('/webhooks', { webhook: payload });
            console.log(`✅ [WEBHOOK AUTO] Créé: ${prop.name} (${wh.event_mask})`);
          }
        } catch(e) {
          console.warn(`⚠️ [WEBHOOK AUTO] ${prop.name}:`, e.message);
        }
      }
      console.log(`✅ [WEBHOOK AUTO] Vérification terminée`);
    } catch(e) {
      console.warn('⚠️ [WEBHOOK AUTO] Erreur générale:', e.message);
    }
  }, 15000); // Attendre 15s que le serveur soit bien up avant de contacter Channex

  // ✅ Synchronisation initiale (APRÈS le chargement des manuelles)
  console.log('🔄 Synchronisation initiale...');
  await syncAllCalendars();
  
  const syncInterval = parseInt(process.env.SYNC_INTERVAL) || 15;
  cron.schedule(`*/${syncInterval} * * * *`, async () => {
    console.log('');
    console.log('⏰ Synchronisation automatique programmée');
    await syncAllCalendars();
  });
  
  const cleaningPlanHour = parseInt(process.env.CLEANING_PLAN_HOUR || '18', 10); // heure FR (18h par défaut)
  cron.schedule(`0 ${cleaningPlanHour} * * *`, async () => {
    console.log('');
    console.log(`⏰ Envoi du planning ménage quotidien (pour demain) à ${cleaningPlanHour}h`);
    try {
      await sendDailyCleaningPlan();
    } catch (err) {
      console.error("❌ Erreur lors de l'envoi du planning ménage quotidien :", err);
    }
  });
  
  console.log('');
  console.log(`⏰ Synchronisation automatique: toutes les ${syncInterval} minutes`);
  console.log('');
  console.log('📧 Notifications configurées:', process.env.EMAIL_USER ? '✅ OUI' : '⚠️  NON');
  console.log('📧 BREVO_API_KEY configurée :', process.env.BREVO_API_KEY ? '✅ OUI' : '❌ NON — les emails de factures ne seront PAS envoyés');
  console.log('📧 EMAIL_FROM configuré     :', process.env.EMAIL_FROM  ? '✅ ' + process.env.EMAIL_FROM : '⚠️  NON (défaut: no-reply@boostinghost.fr)');
  console.log('💳 Stripe configuré :', STRIPE_SECRET_KEY ? '✅ OUI' : '⚠️  NON (pas de création de cautions possible)');
  console.log('');
});

// ============================================
// 🤖 HELPER POUR TRAITER LES MESSAGES ENTRANTS
// ============================================

/**
 * À appeler après chaque insertion de message guest dans la DB
 * Cette fonction gère automatiquement:
 * - L'onboarding (prénom, nom, téléphone, langue)
 * - Les réponses automatiques (mots-clés + Groq AI)
 */
async function processIncomingGuestMessage(savedMessage, conversationId) {
  try {
    // Ne traiter que les messages des clients
    if (savedMessage.sender_type !== 'guest') {
      return;
    }

    // Récupérer la conversation complète avec toutes les infos
    const convResult = await pool.query(
      'SELECT * FROM conversations WHERE id = $1',
      [conversationId]
    );

    if (convResult.rows.length === 0) {
      console.log('⚠️ Conversation introuvable:', conversationId);
      return;
    }

    const conversation = convResult.rows[0];

    // Traiter le message (onboarding + réponses auto)
    await handleIncomingMessage(savedMessage, conversation, pool, io);

  } catch (error) {
    console.error('❌ Erreur processIncomingGuestMessage:', error);
  }
}

// Exporter pour utilisation depuis d'autres fichiers
global.processIncomingGuestMessage = processIncomingGuestMessage;

