// ── Associer un logement BH à une propriété Channex existante ─
app.post('/api/channex/link-property', authenticateToken, async (req, res) => {
  const { property_id, channex_property_id, channex_room_type_id, channex_rate_plan_id } = req.body;
  const user_id = req.user.id;
  if (!property_id || !channex_property_id || !channex_room_type_id || !channex_rate_plan_id) {
    return res.status(400).json({ error: 'property_id, channex_property_id, channex_room_type_id et channex_rate_plan_id requis' });
  }
  try {
    await pool.query(
      `UPDATE properties SET
         channex_enabled = true,
         channex_property_id = $1,
         channex_room_type_id = $2,
         channex_rate_plan_id = $3,
         updated_at = NOW()
       WHERE id = $4 AND user_id = $5`,
      [channex_property_id, channex_room_type_id, channex_rate_plan_id, property_id, user_id]
    );
    await loadProperties();

    // Pousser les disponibilités existantes vers Channex
    const resaResult = await pool.query(
      "SELECT start_date, end_date FROM reservations WHERE property_id = $1 AND status = 'confirmed'",
      [property_id]
    );
    const dates_blocked = [];
    resaResult.rows.forEach(r => {
      const start = new Date(r.start_date);
      const end = new Date(r.end_date);
      for (let d = new Date(start); d < end; d.setDate(d.getDate() + 1)) {
        dates_blocked.push(d.toISOString().split('T')[0]);
      }
    });
    await pushAvailability(pool, { property_id, channex_property_id, channex_room_type_id, dates_blocked });

    res.json({ success: true, message: 'Logement associé à Channex avec succès' });
  } catch (e) {
    console.error('❌ [CHANNEX LINK]', e.message);
    res.status(500).json({ error: 'Erreur lors de l\'association: ' + e.message });
  }
});

app.post('/api/channex/connect-property', authenticateToken, async (req, res) => {
  const { property_id, channex_property_id: existing_channex_property_id } = req.body;
  const user_id = req.user.id;

  if (!property_id) return res.status(400).json({ error: 'property_id requis' });

  try {
    const propResult = await pool.query(
      'SELECT * FROM properties WHERE id = $1 AND user_id = $2',
      [property_id, user_id]
    );

    if (propResult.rows.length === 0) {
      return res.status(404).json({ error: 'Logement non trouvé' });
    }

    const property = propResult.rows[0];

    if (property.channex_enabled && property.channex_property_id) {
      return res.status(400).json({ error: 'Ce logement est déjà connecté à Channex' });
    }

    let result;

    if (existing_channex_property_id) {
      // ── Scénario multi-logements : rattacher à une property Channex existante ──
      // Vérifier que cette channex_property_id appartient bien à l'utilisateur
      const ownerCheck = await pool.query(
        'SELECT id FROM properties WHERE channex_property_id = $1 AND user_id = $2 LIMIT 1',
        [existing_channex_property_id, user_id]
      );
      if (ownerCheck.rows.length === 0) {
        return res.status(403).json({ error: 'Property Channex introuvable ou non autorisée' });
      }

      const { addRoomTypeToProperty } = require('./channex');
      result = await addRoomTypeToProperty(pool, {
        user_id,
        property_id,
        channex_property_id: existing_channex_property_id,
        name: property.name
      });
    } else {
      // ── Scénario standard : créer une nouvelle property Channex ──
      result = await createChannexProperty(pool, {
        user_id,
        property_id,
        name: property.name,
        address: property.address,
        city: property.city
      });
    }

    const resaResult = await pool.query(
      "SELECT start_date, end_date FROM reservations WHERE property_id = $1 AND status = 'confirmed'",
      [property_id]
    );

    const dates_blocked = [];
    resaResult.rows.forEach(r => {
      const start = new Date(r.start_date);
      const end = new Date(r.end_date);
      for (let d = new Date(start); d < end; d.setDate(d.getDate() + 1)) {
        dates_blocked.push(d.toISOString().split('T')[0]);
      }
    });

    await pushAvailability(pool, {
      property_id,
      channex_property_id: result.channex_property_id,
      channex_room_type_id: result.channex_room_type_id,
      dates_blocked
    });

    // ✅ Enregistrer les webhooks uniquement si nouvelle property Channex
    if (!existing_channex_property_id) {
      try {
        const { channexAPI } = require('./channex');
        const appUrl = process.env.APP_URL || 'https://www.boostinghost.fr';

        // Récupérer le billing_account_id (requis en prod Channex)
        let billing_account_id = null;
        try {
          const baRes = await channexAPI.get('/billing_accounts');
          const accounts = baRes.data?.data || [];
          if (accounts.length > 0) billing_account_id = accounts[0].id || accounts[0].attributes?.id;
          if (billing_account_id) console.log(`💳 [CHANNEX] billing_account_id: ${billing_account_id}`);
        } catch (e) { /* non bloquant */ }

        for (const wh of [
          { event_mask: 'booking', callback_url: `${appUrl}/api/channex/webhook`, label: 'BH Bookings' },
          { event_mask: 'message', callback_url: `${appUrl}/api/channex/webhook-message`, label: 'BH Messages' }
        ]) {
          const payload = {
            property_id: result.channex_property_id,
            callback_url: wh.callback_url,
            event_mask: wh.event_mask,
            is_active: true,
            send_data: true
          };
          if (billing_account_id) payload.billing_account_id = billing_account_id;
          await channexAPI.post('/webhooks', { webhook: payload });
          console.log(`✅ [CHANNEX] Webhook ${wh.event_mask} enregistré pour ${result.channex_property_id}`);
        }

        // ✅ Auto-installer l'application "Channex Messages & Reviews"
        try {
          // 1. Lister les applications disponibles pour trouver l'ID de Messages & Reviews
          const appsRes = await channexAPI.get('/applications');
          const apps = appsRes.data?.data || [];
          const msgApp = apps.find(a => {
            const title = (a.attributes?.title || a.title || '').toLowerCase();
            return title.includes('message') || title.includes('review');
          });

          if (msgApp) {
            const appId = msgApp.id;
            console.log(`📦 [CHANNEX] App Messages trouvée: ${msgApp.attributes?.title} (${appId})`);
            // 2. Installer sur la nouvelle propriété
            await channexAPI.post('/property_applications', {
              property_application: {
                property_id: result.channex_property_id,
                application_id: appId
              }
            });
            console.log(`✅ [CHANNEX] App Messages & Reviews installée sur ${result.channex_property_id}`);
          } else {
            console.warn('⚠️ [CHANNEX] App Messages & Reviews non trouvée dans la liste des applications');
          }
        } catch(appErr) {
          console.warn('⚠️ [CHANNEX] Erreur installation app Messages (non bloquant):', appErr.message);
        }
      } catch (whErr) {
        console.warn('⚠️ [CHANNEX] Erreur enregistrement webhooks (non bloquant):', whErr.message);
      }
    }

    res.json({
      success: true,
      message: 'Logement connecté à Channex avec succès',
      channex_property_id: result.channex_property_id
    });

  } catch (e) {
    console.error('❌ [CHANNEX CONNECT]', e.message);
    res.status(500).json({ error: 'Erreur lors de la connexion Channex: ' + e.message });
  }
});

// ── Installer l'app Messages & Reviews sur toutes les properties d'un user ──
app.post('/api/channex/install-messages-app', authenticateToken, async (req, res) => {
  const user_id = req.user.id;
  try {
    const { channexAPI } = require('./channex');

    // Lister les apps disponibles
    const appsRes = await channexAPI.get('/applications');
    const apps = appsRes.data?.data || [];
    const msgApp = apps.find(a => {
      const title = (a.attributes?.title || a.title || '').toLowerCase();
      return title.includes('message') || title.includes('review');
    });

    if (!msgApp) {
      return res.status(404).json({ error: 'App Messages & Reviews non trouvée dans Channex' });
    }

    const appId = msgApp.id;
    console.log(`📦 [CHANNEX] App Messages: ${msgApp.attributes?.title} (${appId})`);

    // Récupérer toutes les properties Channex de l'utilisateur
    const propsResult = await pool.query(
      'SELECT DISTINCT channex_property_id FROM properties WHERE user_id = $1 AND channex_enabled = TRUE AND channex_property_id IS NOT NULL',
      [user_id]
    );

    let installed = 0, skipped = 0, errors = 0;
    for (const row of propsResult.rows) {
      try {
        await channexAPI.post('/property_applications', {
          property_application: {
            property_id: row.channex_property_id,
            application_id: appId
          }
        });
        installed++;
        console.log(`✅ App Messages installée sur ${row.channex_property_id}`);
      } catch(e) {
        if (e.response?.status === 422) {
          skipped++; // déjà installée
        } else {
          errors++;
          console.warn(`⚠️ Erreur ${row.channex_property_id}:`, e.message);
        }
      }
      await new Promise(r => setTimeout(r, 300));
    }

    res.json({ success: true, installed, skipped, errors, total: propsResult.rows.length });
  } catch(e) {
    console.error('❌ [install-messages-app]', e.message);
    res.status(500).json({ error: e.message });
  }
});

